# в”Җв”Җв”Җ Pre-compiled patterns (used across multiple checks) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
RE_STRIP_TAGS        = re.compile(r'<[^>]+>')                  # strip HTML tags (177 uses)
RE_WS                = re.compile(r'\s+')                      # collapse whitespace (40 uses)
RE_HTML_COMMENT      = re.compile(r'<!--.*?-->', re.DOTALL)    # strip HTML comments (9 uses)
RE_IMG_TAG           = re.compile(r'<img\b[^>]*>')             # img elements (4 uses)
RE_STOP_PHOTOS_EMPTY = re.compile(r'\bstop-photos-empty\b')  # empty photo wrapper class (4 uses)
RE_STOP_NAME         = re.compile(r'stop-name[^>]*>([^<]+)<') # stop name text (4 uses)
# Phone/email ban (Rules for Claude.html В§7 вҖ” added 2026-07-11, audit Gap 1).
# Phone: requires 3 digit-groups (or +country/parenthesised area code + 2 groups)
# joined by space/dash/dot only вҖ” deliberately excludes ':' so clock times
# (9:00, 09:00вҖ“17:00) and ISO dates (2026-07-11, single separator) never match.
RE_EMAIL_PATTERN = re.compile(r'\b[\w.+-]+@[\w-]+\.[\w.-]+\b')
RE_PHONE_PATTERN = re.compile(
    r'(?:(?:\+|00)\d{1,3}[-.\s])?(?:\(\d{2,4}\)[-.\s]?)?\d{2,4}[-.\s]\d{3,4}[-.\s]\d{3,4}\b'
)

results = []
_warn_ok_tags: list[str] = []  # populated by validate() from guide HTML

def check(label, passed, detail="", note=""):
    """
    label  вҖ” check description printed on every run
    passed вҖ” True вҶ’ вң…, False вҶ’ вқҢ
    detail вҖ” printed only on FAILURE (failure message / what went wrong)
    note   вҖ” printed on BOTH pass and fail (counts, found-values, etc.)
    """
    icon = PASS if passed else FAIL
    msg = f"{icon} {label}"
    if note:
        msg += f"\n     вҶ’ {note}"
    if not passed and detail:
        msg += f"\n     вҶ’ {detail}"
    results.append((passed, msg))

def warn(label, detail="", tag=None):
    # Derive a stable slug tag from the label when none supplied.
    _slug = tag if tag else re.sub(r'[^a-z0-9]+', '-', label[:60].lower()).strip('-')
    # If the guide has a <!-- warn-ok: TAG reason --> comment for this warning,
    # suppress it entirely вҖ” acknowledged warnings are silent. No output at all.
    _ack = any(_slug in c for c in _warn_ok_tags)
    if _ack:
        return
    msg = f"{WARN}{label}"
    if detail:
        msg += f"\n     вҶ’ {detail}"
    msg += f"\n     вңҸпёҸ  Add <!-- warn-ok: {_slug} WHY --> in the guide to document why this is acceptable"
    results.append((None, msg))

def _safe_read(path, encoding='utf-8', errors='ignore'):
    """Read a file safely вҖ” returns '' on any OS/encoding error (TOCTOU-safe)."""
    try:
        return path.read_text(encoding=encoding, errors=errors)
    except (OSError, UnicodeDecodeError):
        return ''

class BuildStateHalt(Exception):
    """Raised inside validate() when the build-state gate halts the run (Phase 1/2
    unchecked). Carries the intended process exit code. __main__ catches it and
    exits; an importer can catch it instead of being killed by a bare sys.exit.
    (Lane4-03 fix вҖ” validate() no longer terminates the interpreter directly.)"""
    def __init__(self, code: int = 2):
        self.code = code
        super().__init__(f"build-state halt (exit {code})")


def validate(html: str, filename: str):

    # в”Җв”Җв”Җ RESULTS RESET в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # `results` is module-level so check()/warn() can append from anywhere.
    # Clear it at the top of every validate() call so a second in-process call
    # (e.g. if the validator is ever imported and reused) starts clean instead
    # of accumulating the prior run's results and double-counting the tally.
    results.clear()

    # в”Җв”Җв”Җ GUIDE HTML FILENAME PATTERN в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every guide HTML file must follow the {city}_v*.html pattern (e.g.,
    # cairo_v2.html, lake_tahoe_v1.html) where {city} is derived from the
    # folder name. The filename MUST start with the city slug, not generic
    # names like "guide_v1.html" or arbitrary text.
    _guide_filename = Path(filename).name
    _guide_folder = Path(filename).parent.name  # e.g., "Cairo", "Lake Tahoe", "Azores"
    # Convert folder name to lowercase slug: spaces вҶ’ hyphens, diacritics
    # stripped (folders may keep accents вҖ” SГЈo LuГӯs, MaceiГі, SГЈo Paulo вҖ” but the file
    # slug never does; matches brain_check.py's ASCII-only _GUIDE_FILENAME_RE).
    _ascii_folder = _unicodedata.normalize('NFKD', _guide_folder).encode('ascii', 'ignore').decode()
    _city_slug = re.sub(r'[\s]+', '-', _ascii_folder.lower())
    # Filename must start with the (possibly abbreviated) city slug, followed by
    # _v and a version number. Slugs are legitimately abbreviated (San Francisco ->
    # sf_v3, Carmel-by-the-Sea -> carmel_v1) so this only enforces shape, not an
    # exact match against the folder-derived slug вҖ” except the literal "guide_v"
    # placeholder, which is never valid regardless of shape (a build that skipped
    # the Phase 0 read defaults the slug to the literal word "guide").
    _filename_pattern = r'^[a-z0-9][a-z0-9_-]*_v\d+\.html$'
    _filename_valid = (
        re.match(_filename_pattern, _guide_filename, re.IGNORECASE) is not None
        and not _guide_filename.lower().startswith("guide_v")
    )
    check(
        f"Guide HTML filename follows pattern: {{city_slug}}_v*.html (city-specific + version)",
        _filename_valid,
        f"Found: {_guide_filename} in {_guide_folder}/ вҖ” rename to {_city_slug}_{(_vm := re.search(r'_(v[0-9]+)[.]html$', _guide_filename)) and _vm.group(1) or 'v1'}.html"
    )

    # в”Җв”Җв”Җ WARN-OK SENTINEL REGISTRY в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Guide authors add <!-- warn-ok: TAG reason --> to acknowledge warnings.
    # The validator checks this registry when a warning fires; unacknowledged
    # warnings display instructions to add the comment.
    global _warn_ok_tags
    _warn_ok_tags = re.findall(
        r'<!--\s*warn-ok:\s*([^-][^>]+?)\s*-->', html
    )

    # в”Җв”Җв”Җ BUILD-STATE TRACKER в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # BUILD-STATE GATE (per Guide Structure.html )
    #
    # Every guide build maintains a tracker at
    #   Guides/{City}/_build/build_state.md
    # Claude flips each `- [ ]` to `- [x]` as files are read. The validator
    # parses that tracker here and confirms every required phase entry is
    # checked before the guide can ship. This is the hardest-to-skip
    # enforcement layer вҖ” the other safeguards (CLAUDE.md phase list,
    # Guide Structure , DriftyCat tripwires, Pre-Ship Checklist) all
    # rely on Claude actually doing the reads; this gate verifies it.
    #
    # Hard-fail policy (per To Do List + Guide Structure ):
    #   - missing build_state.md             вҶ’ FAIL
    #   - Phase 1 entry unchecked            вҶ’ FAIL
    #   - Phase 2 entry unchecked            вҶ’ FAIL
    #   - Phase 3 entry unchecked + stops    вҶ’ FAIL (skip when no stops)
    #   - Phase 4 entry unchecked + stops    вҶ’ FAIL (skip when no stops)
    #   - Phase 5 entry unchecked + section  вҶ’ FAIL (per shipping extras-section)
    # Phase 0 and Phase 6 are session-level / ship-gate items, not
    # enforced here.
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # CORE RULES INTEGRITY вҖ” checksum guard
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # Every CORE RULES HTML file has a stored SHA-256 hash in
    # core_rules_checksums.json (next to this script). If any file
    # has been modified without an explicit permission grant the hash
    # won't match and the validator fails immediately вҖ” before any
    # guide check runs вҖ” so the unauthorized edit is caught and
    # reverted before it can silently influence a build.
    #
    # To update checksums after a PERMITTED edit:
    #   python3 update_core_rules_checksums.py
    # (from Brain/scripts/ вҖ” updates only; never edits the rules files)
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    print("в”Җв”Җ CORE RULES INTEGRITY в”Җв”Җ")

    # The CORE RULES integrity guard detects unauthorized LOCAL edits by comparing
    # every CORE RULES file against core_rules_checksums.json. That file is local
    # authoring material (gitignored) and is NOT published to the repo, so in CI it
    # is both absent and meaningless. Allow an explicit skip via env var; default
    # (unset) keeps the full local guard exactly as before.
    import os as _os_env
    # PUBLISHED-ONLY MODE (CI): the validator normally runs in the full local
    # authoring environment (CORE RULES checksums, per-guide _build/ trackers and
    # logs, photo-provenance module, all 27 CORE RULES files). CI only has the
    # PUBLISHED subset, so a handful of checks that depend on unpublished authoring
    # artifacts are skipped вҖ” they verify the build PROCESS, not the published
    # guide HTML. All guide-content checks (structure, stops, photo presence,
    # format, links, sections) still run. Cross-surface coverage is enforced
    # separately by .github/scripts/check_coverage.py. Default (unset) = full local.
    _published_only = _os_env.environ.get("VALIDATOR_PUBLISHED_ONLY") == "1"
    _cr_skip = _published_only or _os_env.environ.get("SKIP_CORE_RULES_INTEGRITY") == "1"
    if _cr_skip:
        print("   вҸӯ  skipped (published-only/CI вҖ” integrity guards local edits, N/A in CI)")

    _cr_checksums_path = Path(__file__).parent / "core_rules_checksums.json"
    _cr_rules_dir = Path(filename).resolve().parent.parent.parent.parent / "Brain" / "CORE RULES"
    _cr_integrity_ok = True

    if _cr_skip:
        # Skip the hash comparison, but still populate _cr_stored with the CORE
        # RULES file list вҖ” later CORE RULES CONTENT checks (banned phrases, note
        # words) iterate _cr_stored.keys() to scan each rule file, and would crash
        # if it were left undefined.
        _cr_stored = {p.name: "" for p in _cr_rules_dir.glob("*.html")} if _cr_rules_dir.is_dir() else {}
    elif not _cr_checksums_path.is_file():
        check(
            'CORE RULES integrity вҖ” checksums file present '
            '(core_rules_checksums.json must exist next to validator)',
            False,
            f"Checksums file not found: {_cr_checksums_path} вҖ” "
            f"run update_core_rules_checksums.py to generate it",
        )
        _cr_integrity_ok = False
    elif not _cr_rules_dir.is_dir():
        check(
            'CORE RULES integrity вҖ” CORE RULES directory reachable',
            False,
            f"CORE RULES directory not found at: {_cr_rules_dir}",
        )
        _cr_integrity_ok = False
    else:
        try:
            _cr_stored = json.loads(_cr_checksums_path.read_text(encoding='utf-8'))
        except Exception as _cr_err:
            check(
                'CORE RULES integrity вҖ” checksums file readable',
                False,
                f"Could not read checksums file: {_cr_err}",
            )
            _cr_integrity_ok = False

    if _cr_integrity_ok and not _cr_skip:
        _cr_modified:  list[str] = []
        _cr_missing:   list[str] = []
        for _rel, _stored_hash in sorted(_cr_stored.items()):
            _cr_file = _cr_rules_dir / _rel
            if not _cr_file.is_file():
                _cr_missing.append(_rel)
                continue
            # Re-read on mismatch before failing. The CORE RULES files live on
            # Google Drive File Stream; a cold read of a not-yet-hydrated file
            # can return partial bytes, producing a spurious hash mismatch that
            # would block ship at random on the first run of a session. Retry a
            # couple of times so a real unauthorized edit still fails (it never
            # self-heals) while a hydration flake clears. (Added 2026-05-30 audit.)
            _current_hash = _hashlib.sha256(_cr_file.read_bytes()).hexdigest()
            for _retry in range(2):
                if _current_hash == _stored_hash:
                    break
                _time.sleep(0.25)
                _current_hash = _hashlib.sha256(_cr_file.read_bytes()).hexdigest()
            if _current_hash != _stored_hash:
                _cr_modified.append(_rel)

        check(
            f'CORE RULES integrity вҖ” no file has been modified without permission '
            f'(SHA-256 matches stored checksum for all {len(_cr_stored)} files; '
            'modified = unauthorized edit вҖ” revert the file, then re-run)',
            len(_cr_modified) == 0 and len(_cr_missing) == 0,
            (
                (f"UNAUTHORIZED EDIT detected in {len(_cr_modified)} file(s): "
                 + "; ".join(_cr_modified[:5])
                 + " вҖ” revert to approved version, then run "
                   "update_core_rules_checksums.py if the edit was intentional")
                if _cr_modified else ""
            ) + (
                (f"  |  {len(_cr_missing)} file(s) missing from CORE RULES: "
                 + "; ".join(_cr_missing[:5]))
                if _cr_missing else ""
            ),
        )

        # в”Җв”Җв”Җ COVERAGE вҖ” every CORE RULES .html must be in the checksum store в”Җв”Җв”Җ
        # The modified/missing loop above iterates the STORED checksums only,
        # so any .html sitting in CORE RULES/ that was never added to
        # core_rules_checksums.json is silently unchecked вҖ” edits to it would
        # never be caught. Flag any on-disk CORE RULES .html absent from the
        # store. Fix: run update_core_rules_checksums.py to add it.
        # (Added 2026-05-30 audit вҖ” Toolbar.html was untracked.)
        _cr_disk_html = {_p.name for _p in _cr_rules_dir.glob("*.html")}
        _cr_untracked = sorted(_cr_disk_html - set(_cr_stored.keys()))
        check(
            'CORE RULES integrity вҖ” every CORE RULES .html is covered by the '
            'checksum store (an untracked .html has no integrity guard вҖ” '
            'run update_core_rules_checksums.py to add it)',
            len(_cr_untracked) == 0,
            (f"UNTRACKED CORE RULES file(s) not in core_rules_checksums.json: "
             + "; ".join(_cr_untracked)
             + " вҖ” run update_core_rules_checksums.py to bring under the guard")
            if _cr_untracked else "",
        )

    # в”Җв”Җв”Җ CORE RULES CONTENT вҖ” BANNED ANNOTATION PHRASES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The exemption banner in every CORE RULES file states:
    #   "CSS, HTML, and validator code are not permitted in rule text."
    # Beyond technical jargon, layout annotation comments that crept in as
    # build notes are also banned вҖ” they describe structure mechanically rather
    # than stating the rule positively. Banned phrases (exact substring match,
    # case-insensitive):
    #   "вҶ’ heading row"           вҖ” structural placement note
    #   "вҶ’ last row of body box"  вҖ” structural placement note
    #   "вҖ” first row of body box" вҖ” structural placement note
    #   "first row of body box"   вҖ” variant without dash
    #   "last row of body box"    вҖ” variant without arrow
    # These must not appear in the rule text of any CORE RULES file.
    # The banners themselves are exempt (they are boilerplate, not rule text).
    print("\nв”Җв”Җ CORE RULES CONTENT вҖ” banned annotation phrases в”Җв”Җ")
    _CR_BANNED_PHRASES = [
        "вҶ’ heading row",
        "вҶ’ last row of body box",
        "вҖ” first row of body box",
        "first row of body box",
        "last row of body box",
        "heading row",
        "body box",
    ]
    # Drift words banned from <span class="note"> description field annotations.
    # These are subject/editorial descriptors that open the door for Claude to
    # write opinions or filler instead of facts. Scoped to .note spans only to
    # avoid false positives on legitimate uses elsewhere (e.g. "ticket" in Tickets.html).
    _CR_NOTE_BANNED_WORDS = [
        "vibe",           # subjective atmosphere descriptor
        "ticket info",    # payment detail вҖ” belongs in template line, not description
        "worth",          # editorial judgement ("worth the trip", "worth a visit")
        "kind of experience",  # drift phrase removed 2026-05-27
        "character",      # vague qualitative descriptor
    ]
    _CR_NOTE_SPAN_RE = re.compile(
        r'<span\b[^>]*class\s*=\s*"[^"]*\bnote\b[^"]*"[^>]*>(.*?)</span>',
        re.IGNORECASE | re.DOTALL,
    )
    _cr_banned_hits: list[str] = []
    _cr_note_banned_hits: list[str] = []
    if _cr_integrity_ok and _cr_rules_dir.is_dir():
        for _rel in sorted(_cr_stored.keys()):
            _cr_file = _cr_rules_dir / _rel
            _cr_text = _safe_read(_cr_file, errors='strict')
            if not _cr_text:
                continue
            # Strip banner paragraphs before scanning so the banner's own
            # explanatory text doesn't trigger the check.
            _cr_body = RE_HTML_COMMENT.sub('', _cr_text)
            # Remove banner <p> blocks (contain "ATTENTION: THIS DOCUMENT...")
            _cr_body = re.sub(
                r'<p\b[^>]*>.*?ATTENTION.*?</p>', '', _cr_body,
                flags=re.DOTALL | re.IGNORECASE,
            )
            _cr_plain = RE_WS.sub(' ', RE_STRIP_TAGS.sub('', _cr_body)).strip()
            for _phrase in _CR_BANNED_PHRASES:
                if _phrase.lower() in _cr_plain.lower():
                    _cr_banned_hits.append(f'{_rel}: "{_phrase}"')
                    break  # one hit per file is enough
            # Check .note spans for drift words (word-boundary matching)
            for _note_m in _CR_NOTE_SPAN_RE.finditer(_cr_body):
                _note_text = RE_STRIP_TAGS.sub('', _note_m.group(1)).lower()
                for _word in _CR_NOTE_BANNED_WORDS:
                    if re.search(r'\b' + re.escape(_word) + r'\b', _note_text):
                        _cr_note_banned_hits.append(f'{_rel}: "{_word}" in note span')
                        break
    check(
        'CORE RULES content вҖ” no banned annotation phrases in rule text '
        '("вҶ’ heading row", "first/last row of body box", "body box" etc. '
        'are layout notes, not rules вҖ” remove them)',
        not _cr_banned_hits,
        f'{len(_cr_banned_hits)} file(s) with banned phrases: '
        + '; '.join(_cr_banned_hits[:5])
        if _cr_banned_hits else '',
    )
    check(
        'CORE RULES content вҖ” no drift words in <span class="note"> description annotations '
        '("vibe", "worth", "ticket info", "kind of experience", "character" are banned вҖ” '
        'description notes must state only field name and char limit; removed 2026-05-27)',
        not _cr_note_banned_hits,
        f'{len(_cr_note_banned_hits)} note span(s) with drift words: '
        + '; '.join(_cr_note_banned_hits[:5])
        if _cr_note_banned_hits else '',
    )

    print("в”Җв”Җ BUILD-STATE TRACKER в”Җв”Җ")

    BUILD_STATE_PHASE_1 = [
        "Links.html",
        "Photos Rules.html",
        "Connectors.html",
        "Platforms.md",
    ]
    BUILD_STATE_PHASE_2 = [
        "Guide Structure.html",
        "Stops Structure.html",
        "Hotel Banner.html",
        "Trip Overview.html",
        "Toolbar.html",
        "Navigation.html",
    ]
    BUILD_STATE_PHASE_3 = [
        "Day Structure.html",
    ]
    BUILD_STATE_PHASE_4 = [
        "Tickets.html",
        "Motion Rule.html",
        "Icon Order and Format.html",
    ]
    # Map extras-section id вҶ’ corresponding Phase 5 rule file name.
    # Keep aligned with Guide Structure.html (extras order) and the
    # rules_dependency_map anchor IDs.
    BUILD_STATE_PHASE_5_MAP = {
        'tours':               'Tours - Extra Section.html',
        'weekly-closures':     'Weekly Closures - Extra Section.html',
        'cappuccino':          'Cappuccino - Extra Section.html',
        'restaurants':         'Restaurants Near Hotel - Extra Section.html',
        'downtown':            'Downtown Restaurants - Extra Section.html',
        'local-tastes':        'Local Tastes - Extra Section.html',
        'food-delivery':       'Food Delivery - Extra Section.html',
        'shows':               'Shows, Performances & Concerts - Extra Section.html',
        'getting-around':      'Getting Around - Extra Section.html',
        'stations-near-hotel': 'Train Stations Near Hotel - Extra Section.html',
        'day-trips-by-train':  'Day Trips by Train - Extra Section.html',
        'pickleball':          'Pickleball - Extra Section.html',
        'michelin':            'Michelin Restaurants - Extra Section.html',
        'heads-up':      'Heads Up - Extra Section.html',
        'claude-inspiration':  'Claude Inspiration - Extra Section.html',
        'skip-list':           'Skip List - Extra Section.html',
    }

    _bs_guide_path = Path(filename)
    _bs_path = _bs_guide_path.parent / "_build" / "build_state.md"

    if _published_only:
        # _build/build_state.md is a build-process tracker, not published content.
        print("   вҸӯ  build-state tracker check skipped (published-only/CI)")
    elif not _bs_path.is_file():
        check(
            "Build-state tracker exists at _build/build_state.md "
            "(per Guide Structure.html вҖ” required for every guide build)",
            False,
            f"file not found: {_bs_path} вҖ” create one with the format defined in "
            f"Guide Structure.html (Phase 0 through Phase 6 checklists). The "
            f"tracker is what verifies the build's required reads actually happened; "
            f"its absence means the build skipped the documented build process."
        )
    else:
        try:
            _bs_text = _bs_path.read_text(encoding="utf-8")
        except OSError as _bs_err:
            check(
                "Build-state tracker is readable",
                False,
                f"{type(_bs_err).__name__}: {_bs_err}"
            )
            _bs_text = None

        if _bs_text is not None:
            # Parse each "- [ ] Name" or "- [x] Name" line. Case-insensitive
            # on the x; the trailing text is the file name / item name.
            _bs_entries: dict[str, bool] = {}
            for _line in _bs_text.splitlines():
                _bs_m = re.match(r'^\s*-\s*\[([ xX])\]\s*(.+?)\s*$', _line)
                if _bs_m:
                    _bs_entries[_bs_m.group(2).strip()] = (_bs_m.group(1).lower() == 'x')

            # Basename-normalised lookup вҖ” allows path-prefixed entries like
            # "Brain/Reference/Toolbar.html" to match required bare name "Toolbar.html".
            # Guide Structure.html Phase 2 template emits the path-prefixed form for
            # orientation; the validator accepts either form. Added 2026-06-01.
            from pathlib import Path as _Path
            _bs_by_name: dict[str, bool] = {_Path(k).name: v for k, v in _bs_entries.items()}

            def _bs_phase_check(_label: str, _required: list[str], _ctx: str = "") -> bool:
                _missing = [f for f in _required
                            if f not in _bs_entries and _Path(f).name not in _bs_by_name]
                _unchecked = [f for f in _required
                              if (_Path(f).name in _bs_by_name and not _bs_by_name[_Path(f).name])
                              or (f in _bs_entries and not _bs_entries[f])]
                _detail_parts: list[str] = []
                if _missing:
                    _detail_parts.append(f"missing tracker entries: {', '.join(_missing)}")
                if _unchecked:
                    _detail_parts.append(f"unchecked entries: {', '.join(_unchecked)}")
                _passed = not (_missing or _unchecked)
                check(
                    f"Build-state tracker вҖ” {_label}{_ctx}",
                    _passed,
                    '; '.join(_detail_parts) if _detail_parts else ""
                )
                return _passed

            # Phase 1 вҖ” always required (technical prerequisites).
            _bs_p1_ok = _bs_phase_check("Phase 1 (technical prerequisites) all entries are [x]", BUILD_STATE_PHASE_1)

            # Phase 2 вҖ” always required (guide structure rules).
            _bs_p2_ok = _bs_phase_check("Phase 2 (guide structure) all entries are [x]", BUILD_STATE_PHASE_2)

            # в”Җв”Җ EARLY EXIT: Phase 1 or Phase 2 unchecked в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            # The format lives in CORE RULES. A guide written before these reads
            # is built from memory вҖ” wrong structure, wrong sections, wrong HTML.
            # Running 500+ checks on invented-format HTML produces noise, not signal.
            # Fix: do the reads, flip the boxes in build_state.md, rebuild, re-run.
            if not (_bs_p1_ok and _bs_p2_ok):
                print("\n" + "в”Ғ" * 60)
                print("рҹҡ«  PHASE READS MISSING вҖ” VALIDATION HALTED")
                print("в”Ғ" * 60)
                print("  Phase 1 and/or Phase 2 boxes are unchecked in build_state.md.")
                print("  This means CORE RULES format files were not read before")
                print("  the guide was built. The format cannot be trusted.")
                print()
                print("  Required reads вҖ” do these first, then rebuild the guide:")
                print()
                print("  Phase 1 (technical prerequisites):")
                for _f in BUILD_STATE_PHASE_1:
                    _name = _Path(_f).name
                    _ok = _bs_by_name.get(_name, _bs_entries.get(_f, False))
                    print(f"    {'вң…' if _ok else 'вқҢ'}  Brain/CORE RULES/{_name}")
                print()
                print("  Phase 2 (guide structure вҖ” the format lives here):")
                for _f in BUILD_STATE_PHASE_2:
                    _name = _Path(_f).name
                    _ok = _bs_by_name.get(_name, _bs_entries.get(_f, False))
                    print(f"    {'вң…' if _ok else 'вқҢ'}  Brain/CORE RULES/{_name}")
                print()
                print("  Do NOT patch the guide before doing the reads.")
                print("  The format is in CORE RULES вҖ” not in memory, not in past guides.")
                print("в”Ғ" * 60 + "\n")
                raise BuildStateHalt(2)
            # в”Җв”Җ END EARLY EXIT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

            # Phase 3 вҖ” always required (day shape rules apply to every guide).
            _bs_phase_check("Phase 3 (day shape) all entries are [x]", BUILD_STATE_PHASE_3)

            # Phase 4 вҖ” required when the guide has any stops.
            _bs_has_stops = bool(re.search(
                r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b',
                html, re.IGNORECASE,
            ))
            if _bs_has_stops:
                _bs_phase_check(
                    "Phase 4 (per-stop build) all entries are [x]",
                    BUILD_STATE_PHASE_4,
                    _ctx=" (stops detected in HTML)",
                )

            # Phase 5 вҖ” required per shipping .extras-section id.
            # Extract class and id independently so attribute order doesn't matter.
            _bs_shipped_ids: set[str] = set()
            for _tag in re.findall(r'<div\b[^>]*>', html, re.IGNORECASE):
                if re.search(r'\bextras-section\b', _tag, re.IGNORECASE):
                    _id_m = re.search(r'\bid\s*=\s*"([^"]+)"', _tag, re.IGNORECASE)
                    if _id_m:
                        _bs_shipped_ids.add(_id_m.group(1))
            _bs_p5_required: list[str] = []
            for _sid in _bs_shipped_ids:
                if _sid in BUILD_STATE_PHASE_5_MAP:
                    _bs_p5_required.append(BUILD_STATE_PHASE_5_MAP[_sid])
            if _bs_p5_required:
                _bs_phase_check(
                    "Phase 5 (per-section build) all shipping-section rule files are [x]",
                    sorted(set(_bs_p5_required)),
                    _ctx=f" ({len(_bs_p5_required)} extras section(s) ship)",
                )

    # в”Җв”Җв”Җ DOCUMENT HEAD в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # DOCUMENT STRUCTURE (head, CSS, versioning, file integrity)
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    print("в”Җв”Җ DOCUMENT HEAD в”Җв”Җ")

    has_viewport = bool(re.search(
        r'<meta\b[^>]*\bname\s*=\s*"viewport"[^>]*\bcontent\s*=\s*"[^"]*width\s*=\s*device-width[^"]*"',
        html,
        re.IGNORECASE,
    ))
    check(
        'Viewport meta tag present with width=device-width (checked; initial-scale not verified)',
        has_viewport,
        "Missing вҖ” browsers default to desktop-width rendering and the guide will appear "
        "zoomed-out on mobile. Add the tag per Guide Structure.html "
    )

    has_doctype = bool(re.search(r'<!DOCTYPE\s+html\s*>', html, re.IGNORECASE))
    check(
        "DOCTYPE html declaration present",
        has_doctype,
        "Missing <!DOCTYPE html> вҖ” browsers fall back to quirks mode and CSS mis-renders. "
        "Add as the first line per Guide Structure.html "
    )

    has_lang = bool(re.search(r'<html\b[^>]*\blang\s*=\s*"en"', html, re.IGNORECASE))
    check(
        'HTML lang attribute is "en" (<html lang="en">)',
        has_lang,
        'Missing or wrong вҖ” guide narrative is English regardless of destination. '
        'Per Guide Structure.html '
    )

    has_charset = bool(re.search(r'<meta\b[^>]*\bcharset\s*=\s*"UTF-8"', html, re.IGNORECASE))
    check(
        'Charset meta tag present (<meta charset="UTF-8">)',
        has_charset,
        'Missing вҖ” emoji glyphs depend on UTF-8 encoding. Per Guide Structure.html '
    )

    title_match = re.search(r'<title>([^<]+)</title>', html)
    # Title must be a plain place name вҖ” no em-dash, no date, no suffix.
    # Old format "City вҖ” Dates" retired 2026-05-19; title is now "City, Country".
    has_title = bool(title_match and title_match.group(1).strip())
    check(
        'Guide has a <title> tag with non-empty content',
        has_title,
        'No <title> tag found or empty вҖ” add one matching the Guides-Index.html entry. '
        'Per Guide Structure.html',
    )

    # в”Җв”Җв”Җ NO <h1> ANYWHERE IN GUIDE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _h1_tags = re.findall(r'<h1\b[^>]*>.*?</h1>', html, re.IGNORECASE | re.DOTALL)
    check(
        'No <h1> tags in guide body вҖ” use .title-city / .stop-name / .extras-title '
        '(per guide HTML contract; bare <h1> indicates auto-generated content injection)',
        len(_h1_tags) == 0,
        f'{len(_h1_tags)} <h1> tag(s) found вҖ” remove: '
        + '; '.join(t[:60] for t in _h1_tags[:3]),
    )

    # в”Җв”Җв”Җ TOOLBAR в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # TOOLBAR (Brain/Reference/Toolbar.html вҖ” universal, every HTML page)
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    print("\nв”Җв”Җ TOOLBAR в”Җв”Җ")
    # Every guide page must include the toolbar mount div + script immediately
    # after <body>, OUTSIDE .container, before any other content.
    # data-depth=2 and data-maxwidth=940 are locked for all pages in Guides/{City}/.
    # data-prev / data-next (optional) must be relative intra-Guides paths only вҖ”
    # prev/next navigation stays inside Guides/, never links outside.
    # вҶ‘ back-to-top button (.tb-top) is JS-generated at runtime вҖ” not in source HTML,
    # cannot be validated statically.

    # TB-1: toolbar-mount div present
    _tb_mount_m = re.search(
        r'<div\b[^>]*\bid\s*=\s*"toolbar-mount"[^>]*>',
        html, re.IGNORECASE,
    )
    check(
        'TB-1 toolbar-mount div present вҖ” <div id="toolbar-mount"> required on every guide page '
        '(Brain/Reference/Toolbar.html В§1)',
        bool(_tb_mount_m),
        'Missing <div id="toolbar-mount"> вҖ” add mount div immediately after <body>, before .container',
    )

    # TB-2: data-depth="2" present and correct for Guides/{City}/ pages
    _tb_depth_ok = bool(
        _tb_mount_m and re.search(r'\bdata-depth\s*=\s*"2"', _tb_mount_m.group(0))
    )
    check(
        'TB-2 data-depth="2" on toolbar-mount вҖ” guides live in Guides/{City}/, '
        '2 levels below Travel/ (Brain/Reference/Toolbar.html В§2)',
        _tb_depth_ok,
        'Missing or wrong data-depth вҖ” guide pages must use data-depth="2"; '
        'data-depth describes the PAGE location below Travel/, not the script path',
    )

    # TB-3: data-maxwidth="940" present on mount div (guides = 940, Trip-Essentials = 760)
    _tb_maxwidth_ok = bool(
        _tb_mount_m and re.search(r'\bdata-maxwidth\s*=\s*"940"', _tb_mount_m.group(0))
    )
    check(
        'TB-3 data-maxwidth="940" on toolbar-mount вҖ” guide content width is 940px '
        '(Brain/Reference/Toolbar.html В§3)',
        _tb_maxwidth_ok,
        'Missing or wrong data-maxwidth вҖ” guide pages must use data-maxwidth="940" '
        '(Trip-Essentials pages use 760, but those are not validated here)',
    )

    # TB-4: toolbar.js script tag present with correct relative path for depth=2
    # toolbar.js lives in Travel-Website/assets/ (2026-06-13 reorg); a guide at
    # Guides/{City}/ reaches it two levels up: ../../assets/toolbar.js
    _tb_script_m = re.search(
        r'<script\b[^>]*\bsrc\s*=\s*"(\.\./\.\./assets/toolbar\.js[^"]*)"[^>]*>',
        html, re.IGNORECASE,
    )
    check(
        'TB-4 toolbar.js script tag present вҖ” <script src="../../assets/toolbar.js"> required '
        '(Brain/Reference/Toolbar.html В§1; toolbar.js lives in Travel-Website/assets/ вҖ” permanent home вҖ” '
        'so guide pages reach it 2 levels up, from Guides/{City}/ to the site root then assets/)',
        bool(_tb_script_m),
        'Missing <script src="../../assets/toolbar.js"> вҖ” add immediately after toolbar-mount div; '
        'two ../ segments + assets/: toolbar.js lives in Travel-Website/assets/, two levels up from '
        'Guides/{City}/ (never load it from Guides/ or the Travel root вҖ” assets stay in assets/)',
    )

    # TB-5: toolbar-mount is the first element inside .container, before .title-page
    # All guides place the toolbar as the first item inside .container (not outside it).
    # Check: toolbar-mount appears before .title-page in source order.
    _tb5_title_m = re.search(r'class\s*=\s*"[^"]*\btitle-page\b[^"]*"', html, re.IGNORECASE)
    _tb_title_page_pos = _tb5_title_m.start() if _tb5_title_m else -1
    _tb_mount_pos      = _tb_mount_m.start() if _tb_mount_m else -1
    _tb_before_title = (
        _tb_mount_pos != -1
        and _tb_title_page_pos != -1
        and _tb_mount_pos < _tb_title_page_pos
    )
    check(
        'TB-5 toolbar-mount appears before .title-page вҖ” toolbar is first element '
        'in .container, before the hotel/city title block (Brain/Reference/Toolbar.html В§1)',
        _tb_before_title,
        'toolbar-mount div does not appear before .title-page вҖ” move mount div and '
        'script tag to the top of .container, as the very first items',
    )

    # TB-6: script tag immediately follows the toolbar-mount element (closing </div> +
    # optional whitespace only between the opening tag match and the script tag).
    # Note: _tb_mount_m matches the *opening* <div id="toolbar-mount"...> tag only.
    # The element also has a closing </div>; closing tags and whitespace are allowed.
    if _tb_mount_m and _tb_script_m:
        _tb_between_start = _tb_mount_m.end()
        _tb_script_start  = _tb_script_m.start()
        if _tb_script_start >= _tb_between_start:
            _tb_between = html[_tb_between_start:_tb_script_start]
            _tb_between_clean = RE_HTML_COMMENT.sub('', _tb_between).strip()
            # Strip closing tags (</anything>) вҖ” only </div> of mount should be here
            _tb_between_no_close = re.sub(r'</[^>]+>', '', _tb_between_clean).strip()
            # Fail only if any OPENING tags remain (no <div>, <p>, <link>, etc.)
            _tb_script_adjacent = not bool(re.search(r'<', _tb_between_no_close))
        else:
            _tb_script_adjacent = False
    else:
        # If mount or script is missing, TB-1/TB-4 already caught it вҖ” skip adjacency check
        _tb_script_adjacent = True
    check(
        'TB-6 toolbar.js script tag immediately follows mount div вҖ” no opening HTML '
        'elements between them (Brain/Reference/Toolbar.html В§1)',
        _tb_script_adjacent,
        'Found HTML elements between toolbar-mount div and toolbar.js script tag вҖ” '
        'the script must directly follow the mount div (closing </div> and whitespace only)',
    )

    # TB-7: data-prev (when present) is a relative intra-Guides path
    # Prev/next stay inside Guides/ вҖ” relative paths only, no external URLs.
    # Accepts ../ (guideвҶ’guide or guideвҶ’index) and ./ (indexвҶ’guide).
    _tb_prev_m = _tb_mount_m and re.search(
        r'\bdata-prev\s*=\s*"([^"]*)"', _tb_mount_m.group(0)
    )
    if _tb_prev_m:
        _tb_prev_val = _tb_prev_m.group(1)
        _tb_prev_ok = (
            bool(_tb_prev_val)
            and (_tb_prev_val.startswith('../') or _tb_prev_val.startswith('./'))
            and not re.search(r'https?://', _tb_prev_val)
            and _tb_prev_val.endswith('.html')
        )
        check(
            'TB-7 data-prev is a relative intra-Guides path вҖ” '
            'prev/next stay inside Guides/, never external URLs (Navigation.html В§ 2вҖ“В§3); '
            'guide pages use ../CityName/file.html; index uses ./CityName/file.html',
            _tb_prev_ok,
            f'data-prev="{_tb_prev_val}" вҖ” must start with ../ or ./ and end with .html; '
            'no absolute URLs; path must point to another page within Guides/',
        )

    # TB-8: data-next (when present) is a relative intra-Guides path
    _tb_next_m = _tb_mount_m and re.search(
        r'\bdata-next\s*=\s*"([^"]*)"', _tb_mount_m.group(0)
    )
    if _tb_next_m:
        _tb_next_val = _tb_next_m.group(1)
        _tb_next_ok = (
            bool(_tb_next_val)
            and (_tb_next_val.startswith('../') or _tb_next_val.startswith('./'))
            and not re.search(r'https?://', _tb_next_val)
            and _tb_next_val.endswith('.html')
        )
        check(
            'TB-8 data-next is a relative intra-Guides path вҖ” '
            'prev/next stay inside Guides/, never external URLs (Navigation.html В§ 2вҖ“В§3); '
            'guide pages use ../CityName/file.html; index uses ./CityName/file.html',
            _tb_next_ok,
            f'data-next="{_tb_next_val}" вҖ” must start with ../ or ./ and end with .html; '
            'no absolute URLs; path must point to another page within Guides/',
        )

    # TB-9: FOOTER SHARING BAR REMOVED 2026-06-21 (Dani) вҖ” the footnote.js footer
    # sharing link is gone for good (archived; all traces stripped). A guide must
    # still load toolbar.js (navigation stays) and must NOT carry an inline footer
    # div with a hardcoded public URL, nor load the deleted footnote.js directly.
    # Rule source: Brain/Reference/Toolbar.html В§6 (Removed). History: retired
    # 2026-06-06, removed 2026-06-21.
    _tb9_loads_toolbar = bool(re.search(r'<script[^>]+toolbar\.js', html, re.IGNORECASE))
    _tb9_stale_inline = bool(re.search(
        r'<div[^>]*text-align\s*:\s*center[^>]*>'
        r'.*?dbellinello\.github\.io/(?:travel_guides|Travel)/Guides/.*?</div>',
        html, re.IGNORECASE | re.DOTALL,
    ))
    _tb9_direct_footnote = bool(re.search(
        r'<script[^>]+footnote\.js', html, re.IGNORECASE,
    ))
    check(
        'TB-9 footer sharing bar REMOVED (2026-06-21) вҖ” guide loads toolbar.js '
        '(navigation only), carries no inline footer div, and does not load the '
        'deleted footnote.js (Brain/Reference/Toolbar.html В§6 вҖ” footer sharing link removed)',
        _tb9_loads_toolbar and not _tb9_stale_inline and not _tb9_direct_footnote,
        "Ensure the guide loads toolbar.js, remove any inline footer div with a "
        "hardcoded github.io URL, and remove any <script src=вҖҰfootnote.js> tag "
        "(footnote.js was deleted 2026-06-21)",
    )

    # TB-10: guide is in the carousel chain вҖ” data-prev AND data-next are both
    # REQUIRED on every guide page (being carousel-connected is mandatory, not
    # optional). Additionally, the chain must be bidirectionally consistent:
    # the file pointed to by data-prev must have a data-next that resolves back
    # to THIS guide, and the file pointed to by data-next must have a data-prev
    # that resolves back to THIS guide. This catches the Alaska failure mode:
    # a guide can appear in Guides-Index.html yet be unreachable by вҶҗ/вҶ’ arrows
    # because its toolbar-mount has no prev/next, or because the adjacent guides
    # in the chain don't point back to it. Only runs for depth-2 guide pages
    # (Guides-Index.html, depth=1, is not a validated guide page).
    # Source: Navigation.html В§ 2вҖ“В§3.
    _tb10_is_depth2 = bool(_tb_mount_m and re.search(r'data-depth\s*=\s*"2"', _tb_mount_m.group(0)))
    if _tb10_is_depth2:
        _tb10_has_prev = bool(_tb_prev_m)
        _tb10_has_next = bool(_tb_next_m)
        _tb10_back_ok  = True   # prev.data-next вҶ’ this guide
        _tb10_fwd_ok   = True   # next.data-prev вҶ’ this guide
        _tb10_detail   = []

        if _tb10_has_prev and _tb10_has_next:
            _this_path  = Path(filename).resolve()
            _guide_dir  = _this_path.parent

            def _resolve_href(base_dir: Path, raw_href: str) -> Path:
                """Decode %20 then resolve relative href to absolute Path."""
                return (base_dir / _url_unquote(raw_href)).resolve()

            # Back-link: prev file's data-next must point back here
            _prev_href_raw = _tb_prev_m.group(1)
            _prev_path     = _resolve_href(_guide_dir, _prev_href_raw)
            _prev_html = _safe_read(_prev_path, errors='strict') if _prev_href_raw else ''
            if _prev_html:
                _prev_mount_m = re.search(r'<div\b[^>]*\bid\s*=\s*"toolbar-mount"[^>]*>', _prev_html, re.DOTALL)
                if _prev_mount_m:
                    _prev_next_attr = re.search(r'\bdata-next\s*=\s*"([^"]*)"', _prev_mount_m.group(0))
                    if _prev_next_attr:
                        _prev_points_to = _resolve_href(_prev_path.parent, _prev_next_attr.group(1))
                        if _prev_points_to != _this_path:
                            _tb10_back_ok = False
                            _tb10_detail.append(
                                f"prev guide ({_prev_path.name}) data-next={_prev_next_attr.group(1)!r} "
                                f"вҶ’ {_prev_points_to.name}, expected {_this_path.name}"
                            )
                    else:
                        _tb10_back_ok = False
                        _tb10_detail.append(f"prev guide ({_prev_path.name}) has no data-next")
                else:
                    _tb10_back_ok = False
                    _tb10_detail.append(f"prev guide ({_prev_path.name}) has no toolbar-mount")
            else:
                _tb10_back_ok = False
                _tb10_detail.append(f"prev file not found: {_prev_path.name}")

            # Forward-link: next file's data-prev must point back here
            _next_href_raw = _tb_next_m.group(1)
            _next_path     = _resolve_href(_guide_dir, _next_href_raw)
            _next_html = _safe_read(_next_path, errors='strict') if _next_href_raw else ''
            if _next_html:
                _next_mount_m = re.search(r'<div\b[^>]*\bid\s*=\s*"toolbar-mount"[^>]*>', _next_html, re.DOTALL)
                if _next_mount_m:
                    _next_prev_attr = re.search(r'\bdata-prev\s*=\s*"([^"]*)"', _next_mount_m.group(0))
                    if _next_prev_attr:
                        _next_points_to = _resolve_href(_next_path.parent, _next_prev_attr.group(1))
                        if _next_points_to != _this_path:
                            _tb10_fwd_ok = False
                            _tb10_detail.append(
                                f"next guide ({_next_path.name}) data-prev={_next_prev_attr.group(1)!r} "
                                f"вҶ’ {_next_points_to.name}, expected {_this_path.name}"
                            )
                    else:
                        _tb10_fwd_ok = False
                        _tb10_detail.append(f"next guide ({_next_path.name}) has no data-prev")
                else:
                    _tb10_fwd_ok = False
                    _tb10_detail.append(f"next guide ({_next_path.name}) has no toolbar-mount")
            else:
                _tb10_fwd_ok = False
                _tb10_detail.append(f"next file not found: {_next_path.name}")

        _tb10_pass = _tb10_has_prev and _tb10_has_next and _tb10_back_ok and _tb10_fwd_ok
        _tb10_msg  = []
        if not _tb10_has_prev:
            _tb10_msg.append("data-prev missing on toolbar-mount")
        if not _tb10_has_next:
            _tb10_msg.append("data-next missing on toolbar-mount")
        _tb10_msg.extend(_tb10_detail)
        check(
            'TB-10 guide is in the carousel вҖ” data-prev + data-next required; '
            'chain bidirectionally consistent (Navigation.html В§ 2вҖ“В§3)',
            _tb10_pass,
            ('Guide not properly connected to the вҶҗ/вҶ’ carousel:\n  ' + '\n  '.join(_tb10_msg))
            if _tb10_msg else '',
        )

    # TB-11: LAST-UPDATED STAMP вҖ” the guide's toolbar-mount div must carry a
    # well-formed data-updated="YYYY-MM" attribute. toolbar.js renders it as
    # "Updated Month Year" at the top of the guide (under the title block).
    # The date is EXPLICIT/manual on purpose вҖ” it is the guide's content-currency
    # month and only moves on a genuine content refresh, NOT on bug fixes, format
    # changes, validation re-stamps, or deploys. Rule source: Brain/Reference/
    # Toolbar.html В§10. (Replaced the retired-footnote guard check 2026-06-21;
    # the old document.lastModified auto-stamp was removed the same day.)
    _tb11_mount = _tb_mount_m
    _tb11_val = ''
    if _tb11_mount:
        _tb11_m = re.search(r'data-updated="([^"]*)"', _tb11_mount.group(0))
        _tb11_val = _tb11_m.group(1) if _tb11_m else ''
    _tb11_ok = bool(re.fullmatch(r'(20\d{2})-(0[1-9]|1[0-2])', _tb11_val))
    check(
        'TB-11 last-updated stamp вҖ” toolbar-mount carries data-updated="YYYY-MM" '
        '(valid month); toolbar.js renders it as "Updated Month Year" at the top '
        '(Brain/Reference/Toolbar.html В§10)',
        _tb11_ok,
        'Add data-updated="YYYY-MM" (e.g. data-updated="2026-06") to the '
        '<div id="toolbar-mount"> вҖ” it is the guide\'s content-currency month and '
        'powers the "Updated Month Year" stamp. Bump it only on a real content refresh, '
        f'not on bug fixes or format changes. Found: {_tb11_val!r}',
    )

    # в”Җв”Җв”Җ NOTHING BEFORE .title-page INSIDE .container в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _container_m = re.search(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bcontainer\b[^"]*"[^>]*>(.*?)'
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\btitle-page\b[^"]*"',
        html, re.IGNORECASE | re.DOTALL,
    )
    if _container_m:
        _before_title = RE_HTML_COMMENT.sub('', _container_m.group(1))
        # Strip toolbar-mount div + toolbar.js script tag вҖ” they are intentionally
        # first inside .container on every guide page (Brain/Reference/Toolbar.html В§1). Removing
        # them before the prose/element check prevents a false positive here.
        _before_title = re.sub(
            r'<div\b[^>]*\bid\s*=\s*"toolbar-mount"[^>]*>.*?</div>\s*'
            r'<script\b[^>]*\bsrc\s*=\s*"[^"]*toolbar\.js[^"]*"[^>]*>\s*(?:</script>)?',
            '', _before_title, flags=re.IGNORECASE | re.DOTALL,
        )
        _before_title_stripped = _before_title.strip()
        _has_content_before_title = bool(re.search(r'\S', _before_title_stripped))
    else:
        _has_content_before_title = False  # no container found вҖ” other checks cover that
    check(
        'Nothing before .title-page inside .container вҖ” first child must be the '
        'hotel/city title block; no banners, <h1>, or injected prose above it '
        '(per guide HTML contract)',
        not _has_content_before_title,
        f'Content found before .title-page: '
        + repr(_before_title_stripped[:120])
        if _has_content_before_title else '',
    )

    # в”Җв”Җв”Җ INLINE <style> BLOCK BANNED в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ INLINE STYLE BLOCK в”Җв”Җ")
    _head_m = re.search(r'<head\b[^>]*>(.*?)</head>', html, re.IGNORECASE | re.DOTALL)
    _head_html = _head_m.group(1) if _head_m else html
    # Strip HTML comments from head before checking to avoid false matches.
    _head_stripped = RE_HTML_COMMENT.sub('', _head_html)
    _has_inline_style = bool(re.search(r'<style\b', _head_stripped, re.IGNORECASE))
    check(
        'No inline <style> block in <head> вҖ” load via <link rel="stylesheet" href="../../assets/guide-style.css"> only '
        '(inline CSS drifts from shared tokens; every guide must reference the external stylesheet)',
        not _has_inline_style,
        'Inline <style> block detected вҖ” remove it and replace with '
        '<link rel="stylesheet" href="../../assets/guide-style.css">',
    )

    # Scope the stylesheet-link check to the <head> HTML with BOTH HTML
    # comments AND <style>вҖҰ</style> blocks removed вҖ” otherwise the CSS
    # /* block comment */ framing inside an inline <style> (which may
    # contain the URL as documentation) fools the regex. This was exactly
    # the palo_alto_v5 false-positive: the в•‘ CSS comment in the inlined
    # guide-style.css contained "<link rel=вҖҰ href="../guide-style.css">",
    # so the old check passed even though no real <link> tag existed.
    _head_no_style = re.sub(r'<style\b[^>]*>.*?</style>', '', _head_stripped,
                            flags=re.IGNORECASE | re.DOTALL)
    # Check rel and href independently so attribute order doesn't matter.
    # Updated 2026-05-31: canonical stylesheet is now guide-style.css (gold reskin).
    has_stylesheet = any(
        re.search(r'\brel\s*=\s*"stylesheet"', _tag, re.IGNORECASE)
        and re.search(r'\bhref\s*=\s*"\.\./\.\./assets/guide-style\.css(?:\?[^"]*)?"\s*', _tag, re.IGNORECASE)
        for _tag in re.findall(r'<link\b[^>]*>', _head_no_style, re.IGNORECASE)
    )
    check(
        'Stylesheet link вҶ’ canonical ../../assets/guide-style.css',
        has_stylesheet,
        'Missing or wrong path вҖ” every guide must read from ../../assets/guide-style.css '
        '(no inline styles, no per-guide CSS copy). Per Guide Structure.html '
    )

    # No Google Fonts вҖ” guide typography is system fonts via guide-style.css only
    _has_google_fonts = bool(re.search(
        r'fonts\.googleapis\.com|fonts\.gstatic\.com',
        _head_html, re.IGNORECASE,
    ))
    check(
        'No Google Fonts link',
        not _has_google_fonts,
        'Google Fonts link detected in <head> вҖ” guides use system fonts via guide-style.css only. '
        'Remove the <link> tag. Per Universal Formatting Rules ',
    )

    # в”Җв”Җв”Җ LINKS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # CROSS-CUTTING FORMAT (links, entities, row formats, photos)
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    print("в”Җв”Җ LINKS в”Җв”Җ")

    all_links = re.findall(r'<a [^>]*href="[^"]*"[^>]*>', html)
    # tel: and mailto: links trigger the OS dialer/mail client, not a new
    # tab, so target="_blank" is meaningless for them вҖ” skip both.
    links_no_blank = [
        l[:100] for l in all_links
        if 'target="_blank"' not in l
        and 'href="#' not in l
        and 'mailto:' not in l
        and 'href="tel:' not in l
        and not re.search(r'href="\.\.?[/.]', l)
    ]
    check(
        'All external links open in a new tab (target="_blank")',
        len(links_no_blank) == 0,
        f'{len(links_no_blank)} link(s) missing target="_blank": {links_no_blank[:3]}'
        if links_no_blank else ""
    )

    # в”Җв”Җв”Җ PHONE / EMAIL BAN в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rules for Claude.html В§7: "phone, email вҖҰ belong in research notes,
    # not in the guide." tel:/mailto: hrefs are deliberately skipped by the
    # target="_blank" check above (dialer/mail client, not a new tab) вҖ” that
    # made them invisible to every validator. Catch them here, plus any raw
    # email/phone string in the guide's visible text (added 2026-07-11, audit Gap 1).
    print("\nв”Җв”Җ PHONE / EMAIL BAN в”Җв”Җ")
    _pe_tel_mailto_hrefs = re.findall(r'href\s*=\s*"\s*((?:tel|mailto):[^"]*)"', html, re.IGNORECASE)
    _pe_no_script = re.sub(r'<script[^>]*>.*?</script>', '', html, flags=re.DOTALL | re.IGNORECASE)
    _pe_no_href = re.sub(r'href\s*=\s*"[^"]*"', '', _pe_no_script, flags=re.IGNORECASE)
    _pe_visible = RE_STRIP_TAGS.sub(' ', _pe_no_href)
    _pe_emails = re.findall(RE_EMAIL_PATTERN, _pe_visible)
    _pe_phones = re.findall(RE_PHONE_PATTERN, _pe_visible)
    _pe_violations = (
        [f'tel:/mailto: href: {h[:40]}' for h in _pe_tel_mailto_hrefs]
        + [f'email in body text: {e}' for e in _pe_emails]
        + [f'phone number in body text: {p.strip()}' for p in _pe_phones]
    )
    check(
        'No phone number or email address anywhere in guide content '
        '(Rules for Claude.html В§7 вҖ” research-notes-only info)',
        len(_pe_violations) == 0,
        f'{len(_pe_violations)} violation(s): {_pe_violations[:5]}' if _pe_violations else ""
    )

    # в”Җв”Җв”Җ MALFORMED HTML ENTITIES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ MALFORMED HTML ENTITIES в”Җв”Җ")
    _entity_text = RE_STRIP_TAGS.sub( ' ', html)   # strip all tags/attributes
    _bad_entities = re.findall(r'&[a-zA-Z]{2,8}(?!;|\w)', _entity_text)
    check(
        'No malformed HTML entities (missing semicolon)',
        len(_bad_entities) == 0,
        f'Malformed entities found: {list(set(_bad_entities))[:10]}' if _bad_entities else ''
    )

    # в”Җв”Җв”Җ BARE DOMAIN NAMES MUST BE CLICKABLE LINKS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ BARE DOMAIN NAMES (must be <a> links) в”Җв”Җ")
    # Build <a>...</a> block ranges so link-text domains don't false-fire.
    _a_block_ranges: list[tuple[int, int]] = []
    for _am in re.finditer(r'<a\b[^>]*>.*?</a>', html, re.DOTALL | re.IGNORECASE):
        _a_block_ranges.append((_am.start(), _am.end()))

    def _in_a_block(pos: int) -> bool:
        for s, e in _a_block_ranges:
            if s <= pos < e:
                return True
        return False

    def _in_html_tag(html: str, pos: int) -> bool:
        """True if pos is inside a tag attribute (between < and >)."""
        before = html[:pos]
        return before.rfind('<') > before.rfind('>')

    _DIV_OPEN_RE = re.compile(r'<div(?=[\s>/])', re.IGNORECASE)

    def _walk_balanced_div(text, start):
        """Return (inner, end_index) for the <div> opening at `start`.
        Handles nested <div>s by tracking depth."""
        depth = 1
        j = start
        while j < len(text) and depth > 0:
            nxt_open_m = _DIV_OPEN_RE.search(text, j)
            nxt_open = nxt_open_m.start() if nxt_open_m else -1
            nxt_close = text.find('</div>', j)
            if nxt_close == -1:
                return text[start:], len(text)
            if nxt_open != -1 and nxt_open < nxt_close:
                depth += 1
                j = nxt_open + 4
            else:
                depth -= 1
                if depth == 0:
                    return text[start:nxt_close], nxt_close + 6
                j = nxt_close + 6
        return text[start:j], j

    _DOMAIN_RE = re.compile(
        r'\b([a-zA-Z0-9][a-zA-Z0-9\-]*\.(?:'
        r'com|org|net|gov|io|co|app|uk|fr|it|de|es|jp|au|ca|ch|nl'
        r'|be|pt|se|no|dk|fi|nz|sg|hk|tw|us|eu|info|edu|museum|travel'
        r'))\b',
        re.IGNORECASE,
    )
    _bare_domains: list[str] = []
    _seen_bare: set[str] = set()
    for _dm in _DOMAIN_RE.finditer(html):
        _pos = _dm.start()
        _dom = _dm.group(1).lower()
        if _dom in _seen_bare:
            continue
        # Skip if inside an HTML tag attribute (href="...", src="...", etc.)
        if _in_html_tag(html, _pos):
            continue
        # Skip if inside an <a>...</a> block (link text showing the domain)
        if _in_a_block(_pos):
            continue
        # Skip HTML comment content
        before = html[:_pos]
        comment_start = before.rfind('<!--')
        comment_end = before.rfind('-->')
        if comment_start > comment_end:
            continue
        _seen_bare.add(_dom)
        _bare_domains.append(_dom)
    check(
        "No bare domain names in visible text вҖ” every website URL must be a clickable <a> link "
        "(per Links.html вҖ” every domain in visible text must be wrapped in an anchor tag)",
        len(_bare_domains) == 0,
        (f"{len(_bare_domains)} bare domain(s) not wrapped in <a href>: "
         + "; ".join(f"'{d}'" for d in _bare_domains[:5])
         + " вҖ” wrap each in <a href=\"https://{domain}\" target=\"_blank\">{domain}</a>")
        if _bare_domains else "",
    )

    # в”Җв”Җв”Җ рҹ“– WIKIPEDIA LINK TEXT вҖ” EXACTLY "Wikipedia" в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    print("\nв”Җв”Җ WIKIPEDIA LINK TEXT вҖ” exactly 'Wikipedia' в”Җв”Җ")
    wiki_text_hits: list[str] = []
    wiki_link_re = re.compile(
        r'<a\b[^>]*href="https?://(?:www\.)?en\.wikipedia\.org/[^"]+"[^>]*>([^<]*)</a>',
        re.IGNORECASE,
    )
    for m in wiki_link_re.finditer(html):
        text = m.group(1).strip()
        if text != 'Wikipedia':
            wiki_text_hits.append(text[:60] if text else '(empty)')
    check(
        "рҹ“– Wikipedia link text is exactly 'Wikipedia' "
        "(per Links.html вҖ” no descriptor, no article-title appended)",
        not wiki_text_hits,
        (f"{len(wiki_text_hits)} Wikipedia link(s) with non-canonical text: "
         + "; ".join(f'"{t}"' for t in wiki_text_hits[:3]))
        if wiki_text_hits else "",
    )

    # в”Җв”Җв”Җ рҹ“– ROW FORMAT вҖ” nothing between icon and Wikipedia link в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ рҹ“– ROW FORMAT вҖ” nothing between icon and link в”Җв”Җ")
    _wiki_before_link_bad: list[str] = []
    for _wbm in re.finditer(
        r'<div[^>]*>\s*рҹ“–\s*(.*?)\s*</div>', html, re.DOTALL | re.IGNORECASE
    ):
        _wc = _wbm.group(1)
        # Text between рҹ“– and the first <a>
        _before_a = re.split(r'<a\b', _wc, maxsplit=1)[0]
        _before_text = RE_STRIP_TAGS.sub( '', _before_a).strip()
        if _before_text:
            _wiki_before_link_bad.append(f'text before link: "{_before_text[:60]}"')
    check(
        'рҹ“– row format: nothing between icon and Wikipedia link вҖ” '
        'format must be exactly рҹ“– <a href="...wikipedia...">Wikipedia</a> '
        '(per Icon Order and Format.html Pos 2 (outside the blue box) вҖ” icon immediately before link)',
        len(_wiki_before_link_bad) == 0,
        f"{len(_wiki_before_link_bad)} рҹ“– row(s) with text before link: "
        + "; ".join(_wiki_before_link_bad[:5])
        if _wiki_before_link_bad else "",
    )

    # в”Җв”Җв”Җ EVERY рҹ“Қ IS A GOOGLE MAPS LINK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ EVERY рҹ“Қ IS A GOOGLE MAPS LINK в”Җв”Җ")
    pin_no_maps_hits: list[str] = []
    for m in re.finditer(r'рҹ“Қ', html):
        # Look at the next 250 chars (allow for whitespace + opening <a> tag).
        following = html[m.end():m.end() + 250]
        if not re.search(
            r'<a\b[^>]*href="[^"]*google\.com/maps[^"]*"',
            following, re.IGNORECASE,
        ):
            ctx_start = max(0, m.start() - 30)
            ctx_end = min(len(html), m.end() + 60)
            ctx = RE_STRIP_TAGS.sub( '', html[ctx_start:ctx_end])
            ctx = RE_WS.sub(' ', ctx).strip()
            pin_no_maps_hits.append(f"вҖҰ{ctx}вҖҰ")
    check(
        "Every рҹ“Қ is followed by a Google Maps <a> link "
        "(per Links.html вҖ” every address is a Maps link, every time)",
        not pin_no_maps_hits,
        (f"{len(pin_no_maps_hits)} рҹ“Қ occurrence(s) not followed by a Maps link: "
         + "; ".join(pin_no_maps_hits[:3]))
        if pin_no_maps_hits else "",
    )

    # в”Җв”Җв”Җ рҹ“Қ MUST BE FIRST TOKEN IN ITS <div> вҖ” no merging with вҸ°/рҹҸӣ/other в”Җв”Җ
    _ROW_EMOJIS_BEFORE_PIN = (
        'вҸ°', 'рҹҸӣ', 'рҹҸӣпёҸ', 'рҹҶ“', 'рҹ•җ', 'вҸі', 'рҹ‘Ҙ', 'вҡ пёҸ', 'рҹ””', 'вӯҗ',
    )
    # Container/wrapper div classes that are NOT leaf row divs вҖ” skip these
    # to avoid false-positives where an outer wrapper div spans emoji + рҹ“Қ
    # across nested children (old BR-based tour-box format, stop-block, etc.).
    _CONTAINER_DIV_CLASSES = (
        'tour-box', 'ticket-box', 'entry-body', 'shows-box', 'transit-box',
        'stop-block', 'extras-section', 'day-block', 'stop-photos',
        'local-tastes', 'ride-apps', 'next', 'next-tram', 'hotel-first',
        'arrive-first', 'title-card', 'overview-card', 'overview-day', 'page',
    )
    pin_merged_hits: list[str] = []
    for m in re.finditer(
        r'<div\b([^>]*)>((?:(?!<div\b)(?!</div>).)*?)рҹ“Қ((?:(?!<div\b)(?!</div>).)*?)</div>',
        html, re.IGNORECASE | re.DOTALL,
    ):
        div_attrs = m.group(1)
        # Skip container/wrapper divs вҖ” they are not leaf row divs
        if any(cls in div_attrs for cls in _CONTAINER_DIV_CLASSES):
            continue
        before = m.group(2)
        before_plain = RE_STRIP_TAGS.sub( '', before).strip()
        if not before_plain:
            continue
        # Only flag if a row-level emoji appears BEFORE рҹ“Қ in the same div
        if any(before_plain.startswith(e) or f' {e}' in before_plain for e in _ROW_EMOJIS_BEFORE_PIN):
            full_plain = RE_STRIP_TAGS.sub( '', m.group(0)).strip()[:80]
            pin_merged_hits.append(f'"{full_plain}"')
    check(
        'рҹ“Қ always opens its own <div> row вҖ” never merged onto вҸ°/рҹҸӣ/other line '
        '(e.g. вҸ° ~1h рҹ“Қ Address is wrong; use two separate <div> elements)',
        not pin_merged_hits,
        (f'{len(pin_merged_hits)} merged рҹ“Қ row(s): '
         + '; '.join(pin_merged_hits[:3]))
        if pin_merged_hits else '',
    )

    # в”Җв”Җв”Җ ADDRESS ANCHOR FORMAT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ ADDRESS ANCHOR FORMAT вҖ” country leak + middle-dot в”Җв”Җ")
    # Operational lookup data вҖ” country-name tokens are validator constants,
    # not Brain prose (exempt from the no-real-place-names rule in cleanliness_checks.md).
    COUNTRY_NAMES = {
        'france', 'italy', 'spain', 'portugal', 'germany', 'belgium',
        'netherlands', 'holland', 'switzerland', 'austria', 'greece',
        'turkey', 'czechia', 'czech republic', 'hungary', 'poland',
        'croatia', 'slovenia', 'slovakia', 'ireland', 'scotland',
        'england', 'wales', 'uk', 'united kingdom', 'great britain',
        'usa', 'u.s.a.', 'u.s.', 'united states', 'canada', 'mexico',
        'japan', 'china', 'korea', 'south korea', 'thailand', 'vietnam',
        'singapore', 'indonesia', 'philippines', 'malaysia', 'india',
        'taiwan', 'hong kong', 'australia', 'new zealand',
        'brazil', 'argentina', 'chile', 'peru', 'colombia', 'uruguay',
        'south africa', 'egypt', 'morocco', 'tunisia',
        'iceland', 'norway', 'sweden', 'denmark', 'finland',
        'estonia', 'latvia', 'lithuania', 'romania', 'bulgaria',
        'serbia', 'bosnia', 'bosnia and herzegovina', 'albania',
        'north macedonia', 'macedonia', 'montenegro', 'kosovo',
        'ukraine', 'russia', 'monaco', 'luxembourg', 'liechtenstein',
        'andorra', 'malta', 'cyprus', 'israel', 'jordan', 'lebanon',
        'uae', 'united arab emirates',
    }
    addr_country_hits: list[str] = []
    addr_separator_hits: list[str] = []
    maps_anchor_re = re.compile(
        r'<a\b[^>]*href="[^"]*google\.com/maps[^"]*"[^>]*>([^<]+)</a>',
        re.IGNORECASE,
    )
    for m in maps_anchor_re.finditer(html):
        text = m.group(1).strip()
        # (1) Country leak вҖ” last comma- OR middle-dot-separated segment is a
        # country. Previously only comma-split was tested, so a country
        # appended after the canonical middle-dot (`Street В· Neighborhood В·
        # Country`) slipped through untested вҖ” closed 2026-07-11
        # (enforcement-gap sweep; 0 guides affected fleet-wide).
        _leak = False
        for _sep in (',', 'В·'):
            _parts = text.split(_sep)
            if len(_parts) >= 2 and _parts[-1].strip().lower() in COUNTRY_NAMES:
                _leak = True
                break
        if _leak:
            addr_country_hits.append(text[:80])
        # (2) Wrong separator вҖ” any comma-shaped address must use the
        # canonical ` В· ` separator, with or without a postal code. Previously
        # gated on `has_postal`, so a plain comma address with no postal code
        # (`123 Main St, Downtown`) passed silently вҖ” closed 2026-07-11
        # (enforcement-gap sweep; 0 guides affected fleet-wide).
        if ',' in text and 'В·' not in text:
            addr_separator_hits.append(text[:80])
    check(
        "Address anchors don't leak country "
        "(per Links.html рҹ“Қ Google Maps вҖ” `Street В· Neighborhood`, no country; postal codes banned 2026-05-19)",
        not addr_country_hits,
        (f"{len(addr_country_hits)} address(es) ending in a country name: "
         + "; ".join(f'"{t}"' for t in addr_country_hits[:3]))
        if addr_country_hits else "",
    )
    check(
        "Address anchors use middle-dot ` В· ` separator вҖ” no comma-separated address shape "
        "(per Links.html рҹ“Қ Google Maps вҖ” locked separator; postal codes banned 2026-05-19)",
        not addr_separator_hits,
        (f"{len(addr_separator_hits)} address(es) using `, ` instead of ` В· ` "
         f"as the separator: " + "; ".join(f'"{t}"' for t in addr_separator_hits[:3]))
        if addr_separator_hits else "",
    )

    # NOTE (2026-07-11, enforcement-gap sweep): the July 2026 audit listed a
    # "stop-address city-name ban" as NOT ENFORCED, citing the removed-2026-05-15
    # check above. That's stale вҖ” a working equivalent already exists further
    # down this function ("рҹ“Қ MAPS LINK вҖ” HOME CITY IN DISPLAY TEXT", search
    # _maps_city_hits): it hard-fails a рҹ“Қ Maps link whose display text repeats
    # city_text, scoped to links within 400 chars of a рҹ“Қ emoji (excludes the
    # title-hotel/title-address banner, which legitimately names the city) and
    # carves out real street names that happen to start with the city token.
    # The audit's author grepped only this ADDRESS ANCHOR FORMAT block and
    # missed the other implementation living in the TITLE PAGE block. No new
    # check added here вҖ” would have duplicated it (and, tested against Azores/
    # Bhutan, over-fired on the title-hotel/title-address banner besides).

    # в”Җв”Җв”Җ GLOBAL NO-POSTAL-CODE BAN (all address anchors) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule: postal/ZIP codes are banned from every guide address (Links.html рҹ“Қ;
    # "рҹ“Қ Street В· Neighborhood", no postal вҖ” banned 2026-05-19). The address is the
    # only place a postal code would appear. Added 2026-06-17 (Dani: "no postal code
    # anywhere in the guide" вҖ” the 'global check' the code comments referenced never
    # actually existed; only a separator check did, which missed postal codes that
    # used the ` В· ` separator).
    # Scope to рҹ“Қ ADDRESS anchors only (the Maps link that follows a рҹ“Қ). This
    # excludes rating/review links (which also use google.com/maps URLs and whose
    # "N.Nвӯҗ В· NNNN+ reviews" text would otherwise trip the digit scan).
    _pin_addr_re = re.compile(
        r'рҹ“Қ\s*(?:<[^>]+>\s*)*<a\b[^>]*google\.com/maps[^"]*"[^>]*>([^<]+)</a>',
        re.IGNORECASE,
    )
    # Hard-fail ONLY the postal formats distinctive enough to detect with zero
    # false positives:
    #   вҖў US state-abbrev + 5-digit ZIP вҖ” "Menlo Park CA 94025" / "City, NY 10001".
    #   вҖў UK postcode вҖ” "SW1A 1AA", "EC1V 9NR".
    # A bare 4вҖ“5 digit numeric postal ("28013 Madrid") is NOT machine-detectable
    # here: it is structurally identical to a house number ("2301 Sannai",
    # "9715 Estate Thomas", "Av. de Mayo 1370"), and street vocabulary is unbounded
    # and multilingual, so any numeric rule false-flags real house numbers. Those
    # rely on the address-format rule (Street В· Neighborhood, no city) + build-time
    # review. The earlier separator check (postal + comma + no middle-dot) still
    # catches comma-formatted numeric postals.
    _US_STATE_ZIP_RE = re.compile(r'\b[A-Z]{2}\s+\d{5}(?:-\d{4})?\b')
    _UK_POSTCODE_RE = re.compile(r'\b[A-Z]{1,2}\d[A-Z\d]?\s+\d[A-Z]{2}\b')
    addr_postal_hits: list[str] = []
    for m in _pin_addr_re.finditer(html):
        text = m.group(1).strip()
        if _US_STATE_ZIP_RE.search(text) or _UK_POSTCODE_RE.search(text):
            addr_postal_hits.append(text[:80])
    check(
        "Address anchors carry NO postal/ZIP code вҖ” guide addresses are "
        "`Street В· Neighborhood`, never a US state+ZIP or UK postcode "
        "(per Links.html рҹ“Қ Google Maps; postal codes banned 2026-05-19 вҖ” global, all sections)",
        not addr_postal_hits,
        (f"{len(addr_postal_hits)} address(es) with a postal code: "
         + "; ".join(f'"{t}"' for t in addr_postal_hits[:5]))
        if addr_postal_hits else "",
    )

    # REMOVED 2026-05-15: "English city name in address anchors" check deleted вҖ”
    # Links.html В§ 6 specifies {Street} В· {Postal Code} {City} with no requirement
    # to use the local-language city name. Check had no CORE RULES backing.

    # в”Җв”Җв”Җ рҹ“Қ "MAPS" LINK-TEXT DRIFT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Old format: рҹ“Қ Address <a href="...">Maps</a>  вҶҗ "Maps" word as the link
    # New format: рҹ“Қ <a href="...">Address</a>  вҶҗ address IS the link (postal codes banned 2026-05-19)
    # Catch any <a> whose visible text is exactly "Maps" (case-insensitive) вҖ” a sure
    # sign the old format survived a copy-paste (caught 2026-05-17).
    print("\nв”Җв”Җ рҹ“Қ 'Maps' LINK TEXT DRIFT в”Җв”Җ")
    _maps_linktext_re = re.compile(
        r'<a\b[^>]*>\s*Maps\s*</a>', re.IGNORECASE,
    )
    _maps_linktext_hits = _maps_linktext_re.findall(html)
    check(
        'рҹ“Қ address rows вҖ” link text must be the address itself, not the word "Maps" '
        '(old format: рҹ“Қ Address [Maps]; new format: рҹ“Қ [Address] as link вҖ” postal codes removed 2026-05-19; '
        'per Icon Order and Format.html row 9, updated 2026-05-17)',
        not _maps_linktext_hits,
        f'{len(_maps_linktext_hits)} "Maps" link-text instance(s) found вҖ” '
        'replace with the address text as the clickable link'
        if _maps_linktext_hits else '',
    )

    # в”Җв”Җв”Җ "MAP" / "MAPS" AS BARE VISIBLE TEXT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The word Map or Maps must never appear in guide visible text вҖ” the
    # address IS the clickable link; no separate label is ever used.
    # Catches drift like "Address [Maps]" or legacy "Directions вҶ’ Map".
    # Per Icon Order and Format.html row 7 (updated 2026-05-27).
    print('\nв”Җв”Җ \"Map\"/\"Maps\" as bare visible text вҖ” banned globally в”Җв”Җ')
    _maps_bare_stripped = re.sub(r'<script[^>]*>.*?</script>', '', html, flags=re.DOTALL | re.IGNORECASE)
    _maps_bare_stripped = re.sub(r'<style[^>]*>.*?</style>', '', _maps_bare_stripped, flags=re.DOTALL | re.IGNORECASE)
    _maps_bare_stripped = re.sub(r'<!--.*?-->', '', _maps_bare_stripped, flags=re.DOTALL)
    _maps_bare_word_re = re.compile(r'>([^<]*\bMaps?\b[^<]*)<', re.IGNORECASE)
    _maps_bare_hits: list[str] = []
    for _mbm in _maps_bare_word_re.finditer(_maps_bare_stripped):
        _snippet = _mbm.group(1).strip()
        if _snippet:
            _maps_bare_hits.append(_snippet[:60])
    check(
        'No "Map"/"Maps" in guide visible text вҖ” the address is the clickable link; '
        'the word Map/Maps never appears as guide text (per Icon Order and Format.html row 7)',
        not _maps_bare_hits,
        f'{len(_maps_bare_hits)} text node(s) containing "Map"/"Maps": '
        + '; '.join(f'\"{h}\"' for h in _maps_bare_hits[:5])
        if _maps_bare_hits else '',
    )

    # в”Җв”Җв”Җ "вҶ’ hotel" вҖ” BANNED EVERYWHERE EXCEPT DAY-CLOSER BANNERS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # "вҶ’ hotel" is valid ONLY inside .next and .arrive-first banners (end-of-day
    # return and train arrival closers). Anywhere else it is a template leak or
    # misplaced motion label вҖ” hard fail.
    print('\nв”Җв”Җ "вҶ’ hotel" outside day-closer banners вҖ” banned globally в”Җв”Җ')
    _arrow_hotel_stripped = re.sub(r'<script[^>]*>.*?</script>', '', html, flags=re.DOTALL | re.IGNORECASE)
    _arrow_hotel_stripped = re.sub(r'<style[^>]*>.*?</style>', '', _arrow_hotel_stripped, flags=re.DOTALL | re.IGNORECASE)
    _arrow_hotel_stripped = re.sub(r'<!--.*?-->', '', _arrow_hotel_stripped, flags=re.DOTALL)
    # Strip legitimate banner divs that are allowed to contain "вҶ’ hotel"
    _arrow_hotel_stripped = re.sub(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\b(?:next|arrive-first|leave-first)\b[^"]*"[^>]*>.*?</div>',
        '', _arrow_hotel_stripped, flags=re.DOTALL | re.IGNORECASE,
    )
    _arrow_hotel_hits: list[str] = []
    for _ahm in re.finditer(r'вҶ’\s*hotel\b', _arrow_hotel_stripped, re.IGNORECASE):
        _ctx_s = max(0, _ahm.start() - 50)
        _ctx_e = min(len(_arrow_hotel_stripped), _ahm.end() + 50)
        _ctx = RE_STRIP_TAGS.sub(' ', _arrow_hotel_stripped[_ctx_s:_ctx_e]).strip()
        _arrow_hotel_hits.append(RE_WS.sub(' ', _ctx)[:80])
    check(
        '"вҶ’ hotel" only in .next / .arrive-first / .leave-first banners вҖ” '
        'never in tour entries, stops, or any other content '
        '(Motion Rule вҖ” end-of-day closer and train arrival only)',
        not _arrow_hotel_hits,
        f'{len(_arrow_hotel_hits)} instance(s) of "вҶ’ hotel" outside permitted banners: '
        + '; '.join(f'\"вҖҰ{h}вҖҰ\"' for h in _arrow_hotel_hits[:3])
        if _arrow_hotel_hits else '',
    )

    # в”Җв”Җв”Җ "вҶ’ time from hotel" вҖ” GLOBAL TEMPLATE LEAKAGE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The рҹҡ¶/рҹҡ• row in Tours entry format uses "вҶ’ time from hotel" as a builder
    # instruction (Tours - Extra Section.html В§ 4). That phrase must never appear
    # anywhere in a shipped guide вҖ” guide-wide hard fail regardless of section.
    print('\nв”Җв”Җ "вҶ’ time from hotel" template leakage вҖ” guide-wide в”Җв”Җ')
    _tfh_global_stripped = re.sub(r'<script[^>]*>.*?</script>', '', html, flags=re.DOTALL | re.IGNORECASE)
    _tfh_global_stripped = re.sub(r'<style[^>]*>.*?</style>', '', _tfh_global_stripped, flags=re.DOTALL | re.IGNORECASE)
    _tfh_global_stripped = re.sub(r'<!--.*?-->', '', _tfh_global_stripped, flags=re.DOTALL)
    _tfh_global_hits: list[str] = []
    for _tfh_gm in re.finditer(r'time\s+from\s+hotel', _tfh_global_stripped, re.IGNORECASE):
        _ctx_s = max(0, _tfh_gm.start() - 40)
        _ctx_e = min(len(_tfh_global_stripped), _tfh_gm.end() + 40)
        _ctx = RE_STRIP_TAGS.sub(' ', _tfh_global_stripped[_ctx_s:_ctx_e]).strip()
        _tfh_global_hits.append(RE_WS.sub(' ', _ctx)[:80])
    check(
        '"вҶ’ time from hotel" must not appear anywhere in a shipped guide вҖ” '
        'replace with actual рҹҡ¶ N min В· рҹҡ• N min values '
        '(Tours - Extra Section.html В§ 4 builder instruction, not guide content)',
        not _tfh_global_hits,
        f'{len(_tfh_global_hits)} instance(s) of unresolved template text found guide-wide: '
        + '; '.join(f'\"вҖҰ{h}вҖҰ\"' for h in _tfh_global_hits[:3])
        if _tfh_global_hits else '',
    )

    # в”Җв”Җв”Җ GOOGLE MAPS URL вҖ” LOCKED PATTERN в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Locked pattern applies only to рҹ“Қ address rows вҖ” not to extras-sub review
    # links (cafГ©/restaurant names in Cappuccino/Restaurants Near Hotel/Downtown headings
    # legitimately use maps.google.com/?q=, google.com/maps?cid=, or place/ URLs).
    # Only scan Maps URLs that appear within 250 chars of a рҹ“Қ emoji.
    print("\nв”Җв”Җ GOOGLE MAPS URL вҖ” locked pattern в”Җв”Җ")
    LOCKED_MAPS_URL_RE = re.compile(
        r'^https://www\.google\.com/maps/search/\?api=1&query=',
        re.IGNORECASE,
    )
    _pin_maps_url_re = re.compile(
        r'href="([^"]*(?:google\.com/maps|maps\.google\.com|goo\.gl/maps)[^"]*)"',
        re.IGNORECASE,
    )
    maps_url_format_hits: list[str] = []
    for _pin_m in re.finditer(r'рҹ“Қ', html):
        _window = html[_pin_m.end():_pin_m.end() + 250]
        for _url_m in _pin_maps_url_re.finditer(_window):
            _url = _url_m.group(1)
            if not LOCKED_MAPS_URL_RE.match(_url):
                maps_url_format_hits.append(_url[:100])
    check(
        "Google Maps URLs match the locked pattern "
        "`https://www.google.com/maps/search/?api=1&query=...` "
        "(per Links.html рҹ“Қ Google Maps вҖ” URL pattern)",
        not maps_url_format_hits,
        (f"{len(maps_url_format_hits)} Maps URL(s) not matching the locked pattern: "
         + "; ".join(f'"{u}"' for u in maps_url_format_hits[:3]))
        if maps_url_format_hits else "",
    )

    # в”Җв”Җв”Җ рҹ“– ROW вҖ” VALID NON-EMPTY ANCHOR в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ рҹ“– ROW вҖ” VALID NON-EMPTY ANCHOR в”Җв”Җ")
    reading_no_anchor_hits: list[str] = []
    for m in re.finditer(r'рҹ“–', html):
        following = html[m.end():m.end() + 250]
        href_m = re.match(
            r'\s*<a\b[^>]*href="(https?://[^"]+)"',
            following, re.IGNORECASE,
        )
        if not href_m:
            ctx_start = max(0, m.start() - 20)
            ctx_end = min(len(html), m.end() + 80)
            ctx = RE_STRIP_TAGS.sub( '', html[ctx_start:ctx_end])
            ctx = RE_WS.sub(' ', ctx).strip()
            reading_no_anchor_hits.append(f"вҖҰ{ctx}вҖҰ")
    check(
        "Every рҹ“– is followed by a non-empty <a href> link "
        "(per Links.html рҹ“– Wikipedia вҖ” drop the row entirely if no article)",
        not reading_no_anchor_hits,
        (f"{len(reading_no_anchor_hits)} рҹ“– occurrence(s) without a valid http(s):// link: "
         + "; ".join(reading_no_anchor_hits[:3]))
        if reading_no_anchor_hits else "",
    )

    # в”Җв”Җв”Җ WIKIPEDIA PRESENCE PER STOP-BLOCK (HARD FAIL) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _sb_open_wiki_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"[^>]*>',
        re.IGNORECASE,
    )
    _sb_boundary_wiki_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\b(?:stop-block|day-block|extras-section)\b',
        re.IGNORECASE,
    )
    stop_blocks_no_wiki: list[str] = []
    _sb_wiki_positions = [m.start() for m in _sb_open_wiki_re.finditer(html)]
    for _wi, _wpos in enumerate(_sb_wiki_positions):
        _wnext = _sb_wiki_positions[_wi + 1] if _wi + 1 < len(_sb_wiki_positions) else len(html)
        _wbm = _sb_boundary_wiki_re.search(html, _wpos + 1)
        if _wbm and _wbm.start() < _wnext:
            _wnext = _wbm.start()
        _sb_inner = html[_wpos:_wnext]
        _has_wiki = 'рҹ“–' in _sb_inner
        # Dani 2026-06-17: the <!-- no-wikipedia: --> sentinel NO LONGER exempts
        # a stop. Every stop-block must carry a рҹ“– Wikipedia row or it hard-fails.
        if not _has_wiki:
            _sn = re.search(
                r'class\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>([^<]+)',
                _sb_inner, re.IGNORECASE,
            )
            _label = _sn.group(1).strip()[:60] if _sn else _sb_inner[:40]
            stop_blocks_no_wiki.append(_label)
    # Dani 2026-06-17: a guide may omit the рҹ“– row on AT MOST ONE stop, and that
    # single omission MUST carry a full written explanation in the guide log
    # (_build/verification_log.json) вҖ” an entry with platform "wikipedia-omit"
    # and a substantive (>= 40 char) notes/explanation field. Zero omissions is
    # always fine; two or more omissions hard-fail regardless of the log.
    _WIKI_OMIT_MIN_EXPLANATION = 40
    _wiki_omit_logged = 0
    try:
        _vlog_path = Path(filename).parent / "_build" / "verification_log.json"
        if _vlog_path.exists():
            _vlog = json.loads(_vlog_path.read_text(encoding='utf-8'))
            for _k, _e in (_vlog.get("entries", {}) or {}).items():
                if not isinstance(_e, dict):
                    continue
                _plat = str(_e.get("platform", "")).lower()
                _res = str(_e.get("result", "")).upper()
                if _plat in ("wikipedia-omit", "wikipedia_omit") or _res == "OMIT":
                    _expl = str(_e.get("notes", "") or _e.get("explanation", "")).strip()
                    if len(_expl) >= _WIKI_OMIT_MIN_EXPLANATION:
                        _wiki_omit_logged += 1
    except Exception as _wiki_e:
        warn(f"verification_log parse error: {_wiki_e}", "")
    _n_missing = len(stop_blocks_no_wiki)
    if _n_missing >= 2:
        _wiki_ok = False
        _wiki_msg = (f'{_n_missing} stop-block(s) missing рҹ“– row вҖ” a guide may omit Wikipedia '
                     f'on AT MOST ONE stop: '
                     + '; '.join(f'"{s}"' for s in stop_blocks_no_wiki[:6]))
    elif _n_missing == 1:
        _wiki_ok = _wiki_omit_logged >= 1
        _wiki_msg = ('' if _wiki_ok else
                     f'1 stop-block missing рҹ“– ("{stop_blocks_no_wiki[0]}") with no full '
                     f'explanation in the guide log вҖ” add a "wikipedia-omit" entry '
                     f'(notes >= {_WIKI_OMIT_MIN_EXPLANATION} chars) to '
                     f'_build/verification_log.json')
    else:
        _wiki_ok = True
        _wiki_msg = ''
    check(
        'Every stop-block carries a рҹ“– Wikipedia row вҖ” HARD FAIL; a guide may omit it on '
        'at most ONE stop, and only with a full explanation in the guide log '
        '(_build/verification_log.json, platform "wikipedia-omit") '
        '(Dani 2026-06-17: the no-wikipedia sentinel no longer exempts a stop)',
        _wiki_ok,
        _wiki_msg,
    )

    # в”Җв”Җв”Җ NO-WIKIPEDIA SENTINEL вҖ” NOT ABUSABLE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Links.html В§ 5: the рҹ“– row is omitted ONLY when no substantive English
    # Wikipedia article exists for the stop's specific subject. The
    # <!-- no-wikipedia: reason --> sentinel records that legitimate omission.
    # ABUSE pattern (Dani 2026-06-16): a dedicated English article DOES exist
    # but the sentinel was used to dodge the В§3 h1-name-match gate вҖ” the
    # reason text itself admits the article (e.g. Quebec City: 'English
    # Wikipedia article title is "Plains of Abraham" вҖ” French name used in
    # guide'). When an English article exists, the рҹ“– row must link it; a
    # sentinel that admits an existing/usable English article hard-fails.
    # Detector is text-only (no network): flag reasons whose own wording
    # concedes a usable EN article. "only a German/French/es article exists"
    # and "no вҖҰ article" stay legitimate (English-only rule, В§ 5).
    print("\nв”Җв”Җ NO-WIKIPEDIA SENTINEL вҖ” NOT ABUSABLE в”Җв”Җ")
    _wiki_abuse_re = re.compile(
        r'(english wikipedia article title is'
        r'|en article\s+"[^"]+"\s+exists'
        r'|wikipedia article title is\s+"'
        r'|closest is\s+\w)',
        re.IGNORECASE,
    )
    _wiki_abuse: list[str] = []
    for _wm in re.finditer(r'<!--\s*no-wikipedia:\s*(.*?)-->', html, re.DOTALL):
        _reason = RE_WS.sub(' ', _wm.group(1)).strip()
        if _wiki_abuse_re.search(_reason):
            _wiki_abuse.append(_reason[:100])
    check(
        'no-wikipedia sentinel is not abused вҖ” when the reason itself concedes a '
        'usable English Wikipedia article exists (name-mismatch, "closest is вҖҰ"), '
        'the рҹ“– row must link that article, not be suppressed '
        '(per Links.html В§ 5 вҖ” omit only when no substantive English article exists)',
        len(_wiki_abuse) == 0,
        (f'{len(_wiki_abuse)} no-wikipedia sentinel(s) that admit a usable English article вҖ” '
         f'link it instead: ' + '; '.join(f'"{s}"' for s in _wiki_abuse[:6]))
        if _wiki_abuse else '',
    )

    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # TITLE PAGE (city name, hotel, address, banner)
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    print("\nв”Җв”Җ TITLE PAGE: .title-city uppercase в”Җв”Җ")
    title_city_case_hits: list[str] = []
    city_text: str = ''                     # home city вҖ” populated below if .title-city found
    title_city_m = re.search(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btitle-city\b[^"]*"[^>]*>\s*([^<]+?)\s*</div>',
        html, re.IGNORECASE | re.DOTALL,
    )
    if title_city_m:
        city_text = title_city_m.group(1).strip()
        if city_text and city_text != city_text.upper():
            title_city_case_hits.append(city_text[:60])
    check(
        ".title-city is uppercase (per Hotel Banner.html В§1 Entry)",
        not title_city_case_hits,
        (f".title-city contains lowercase: \"{title_city_case_hits[0]}\" вҖ” "
         f"locked shape is `{{CITY (uppercase)}}`")
        if title_city_case_hits else "",
    )

    # в”Җв”Җв”Җ TITLE-CITY: no folder-convention hyphens in display name в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule: the .title-city value is the real city name, not a filesystem slug.
    # Folder names use hyphens as space replacements (e.g. Carmel-by-the-Sea/).
    # When a city name like "CARMEL BY THE SEA" is copied from the folder name it
    # ships with hyphens ("CARMEL-BY-THE-SEA") вҖ” wrong. Detection: after stripping
    # the " В· STATE/COUNTRY" suffix, the city portion must not contain a hyphen
    # that separates two letter-sequences (i.e. slug-style hyphens). Legitimate
    # hyphens within proper names are grammatically correct and are excluded via
    # an explicit allowlist below вҖ” only hyphens that come purely from the folder
    # naming convention are targeted.
    # Approach: flag when the city portion contains a hyphen AND the folder name
    # (derived from the guide file path) exactly matches the city portion lowercased
    # with spacesвҶ’hyphens вҖ” meaning the display name was copied verbatim from the
    # folder slug rather than written as a real city name. Allowlisted names are
    # skipped because their hyphens are grammatically correct (French/Spanish/etc.
    # compound names where the hyphen is part of the real spelling).
    _SLUG_HYPHEN_ALLOWLIST = {
        # French compound city names вҖ” hyphens are grammatically required
        'aix-en-provence',
        'bourg-en-bresse',
        'chalon-sur-saone',
        'clermont-ferrand',
        'fontainebleau',       # no hyphen, but keep slot for future
        'la-baule',
        'marne-la-vallee',
        'neuilly-sur-seine',
        'saint-malo',
        'saint-tropez',
        'villefranche-sur-mer',
        # Spanish compound city names
        'san-sebastian',
        'sitges',
        # Other legitimate hyphenated proper names
        'rio-de-janeiro',
        'stratford-upon-avon',
        'weston-super-mare',
    }
    print("\nв”Җв”Җ TITLE PAGE: .title-city must use real city name, not folder slug в”Җв”Җ")
    _folder_slug_hits: list[str] = []
    if city_text:
        # Strip optional " В· SUFFIX" to isolate the city portion
        _city_portion = city_text.split('В·')[0].strip()
        # Build the expected folder slug from the city portion
        _expected_slug = _city_portion.lower().replace(' ', '-')
        # Compare against the actual folder name (parent dir of the guide file)
        import os as _os
        _guide_folder = _os.path.basename(_os.path.dirname(_os.path.abspath(filename))).lower()
        # A match means the display name was copied verbatim from the folder slug,
        # unless it's in the allowlist of cities with grammatically correct hyphens
        if '-' in _city_portion and _expected_slug == _guide_folder and _guide_folder not in _SLUG_HYPHEN_ALLOWLIST:
            _folder_slug_hits.append(_city_portion)
    check(
        ".title-city uses the real city name, not the folder-convention slug "
        "(hyphens that replace spaces belong in file/folder paths, not display names вҖ” "
        "e.g. folder 'Carmel-by-the-Sea/' вҶ’ display 'CARMEL BY THE SEA', "
        "per Hotel Banner.html В§1)",
        not _folder_slug_hits,
        (f".title-city \"{_folder_slug_hits[0]}\" matches the folder slug exactly "
         f"вҖ” replace hyphens with spaces in the display name")
        if _folder_slug_hits else "",
    )

    # в”Җв”Җв”Җ рҹ“Қ MAPS LINK вҖ” HOME CITY IN DISPLAY TEXT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule (Hotel Banner.html В§1): the guide's home city must NOT appear in
    # a Maps link's visible text when the stop is in the home city вҖ” city
    # belongs in the URL query only. A *different* city in the link text is
    # fine (out-of-city stop: see Links.html).
    # Scope: only <a> tags that appear within 400 chars after a рҹ“Қ emoji.
    print("\nв”Җв”Җ рҹ“Қ Maps link: home city in display text в”Җв”Җ")
    _maps_city_hits: list[str] = []
    if city_text:
        _home_city_lc = city_text.lower()   # e.g. "pasadena"
        _maps_anchor_re = re.compile(
            r'<a\b[^>]*href="[^"]*(?:google\.com/maps|maps\.google\.com)[^"]*"[^>]*>(.*?)</a>',
            re.IGNORECASE | re.DOTALL,
        )
        # Street-name carve-out (2026-06-06, Miami build): a home-city token
        # that is immediately followed by a street suffix is part of a STREET
        # NAME (e.g. "3251 S Miami Ave" in Miami), not a city suffix. The rule
        # (Links.html В§6) bans the redundant CITY in the display text вҖ” it
        # does not rename real streets. Only a standalone home-city token
        # (not followed by a street suffix) is flagged.
        _street_suffix_re = (
            r'(?:ave(?:nue)?|st(?:reet)?|blvd|boulevard|rd|road|dr(?:ive)?|'
            r'way|wy|ln|lane|ct|court|hwy|highway|pkwy|parkway|ter(?:race)?|'
            r'pl(?:ace)?|sq(?:uare)?)\b'
        )
        _home_city_flag_re = re.compile(
            r'\b' + re.escape(_home_city_lc) + r'\b(?!\s+' + _street_suffix_re + r')',
        )
        for _pin_m in re.finditer(r'рҹ“Қ', html):
            _window = html[_pin_m.end():_pin_m.end() + 400]
            for _link_m in _maps_anchor_re.finditer(_window):
                _display = RE_STRIP_TAGS.sub('', _link_m.group(1)).strip()
                if _home_city_flag_re.search(_display.lower()):
                    _maps_city_hits.append(f'"{_display[:80]}"')
    check(
        f'рҹ“Қ Maps link display text must not contain the home city name '
        f'("{city_text.title() if city_text else "?"}" from .title-city) вҖ” '
        'city suffix belongs in the URL query, not the visible anchor text. '
        'A different city is allowed for out-of-city stops (per Links.html)',
        not _maps_city_hits,
        (f'{len(_maps_city_hits)} Maps link(s) showing home city in display text: '
         + '; '.join(_maps_city_hits[:3]))
        if _maps_city_hits else '',
    )

    # в”Җв”Җв”Җ рҹҡӨ CAR-FREE CITY RIDE GLYPH в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Cities with no road network use рҹҡӨ (water-taxi) instead of рҹҡ• in every
    # motion banner and from-hotel row (Motion Rule.html В§1; Icon Order В§2 8f).
    # Enforcement runs on the RAW html, then рҹҡӨ is normalised to рҹҡ• so every
    # downstream ride check (closer, RNH, Michelin check-D, Stations, ToursвҖҰ)
    # validates рҹҡӨ with the identical format/time/order rules as рҹҡ•.
    print("\nв”Җв”Җ рҹҡӨ CAR-FREE CITY RIDE GLYPH в”Җв”Җ")
    CAR_FREE_CITIES = {'venice', 'maldives', 'hydra', 'zermatt'}
    _city_lc = city_text.strip().lower()
    _car_free = _city_lc in CAR_FREE_CITIES
    # Getting Around may legitimately keep a рҹҡ• ride-app heading; exclude it.
    _ga_m = re.search(
        r'id\s*=\s*"getting-around".*?(?=id\s*=\s*"|</body>)',
        html, re.IGNORECASE | re.DOTALL,
    )
    _html_ex_ga = (html[:_ga_m.start()] + html[_ga_m.end():]) if _ga_m else html
    if _car_free:
        _stray_taxi = 'рҹҡ•' in _html_ex_ga
        check(
            f'рҹҡӨ Car-free city ("{city_text.title()}") вҖ” motion/from-hotel rows use рҹҡӨ '
            '(water-taxi), not рҹҡ• (per Motion Rule.html В§1 В· Icon Order В§2 8f)',
            not _stray_taxi,
            'рҹҡ• found outside Getting Around вҖ” replace with рҹҡӨ in every motion banner / from-hotel row'
            if _stray_taxi else '',
        )
        html = html.replace('рҹҡӨ', 'рҹҡ•')   # normalise: рҹҡӨ obeys all рҹҡ• ride checks
    else:
        check(
            'рҹҡӨ reserved for car-free cities вҖ” рҹҡӨ must not appear in a road-city guide '
            '(per Icon Order В§2 8f)',
            'рҹҡӨ' not in html,
            'рҹҡӨ found in a non-car-free guide вҖ” use рҹҡ• for rides'
            if 'рҹҡӨ' in html else '',
        )

    # в”Җв”Җв”Җ TITLE PAGE: direct-children list + ORDER в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ TITLE PAGE: direct-children list + order в”Җв”Җ")
    title_page_children_hits: list[str] = []
    # Defaults вҖ” overridden inside `if tp_open_m:` below.
    # Declared here so later checks (hotel suffix etc.) are
    # safe even when .title-page is absent from the guide.
    is_single_city = False
    tp_inner_for_children: str = ''
    tp_open_m = re.search(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btitle-page\b[^"]*"[^>]*>',
        html, re.IGNORECASE,
    )
    if tp_open_m:
        tp_inner_for_children, _ = _walk_balanced_div(html, tp_open_m.end())
        children_classes = re.findall(
            r'<div\s+class\s*=\s*"([^"]+)"',
            tp_inner_for_children, re.IGNORECASE,
        )
        # Hotel Banner.html В§1 вҖ” four items: title-city, title-hotel, title-address, title-country.
        expected = ['title-city', 'title-hotel', 'title-address', 'title-country']
        is_single_city = (children_classes == expected)
        if not is_single_city:
            title_page_children_hits.append(
                f"got {children_classes}, expected {expected} "
                f"(Hotel Banner.html В§1 Entry)"
            )
    check(
        ".title-page direct children must be exactly [title-city, title-hotel, title-address, title-country] "
        "(per Hotel Banner.html В§1 Entry)",
        not title_page_children_hits,
        title_page_children_hits[0] if title_page_children_hits else "",
    )

    # The check above only catches an EXTRA <div class="..."> sibling вҖ” a bare
    # text node, <p>, <span>, or an unclassed <div> inserted into .title-page
    # slips through undetected. Strip the 4 canonical divs out of the balanced
    # .title-page content and assert nothing but whitespace remains (Hotel
    # Banner.html В§2 вҖ” "no additional lines appear in the banner").
    # Added 2026-07-11, audit Gap 5.
    if tp_open_m and is_single_city:
        _tp_stripped = re.sub(
            r'<div\b[^>]*class\s*=\s*"[^"]*\btitle-(?:city|hotel|address|country)\b[^"]*"[^>]*>.*?</div>',
            '', tp_inner_for_children, flags=re.IGNORECASE | re.DOTALL,
        )
        _tp_leftover = RE_STRIP_TAGS.sub('', _tp_stripped).strip()
        check(
            "Title banner holds only the 4 canonical lines вҖ” no extra tagline/element "
            "(Hotel Banner.html В§2: city, hotel/rental name, address; no additional lines appear)",
            not _tp_leftover,
            f'unexpected content inside .title-page beyond city/hotel/address/country: "{_tp_leftover[:80]}"'
            if _tp_leftover else "",
        )

    # в”Җв”Җв”Җ TITLE-UPDATED STAMP: never hardcoded in guide HTML в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The "Updated Month Year" stamp is injected client-side by toolbar.js
    # (el.className = 'title-updated', reading data-updated="YYYY-MM" off the
    # toolbar-mount div) вҖ” it must never exist in the guide's static HTML
    # source. A hand-typed stamp is exactly what the JS-injection rule exists
    # to prevent, and previously nothing scanned the guide body for it (only
    # brain_check verified the CSS rule's existence). Hotel Banner.html В§2a.
    # Added 2026-07-11, audit Gap 3.
    print("\nв”Җв”Җ TITLE-UPDATED: never hardcoded in guide body в”Җв”Җ")
    _tu_hardcoded = bool(re.search(r'class\s*=\s*"[^"]*\btitle-updated\b[^"]*"', html, re.IGNORECASE))
    check(
        'The "Updated" stamp is JS-injected only вҖ” .title-updated must never appear '
        'hardcoded in guide HTML (Hotel Banner.html В§2a)',
        not _tu_hardcoded,
        'Found a hardcoded class="вҖҰtitle-updatedвҖҰ" element in the guide body вҖ” remove it; '
        'the stamp is injected by toolbar.js from data-updated="YYYY-MM" on the toolbar-mount div'
        if _tu_hardcoded else "",
    )

    # в”Җв”Җв”Җ TITLE COUNTRY: must be present and non-empty в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Hotel Banner.html В§1 вҖ” .title-country (country name, right-aligned)
    # is required on every guide. Hard-fail if absent or blank.
    print("\nв”Җв”Җ TITLE PAGE: .title-country present and non-empty в”Җв”Җ")
    _tc_m = re.search(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btitle-country\b[^"]*"[^>]*>\s*([^<]*?)\s*</div>',
        html, re.IGNORECASE | re.DOTALL,
    )
    _tc_text = _tc_m.group(1).strip() if _tc_m else ''
    check(
        ".title-country must be present and non-empty вҖ” country name required on every guide "
        "(Hotel Banner.html В§1 Entry вҖ” added 2026-06-15)",
        bool(_tc_text),
        ".title-country div missing or empty вҖ” add country name to the title banner"
        if not _tc_text else "",
    )

    # Hotel Banner.html В§1 вҖ” the country label is the country's FULL name only:
    # no abbreviation, no country code, and no subdivision below the national
    # level (state / province / territory / region). A subdivision shows up as a
    # comma or middle-dot separator; an abbreviation/code is a short all-caps
    # token (e.g. two-to-four letters, dots optional). Empty is handled by the
    # presence check above, so this check passes when the field is blank.
    print("\nв”Җв”Җ TITLE PAGE: .title-country is a full country name (no abbreviation or subdivision) в”Җв”Җ")
    _tc_norm = _tc_text.replace('.', '').replace(' ', '')
    _tc_has_subdivision = (',' in _tc_text) or ('В·' in _tc_text)
    _tc_is_abbreviation = bool(_tc_norm) and _tc_norm.isalpha() and _tc_norm.isupper() and len(_tc_norm) <= 4
    # Spelled-out subdivision detection: US states, Canadian provinces, and
    # other common subdivisions that are NOT sovereign country names.
    _SUBDIVISION_NAMES = {
        # US states (all 50 + DC)
        "alabama", "alaska", "arizona", "arkansas", "california", "colorado",
        "connecticut", "delaware", "florida", "hawaii", "idaho",
        "illinois", "indiana", "iowa", "kansas", "kentucky", "louisiana",
        "maine", "maryland", "massachusetts", "michigan", "minnesota",
        "mississippi", "missouri", "montana", "nebraska", "nevada",
        "new hampshire", "new jersey", "new mexico", "new york",
        "north carolina", "north dakota", "ohio", "oklahoma", "oregon",
        "pennsylvania", "rhode island", "south carolina", "south dakota",
        "tennessee", "texas", "utah", "vermont", "virginia",
        "washington", "west virginia", "wisconsin", "wyoming",
        "district of columbia",
        # Canadian provinces
        "ontario", "quebec", "british columbia", "alberta", "manitoba",
        "saskatchewan", "nova scotia", "new brunswick",
        "prince edward island", "newfoundland and labrador",
        # Other common subdivisions
        "bavaria", "catalonia", "andalusia", "tuscany", "lombardy",
        "provence", "normandy", "brittany", "scotland", "wales",
        "northern ireland", "england",
    }
    # Georgia is both a US state and a country вҖ” exclude from subdivision list.
    # "Washington" = also a common city name used alone; only flag it if the full
    # value is exactly "Washington" (not "Washington, D.C." which is caught by comma).
    _tc_is_subdivision = _tc_text.lower().strip() in _SUBDIVISION_NAMES
    _tc_bad = _tc_has_subdivision or _tc_is_abbreviation or _tc_is_subdivision
    check(
        ".title-country must be the country's full name вҖ” no abbreviation, country code, "
        "or subdivision (state/province/region) (Hotel Banner.html В§1 Entry вҖ” added 2026-06-27)",
        (not _tc_text) or (not _tc_bad),
        (f'.title-country "{_tc_text}" is not a full country name вҖ” '
         "write the country's full name with no abbreviation and no state/province/region"
         + (f' ("{_tc_text}" is a subdivision, not a country)' if _tc_is_subdivision else ''))
        if _tc_bad else "",
    )

    # в”Җв”Җв”Җ рҹ“Қ ADDRESS: destination's own country never appears in address text в”Җв”Җ
    # Links.html В§6: country included in a рҹ“Қ address ONLY when the address is
    # in a different country from the destination. The existing "address anchors
    # don't leak country" check above only reads the LAST comma-separated segment
    # (COUNTRY_NAMES, any country) вҖ” a country name reachable via the locked
    # ` В· ` separator slipped through. This check is guide-specific: does THIS
    # guide's own .title-country value appear as the LAST ` В· `-separated
    # segment (a trailing country descriptor, matching the shape the sibling
    # comma-based check above already looks for)? Reuses _pin_addr_re (compiled
    # above for the postal-code scan). Added 2026-07-11, audit Gap 4.
    #
    # BUG FIX 2026-07-11 (same day, caught by fleet-wide regression run): the
    # first version substring-matched the country name ANYWHERE in the address,
    # which false-fired on venue/street names that legitimately contain the
    # country word вҖ” "Bank of China" (Beijing), "Qatar Foundation" (Doha),
    # "Canada Place" (Vancouver, a real landmark named after the country),
    # "rue de France" (Nice, a real street name), "Petite France" (Strasbourg,
    # a real historic district name), "Estonia pst" (Tallinn, "Estonia Avenue").
    # Tightened to an exact match on the final middle-dot segment only вҖ” this
    # still catches the genuine violation shape (Pokhara: "Rupa Lake В· Kaski
    # District В· Nepal", a real trailing country leak) while dropping all 8
    # false positives found across the fleet.
    print("\nв”Җв”Җ рҹ“Қ ADDRESS: destination's own country not in address text в”Җв”Җ")
    _addr_own_country_hits: list[str] = []
    if _tc_text and not _tc_bad:
        _own_country_re = re.compile(r'^\s*' + re.escape(_tc_text) + r'\s*$', re.IGNORECASE)
        for _m in _pin_addr_re.finditer(html):
            _addr_text = _m.group(1).strip()
            _last_seg = _addr_text.split('В·')[-1]
            if _own_country_re.match(_last_seg):
                _addr_own_country_hits.append(_addr_text[:80])
    check(
        f'рҹ“Қ address text never contains the destination\'s own country '
        f'(per Links.html В§6 вҖ” country shown only when the address is in a '
        f'different country from the destination)',
        not _addr_own_country_hits,
        (f'{len(_addr_own_country_hits)} address(es) containing the guide\'s own '
         f'country "{_tc_text}": ' + '; '.join(f'"{t}"' for t in _addr_own_country_hits[:5]))
        if _addr_own_country_hits else "",
    )

    # в”Җв”Җв”Җ TITLE PAGE COLOR DRIFT: no local style override allowed в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Canonical colors (title-page redesigned 2026-06-20 to light-bg/dark-text
    # matching the site header вҖ” supersedes the 2026-06-15 dark-bg/light-text palette):
    #   .title-city    вҶ’ #3d3a32
    #   .title-hotel   вҶ’ #3d3a32
    #   .title-country вҶ’ #3d3a32
    #   .title-address вҶ’ #3d3a32
    # If a local <style> block overrides any of these with a different value,
    # the guide will look wrong. Hard-fail.
    print("\nв”Җв”Җ TITLE PAGE: no local color override on title-city / title-hotel / title-address / title-country в”Җв”Җ")
    _local_style_blocks = re.findall(r'<style[^>]*>(.*?)</style>', html, re.IGNORECASE | re.DOTALL)
    _color_override_hits: list[str] = []
    _TITLE_COLOR_RE = re.compile(
        r'(\.title-(?:city|hotel|address|country)\s*\{[^}]*\bcolor\s*:[^;}]+)',
        re.IGNORECASE,
    )
    for _block in _local_style_blocks:
        for _hit in _TITLE_COLOR_RE.finditer(_block):
            _rule = _hit.group(1).strip()
            # Allow only the canonical values
            _val = re.search(r'color\s*:\s*([^;]+)', _rule, re.IGNORECASE)
            if _val:
                _v = _val.group(1).strip().lower().replace(' ', '')
                _canonical = {'#3d3a32', '#6a6660'}
                if _v not in _canonical:
                    _color_override_hits.append(_rule[:120])
    check(
        "No local <style> block may override .title-city / .title-hotel / .title-address / .title-country color "
        "вҖ” canonical palette defined in guide-style.css (added 2026-06-15). Remove local override.",
        len(_color_override_hits) == 0,
        "Local color override detected: " + "; ".join(_color_override_hits) if _color_override_hits else "",
    )

    # в”Җв”Җв”Җ TITLE HOTEL: banned trailing words (Home, House, Apartment, Airbnb) в”Җв”Җ
    # Hotel Banner.html В§1 вҖ” .title-hotel is the property name only;
    # generic accommodation-type words at the end are banned (e.g. "Sunriver Rental Home").
    _TITLE_HOTEL_BANNED_SUFFIX_RE = re.compile(
        r'\b(?:Home|House|Apartment|Airbnb|Condo|Villa|Cottage|Cabin|Rental\s+Home)\s*$',
        re.IGNORECASE,
    )
    _th_suffix_fails: list[str] = []
    for _thm in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"title-hotel"[^>]*>\s*([^<]+?)\s*</div>',
        html, re.IGNORECASE,
    ):
        _th_text = _thm.group(1).strip()
        if _TITLE_HOTEL_BANNED_SUFFIX_RE.search(_th_text):
            _th_suffix_fails.append(
                f'"{_th_text}" вҖ” remove generic accommodation type from end '
                f'(e.g. "Rental Home" вҶ’ "Rental"; Hotel Banner.html В§1)'
            )
    check(
        ".title-hotel must not end with a generic accommodation word "
        "(Home / House / Apartment / Airbnb / Rental Home вҖ” Hotel Banner.html В§1)",
        not _th_suffix_fails,
        _th_suffix_fails[0] if _th_suffix_fails else "",
    )

    # в”Җв”Җв”Җ TITLE CARD: every .title-address Maps link + address format в”Җв”Җ
    print("\nв”Җв”Җ TITLE CARD: .title-address Maps links + format в”Җв”Җ")
    _ta_maps_fails: list[str] = []
    for _tam in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"title-address"[^>]*>(.*?)</div>',
        html, re.IGNORECASE | re.DOTALL,
    ):
        _ta_inner = _tam.group(1)
        _ta_hrefs = re.findall(r'href="([^"]+)"', _ta_inner, re.IGNORECASE)
        _ta_plain = RE_STRIP_TAGS.sub('', _ta_inner).strip()
        # Maps link check.
        if not _ta_hrefs:
            _ta_maps_fails.append(
                f'"{_ta_plain[:60]}" вҖ” no <a> found; wrap address in a Google Maps link'
            )
        elif not any('google.com/maps' in u.lower() for u in _ta_hrefs):
            _ta_maps_fails.append(
                f'"{_ta_plain[:60]}" вҖ” links to {_ta_hrefs[0][:60]}; must be google.com/maps'
            )
        # Address-format separator check RETIRED 2026-05-20: the home-city hotel
        # address is now street + neighborhood only вҖ” no city (per Links.html В§ 6 /
        # Hotel Banner.html В§ 1). A ' В· ' appears only when the address is in a
        # different city, or carries the US state code вҖ” both optional. Requiring
        # ' В· ' here contradicted the new address rule; the no-postal and
        # no-home-city checks enforce the current rule instead.
    check(
        "Title card: every .title-address is a Google Maps link "
        "(Hotel Banner.html В§1 Entry / В§2 Multi-city guides)",
        not _ta_maps_fails,
        (f'{len(_ta_maps_fails)} address div(s) missing Maps link: '
         + '; '.join(_ta_maps_fails[:3]))
        if _ta_maps_fails else '',
    )
    # (Title-card "Street В· City" separator check retired 2026-05-20 вҖ” see note
    #  above. Street-only home-city addresses are valid under the no-city rule.)

    # в”Җв”Җв”Җ TITLE CARD: .title-address must be a complete address в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Complete address = digit present (has street number) OR middle-dot present
    # (street name В· neighborhood вҖ” valid when hotel has no published street number).
    # Bare street name with no digit and no В· is incomplete (e.g. "Av. Marginal").
    # Added 2026-05-23: caught by Cascais guide (title-address was "Av. Marginal" only).
    # Updated 2026-06-15: allow no-number addresses per Hotel Banner.html В§1 revision вҖ”
    # some hotels have no published street number; street + neighborhood (В· present) is valid.
    _ta_incomplete: list[str] = []
    for _tam2 in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"title-address"[^>]*>(.*?)</div>',
        html, re.IGNORECASE | re.DOTALL,
    ):
        _ta2_plain = RE_STRIP_TAGS.sub('', _tam2.group(1)).strip()
        if _ta2_plain and not re.search(r'\d', _ta2_plain) and 'В·' not in _ta2_plain:
            _ta_incomplete.append(f'"{_ta2_plain[:60]}" вҖ” bare street name only; address is incomplete')
    check(
        'Title card: .title-address must be a complete address вҖ” digit (street number) OR '
        'middle-dot separator (street В· neighborhood) required; bare street name alone is '
        'incomplete (per Hotel Banner.html В§1; caught 2026-05-23 Cascais "Av. Marginal" failure)',
        not _ta_incomplete,
        (f'{len(_ta_incomplete)} address(es) incomplete: '
         + '; '.join(_ta_incomplete[:3]))
        if _ta_incomplete else '',
    )

    # в”Җв”Җв”Җ TITLE CARD: .title-hotel bold / .title-address plain enforcement в”Җв”Җв”Җв”Җв”Җв”Җ
    # Hotel Banner.html В§1 вҖ” .title-hotel is bold (set by guide-style.css); .title-address
    # is plain weight and smaller. Checks prevent inline overrides or markup that
    # would flip the visual hierarchy back to the pre-2026-06-01 broken state.
    print("\nв”Җв”Җ TITLE CARD: hotel name bold / address plain в”Җв”Җ")

    # (a) .title-address must not contain <strong> or <b> вҖ” making it bold overrides CSS.
    _ta_bold_fails: list[str] = []
    for _tam3 in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"title-address"[^>]*>(.*?)</div>',
        html, re.IGNORECASE | re.DOTALL,
    ):
        _ta3_inner = _tam3.group(1)
        if re.search(r'<(strong|b)\b', _ta3_inner, re.IGNORECASE):
            _ta_bold_fails.append(
                f'"{RE_STRIP_TAGS.sub("", _ta3_inner).strip()[:60]}" '
                f'вҖ” <strong>/<b> inside .title-address makes address bold; '
                f'address must be plain weight (Hotel Banner.html В§1)'
            )
        if re.search(r'font-weight\s*:\s*(bold|[5-9]\d\d)', _ta3_inner, re.IGNORECASE):
            _ta_bold_fails.append(
                f'"{RE_STRIP_TAGS.sub("", _ta3_inner).strip()[:60]}" '
                f'вҖ” inline font-weight bold on .title-address; '
                f'address must be plain weight (Hotel Banner.html В§1)'
            )
    check(
        ".title-address must be plain weight вҖ” no <strong>, <b>, or inline bold style "
        "(Hotel Banner.html В§1: address is subordinate to hotel name)",
        not _ta_bold_fails,
        _ta_bold_fails[0] if _ta_bold_fails else "",
    )

    # (a2) No inline font-size on .title-hotel / .title-address / .title-country.
    # All three are locked at 14px in guide-style.css (Hotel Banner.html В§2a).
    # An inline style override would silently break the locked standard.
    _fs_override_fails: list[str] = []
    for _cls in ('title-hotel', 'title-address', 'title-country'):
        for _m in re.finditer(
            r'<div\b[^>]*\bclass\s*=\s*"' + _cls + r'"[^>]*style\s*=\s*"([^"]*)"[^>]*>',
            html, re.IGNORECASE,
        ):
            if re.search(r'font-size\s*:', _m.group(1), re.IGNORECASE):
                _fs_override_fails.append(
                    f'.{_cls} has inline font-size override: style="{_m.group(1)[:80]}" '
                    f'вҖ” font sizes are locked in guide-style.css (Hotel Banner.html В§2a)'
                )
    check(
        "No inline font-size on .title-hotel / .title-address / .title-country "
        "вҖ” all three locked at 14px in guide-style.css (Hotel Banner.html В§2a, approved 2026-06-26)",
        not _fs_override_fails,
        _fs_override_fails[0] if _fs_override_fails else "",
    )

    # (b) .title-hotel must not have an inline style stripping its bold.
    _th_unbold_fails: list[str] = []
    for _thm2 in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"title-hotel"[^>]*style\s*=\s*"([^"]*)"[^>]*>',
        html, re.IGNORECASE,
    ):
        _th_style = _thm2.group(1)
        if re.search(r'font-weight\s*:\s*(normal|[1-3]\d\d|400)', _th_style, re.IGNORECASE):
            _th_unbold_fails.append(
                f'inline style removes bold from .title-hotel: style="{_th_style[:80]}" '
                f'вҖ” hotel name must be bold (Hotel Banner.html В§1)'
            )
    check(
        ".title-hotel must not have an inline style that strips bold "
        "(Hotel Banner.html В§1: hotel name is the primary label, styled bold by guide-style.css)",
        not _th_unbold_fails,
        _th_unbold_fails[0] if _th_unbold_fails else "",
    )

    # (c) .title-hotel must not contain a link вҖ” color-drift guard.
    # Hotel Banner.html В§1 вҖ” only .title-address is the Google Maps link; the
    # hotel/rental name is plain text. guide-style.css has no color rule for
    # ".title-hotel a", so wrapping the hotel name in a link falls through to
    # the global canonical link blue instead of matching .title-address.
    # Caught 2026-07-12: Bhutan's "COMO Uma Paro" rendered blue against a dark
    # "Paro Valley В· Bhutan" вҖ” the only guide (1/220) with this wrapper.
    _th_link_fails: list[str] = []
    for _thl in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"title-hotel"[^>]*>(.*?)</div>',
        html, re.IGNORECASE | re.DOTALL,
    ):
        _th_inner = _thl.group(1)
        if re.search(r'<a\b', _th_inner, re.IGNORECASE):
            _th_link_fails.append(
                f'"{RE_STRIP_TAGS.sub("", _th_inner).strip()[:60]}" '
                f'вҖ” .title-hotel wraps an <a>, which has no dedicated CSS color '
                f'rule and falls through to the global link blue instead of '
                f'matching .title-address (Hotel Banner.html В§1)'
            )
    check(
        ".title-hotel must not contain a link вҖ” hotel name is plain text; "
        "only .title-address is the Maps link. An unstyled <a> falls through "
        "to the global link blue, rendering a different color than the "
        "address beside it (Hotel Banner.html В§1)",
        not _th_link_fails,
        _th_link_fails[0] if _th_link_fails else "",
    )

    # в”Җв”Җв”Җ TITLE CARD SCOPE вҖ” hotel is name + address only в”Җв”Җв”Җв”Җв”Җв”Җ
    # tp_inner_for_children holds the balanced .title-page content from _walk_balanced_div
    # above вҖ” use it directly instead of a fragile lookahead regex.
    if tp_open_m and tp_inner_for_children:
        tp_inner = tp_inner_for_children
        # Strip .title-address href contents (Google Maps URL legitimately
        # contains digits, commas, and sometimes month-like strings in
        # place-slugs) вҖ” only the visible text should be scanned.
        tp_scan = re.sub(r'<a\b[^>]*>', '', tp_inner, flags=re.IGNORECASE)
        tp_scan = re.sub(r'</a>', '', tp_scan, flags=re.IGNORECASE)
        tp_scan = re.sub(r'href\s*=\s*"[^"]*"', '', tp_scan, flags=re.IGNORECASE)

        tp_violations: list[str] = []
        # Currency symbols and price tokens.
        if re.search(r'[\$вӮ¬ВЈВҘ]\s?\d', tp_scan):
            tp_violations.append("currency symbol near a digit (price leak)")
        if re.search(r'\b(USD|EUR|GBP|JPY)\b', tp_scan):
            tp_violations.append("currency code (USD/EUR/GBP/JPY)")
        if re.search(r'\bper\s+night\b', tp_scan, re.IGNORECASE):
            tp_violations.append('"per night" вҖ” price cadence')
        if re.search(r'\b(from\s+\$|starting\s+at\s+\$|rate[s]?\s*:)', tp_scan, re.IGNORECASE):
            tp_violations.append('"from $" / "starting at" / "rates:" вҖ” price phrasing')
        # Date tokens.
        if re.search(r'\b(check[-\s]?in|check[-\s]?out|arrival|departure|arriving|departing)\b', tp_scan, re.IGNORECASE):
            tp_violations.append("check-in/check-out/arrival/departure word")
        if re.search(r'\b(20\d{2}[-/]\d{1,2}[-/]\d{1,2})\b', tp_scan):
            tp_violations.append("ISO / numeric date (YYYY-MM-DD)")
        if re.search(r'\b(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Sept|Oct|Nov|Dec)(?:uary|ruary|ch|il|e|y|ust|tember|ober|ember)?\s+\d{1,2}\b', tp_scan):
            tp_violations.append("month-name + day (arrival date leak)")
        if re.search(r'\b\d{1,2}\s+(nights?|days?)\b', tp_scan, re.IGNORECASE):
            tp_violations.append('"N nights"/"N days" вҖ” stay-length leak')
        # Time tokens (no :NN timestamps inside the title card).
        if re.search(r'\b\d{1,2}:\d{2}\s*(am|pm)?\b', tp_scan, re.IGNORECASE):
            tp_violations.append("clock time вҖ” arrival/check-in time leak")
        # Booking / loyalty / room admin.
        if re.search(r'\b(confirmation|reservation|booking\s+ref|folio)\s*(number|code|#|:)?\b', tp_scan, re.IGNORECASE):
            tp_violations.append("confirmation/reservation code")
        if re.search(r'\b(loyalty|platinum|gold|silver|elite|bonvoy|honors|gha|genius)\b', tp_scan, re.IGNORECASE):
            tp_violations.append("loyalty status / tier word")
        if re.search(r'\b(king|queen|suite|double|twin|deluxe|superior|standard)\s+(room|bed)\b', tp_scan, re.IGNORECASE):
            tp_violations.append("room-type / bed-config word")
        if re.search(r'\b(breakfast|wi-?fi|parking|amenit)\b', tp_scan, re.IGNORECASE):
            tp_violations.append("amenity word (breakfast / wifi / parking / amenity)")
        # Phone / email вҖ” research-notes-only info (Rules for Claude.html В§7).
        if re.search(RE_EMAIL_PATTERN, tp_scan):
            tp_violations.append("email address")
        if re.search(RE_PHONE_PATTERN, tp_scan):
            tp_violations.append("phone number")

        check(
            "Title card scope вҖ” hotel is name + address only (В§Hotel Naming вҶ’ Out of scope)",
            len(tp_violations) == 0,
            "title card contains out-of-scope hotel info: " + "; ".join(tp_violations)
            if tp_violations else ""
        )

    # в”Җв”Җв”Җ HOTELS & RENTALS вҖ” VALIDATOR-COVERAGE BACKFILL (2026-04-27) в”Җ
    print("\nв”Җв”Җ HOTELS & RENTALS в”Җв”Җ")

    hr_placeholder_hits: list[str] = []
    # Banned placeholder patterns inside .title-hotel and .title-address.
    # Matched on plain text after HTML tag strip.
    _hr_placeholder_patterns = [
        (r'\{[^}]+\}', 'curly-brace placeholder ({...})'),
        (r'\[[^\]]+\]', 'square-bracket placeholder ([...])'),
        (r'\bTBD\b', 'TBD'),
        (r'\bTODO\b', 'TODO'),
        (r'\bFIXME\b', 'FIXME'),
        (r'\?{2,}', '?? / ??? (multi-question-mark placeholder)'),
    ]

    for _surface_class in ('title-hotel', 'title-address'):
        for _m in re.finditer(
            rf'<[^>]*\bclass\s*=\s*"[^"]*\b{_surface_class}\b[^"]*"[^>]*>(.*?)</',
            html, re.IGNORECASE | re.DOTALL,
        ):
            _content = _m.group(1)
            # Strip HTML tags (anchor wraps on title-address are valid;
            # we want the visible text content, not the href URL).
            _plain = RE_STRIP_TAGS.sub( '', _content).strip()
            for _pat, _label in _hr_placeholder_patterns:
                _hits = re.findall(_pat, _plain, re.IGNORECASE)
                for _hit in _hits:
                    hr_placeholder_hits.append(
                        f'.{_surface_class}: {_label} "{_hit}" in "{_plain[:60]}"'
                    )

    check(
        'Title-page hotel name + address contain no placeholder tokens '
        '({...} / [...] / TBD / TODO / FIXME / ???) вҖ” per Rules for Claude.html DriftyCat (no fabrication) '
        '(adjacent to On Demand - Don\'t Ship in Guide/Hotels & Rentals - On Demand.html Hotels вҖ” title-page hotel name + address)',
        not hr_placeholder_hits,
        (f"{len(hr_placeholder_hits)} placeholder hit(s) on title page: "
         + "; ".join(hr_placeholder_hits[:3]))
        if hr_placeholder_hits else "",
    )

    # в”Җв”Җв”Җ GLOBAL BODY вҖ” BARE PLACEHOLDER TOKENS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rules for Claude.html DriftyCat: "No placeholders вҖ” TBD/TODO/fill in later
    # = fabrication." The title-page check above catches hotel/address surfaces;
    # this scan catches bare tokens anywhere in visible body text (stop names,
    # descriptions, motion rows, extras entries, annotations).
    # "fill in later" / "tour TBD" have no matcher elsewhere (B1 audit fix 2026-06-19).
    # Scoped to rendered text (tags stripped); excludes href/src attribute values
    # so URL tokens ("?todo=вҖҰ") don't false-positive.
    print("\nв”Җв”Җ GLOBAL BODY вҖ” bare placeholder tokens в”Җв”Җ")
    _body_m = re.search(r'<body\b[^>]*>(.*)</body>', html, re.IGNORECASE | re.DOTALL)
    _body_plain = RE_STRIP_TAGS.sub(' ', _body_m.group(1) if _body_m else html)
    _BARE_PLACEHOLDER_PATS = [
        (r'\bTBD\b',           'TBD'),
        (r'\bTODO\b',          'TODO'),
        (r'\bFIXME\b',         'FIXME'),
        (r'fill[\s\-]?in\s+later', 'fill in later'),
        (r'\btour\s+TBD\b',    'tour TBD'),
    ]
    _body_placeholder_hits: list[str] = []
    for _bpat, _blabel in _BARE_PLACEHOLDER_PATS:
        for _bm in re.finditer(_bpat, _body_plain, re.IGNORECASE):
            _snip = _body_plain[max(0, _bm.start()-30):_bm.end()+30].strip()
            _body_placeholder_hits.append(f'{_blabel}: "вҖҰ{_snip}вҖҰ"')
    check(
        'Guide body contains no bare placeholder tokens (TBD / TODO / FIXME / '
        '"fill in later" / "tour TBD") вҖ” per Rules for Claude.html DriftyCat '
        '(no fabrication / no placeholders)',
        not _body_placeholder_hits,
        f"{len(_body_placeholder_hits)} placeholder token(s) in body: "
        + "; ".join(_body_placeholder_hits[:5])
        if _body_placeholder_hits else '',
    )

    # в”Җв”Җв”Җ HOTEL NAMING PROTOCOL в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    hotel_title_m = re.search(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btitle-hotel\b[^"]*"[^>]*>(.*?)</div>',
        html,
        re.IGNORECASE,
    )
    hotel_protocol_bad = []
    if hotel_title_m:
        hotel_name = hotel_title_m.group(1).strip()
        # If the hotel name is short (1вҖ“2 tokens like "hotel") skip вҖ” can't
        # meaningfully distinguish from the generic word.
        if len(hotel_name.split()) >= 2 and hotel_name.lower() != "hotel":
            banner_re = re.compile(
                r'<div\s+class\s*=\s*"(next|next-tram|next-metro|hotel-first|arrive-first|depart)"[^>]*>\s*(.*?)\s*</div>',
                re.IGNORECASE | re.DOTALL,
            )
            for bm in banner_re.finditer(html):
                banner_class = bm.group(1)
                banner_body = bm.group(2)
                if hotel_name in banner_body:
                    snip = banner_body[:80].replace("\n", " ")
                    hotel_protocol_bad.append(f'.{banner_class}: "{snip}вҖҰ"')
    check(
        "Hotel naming protocol вҖ” only .title-hotel carries the full name; banners use generic 'hotel'",
        len(hotel_protocol_bad) == 0,
        f"{len(hotel_protocol_bad)} banner(s) repeat the hotel name instead of using 'hotel': "
        + "; ".join(hotel_protocol_bad[:3])
        if hotel_protocol_bad else ""
    )

    # в”Җв”Җ HOTEL NAME CHECK вҖ” PERMANENTLY REMOVED 2026-05-26 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # DO NOT RE-ADD. Surfacing .title-hotel names for manual confirmation
    # adds no automated value and produces noise on every run. Removed at
    # Dani's explicit request. If you are considering re-adding any form of
    # hotel-name warning or confirmation prompt, stop вҖ” the answer is no.
    # See Brain/Reference/decisions.md В§ 2026-05-26 for the removal record.
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    # в”Җв”Җв”Җ TRIP OVERVIEW в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # TRIP OVERVIEW (overview section, day cards, extras links)
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    print("\nв”Җв”Җ TRIP OVERVIEW в”Җв”Җ")

    # 4 locked day-overview labels per Stops Structure.html + Trip Overview.html.
    # Train Day variant: `рҹҡҶ Train Day вҖ” {City}` carries the destination city as a dash
    # suffix so the destination is visible at overview level. Per Dani 2026-04-26: train days
    # come last in the itinerary; the city suffix is the at-a-glance differentiator. The
    # plain `рҹҡҶ Train Day` form (no suffix) also remains acceptable for back-compat with
    # shipped guides.
    overview_open_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\boverview-section\b[^"]*"[^>]*>',
        re.IGNORECASE,
    )
    overview_m = overview_open_re.search(html)
    check(
        'Trip Overview вҖ” .overview-section wrapper present',
        bool(overview_m),
        'Missing <div class="overview-section"> вҖ” guide has no Trip Overview section'
        if not overview_m else "",
    )

    # Pre-bind so later checks (e.g. the Day Trips block ~L16026) never hit an
    # UnboundLocalError when a guide has no .overview-section. A missing section
    # is already reported as a hard FAIL above; downstream code must degrade to a
    # clean result, not crash mid-run with an opaque traceback. (Lane4-01 fix.)
    overview_inner = ""
    overview_days: list = []

    if overview_m:
        overview_inner, _ = _walk_balanced_div(html, overview_m.end())

        # в”Җв”Җ overview-title must be a <div class="overview-title">, not a heading в”Җв”Җ
        # toolbar.js injects вҖ№/вҖә arrows by querying `.overview-title`; using <h2>
        # or any heading element breaks arrow injection and CSS styling.
        # Per Trip Overview.html В§1 вҖ” locked 2026-06-01.
        _overview_title_m = re.search(
            r'<(?P<tag>\w+)\b[^>]*\bclass\s*=\s*"[^"]*\boverview-title\b[^"]*"',
            overview_inner, re.IGNORECASE,
        )
        _overview_title_tag = _overview_title_m.group('tag').lower() if _overview_title_m else None
        _overview_heading_used = _overview_title_tag in ('h1', 'h2', 'h3', 'h4', 'h5', 'h6') if _overview_title_tag else False
        _overview_title_missing = _overview_title_m is None
        check(
            'Trip Overview вҖ” .overview-title must be a <div>, not a heading element '
            '(toolbar.js queries .overview-title via querySelector; <h2> breaks arrow injection '
            'and CSS; Trip Overview.html В§1)',
            not _overview_title_missing and not _overview_heading_used,
            (f'.overview-title uses <{_overview_title_tag}> вҖ” replace with <div class="overview-title">; '
             f'heading elements break toolbar.js arrow injection')
            if _overview_heading_used else
            ('Missing <div class="overview-title"> inside .overview-section')
            if _overview_title_missing else '',
        )

        # Match every <a вҖҰ> block inside the section; filter to overview-day only.
        overview_day_re = re.compile(
            r'<a\b([^>]*)>(.*?)</a>',
            re.DOTALL | re.IGNORECASE,
        )
        overview_days = [
            m for m in overview_day_re.finditer(overview_inner)
            if re.search(r'\boverview-day\b', m.group(1))
        ]

        check(
            'Trip Overview вҖ” at least one .overview-day card present',
            len(overview_days) > 0,
            'No <a class="overview-day"> cards found inside .overview-section'
            if not overview_days else "",
        )

        overview_bad_href: list[str] = []
        overview_missing_title: list[str] = []
        overview_stale_stops_div: list[str] = []  # .overview-day-stops is retired (2026-05-26)
        overview_has_count: list[str] = []
        overview_eoi_content: list[str] = []
        overview_day_label_repeated: list[str] = []
        # A day card is a title-only nav chip вҖ” a days-only grid, never a full
        # "Explore-of-Interest" card. Banning the retired .overview-day-stops /
        # -count divs is not enough: ANY EoI building block (image, paragraph,
        # list, table, heading, media) dropped into a card would pass vacuously.
        # This positively forbids those tags (Trip Overview.html вҖ” "No full EoI
        # cards in Trip Overview day-card area. Days-only grid.").
        _overview_eoi_re = re.compile(
            r'<(img|p|ul|ol|li|table|h[1-6]|figure|picture|source|video|iframe)\b',
            re.IGNORECASE,
        )

        for i, gd in enumerate(overview_days, 1):
            attrs = gd.group(1)
            inner = gd.group(2)

            # 5. No EoI card content вҖ” a day card holds only its title (+ optional
            # day-number badge); it is never a full illustrated/priced EoI card.
            _eoi_tags = _overview_eoi_re.findall(inner)
            if _eoi_tags:
                overview_eoi_content.append(f"card {i}: <{'>, <'.join(sorted(set(t.lower() for t in _eoi_tags)))}>")

            # 1. href="#..." must be present so the card actually navigates.
            # (Exact #day{N} format enforced by the TRIP OVERVIEW вҖ” STRICT FORMAT block.)
            if not re.search(r'\bhref\s*=\s*"#[^"]+?"', attrs):
                overview_bad_href.append(f"card {i}")

            # 2. .overview-day-title must exist.
            # (Title format "Day N В· рҹҺ’ вҖ” Stop1 В· Stop2" or "Day N В· рҹҡҶ Train Day вҖ” City"
            # enforced by the TRIP OVERVIEW STRICT FORMAT block.)
            title_m = re.search(
                r'<div\b[^>]*class\s*=\s*"[^"]*\boverview-day-title\b[^"]*"[^>]*>(.*?)</div>',
                inner, re.DOTALL | re.IGNORECASE,
            )
            if not title_m:
                overview_missing_title.append(f"card {i}")

            # 3. .overview-day-stops div is RETIRED (2026-05-26). Stops are now
            # inline in the title: "Day N В· рҹҺ’ вҖ” Stop1 В· Stop2 В· Stop3".
            # Hard-fail if the stale div still exists.
            if re.search(
                r'<div\b[^>]*class\s*=\s*"[^"]*\boverview-day-stops\b[^"]*"',
                inner, re.IGNORECASE,
            ):
                overview_stale_stops_div.append(f"card {i}")

            # 4. .overview-day-count is forbidden. Each card is title-only вҖ”
            # no "N stops В· N guided tours" count line. Per Trip Overview.html
            if re.search(
                r'<div\b[^>]*class\s*=\s*"[^"]*\boverview-day-count\b[^"]*"',
                inner, re.IGNORECASE,
            ):
                overview_has_count.append(f"card {i}")

            # 6. Day-number label "Day N" must not repeat inside a single card.
            # One nav chip = one "Day N" label, carried once by the
            # .overview-day-title text ("Day N вҖ“ Stop1 В· Stop2"). A duplicate вҖ”
            # e.g. a stray .overview-day-num badge sitting above the title вҖ”
            # shows the number twice in the same card. Caught via screenshot:
            # Aracaju/Olinda (same crib batch as the 2026-07-10 motion-banner
            # blue-link bug) carry an undocumented .overview-day-num div ("Day
            # 1") immediately followed by .overview-day-title ("Day 1 вҖ“ вҖҰ").
            _card_plain = RE_STRIP_TAGS.sub(' ', inner)
            _day_label_hits = re.findall(r'\bDay\s+' + str(i) + r'\b', _card_plain)
            if len(_day_label_hits) > 1:
                overview_day_label_repeated.append(
                    f'card {i}: "Day {i}" appears {len(_day_label_hits)} times in the card'
                )

        if overview_days:
            check(
                'Trip Overview вҖ” each .overview-day links to a day anchor (href="#вҖҰ")',
                len(overview_bad_href) == 0,
                f"{len(overview_bad_href)} card(s) missing href anchor: {overview_bad_href[:3]}"
                if overview_bad_href else "",
            )
            check(
                'Trip Overview вҖ” each card has a .overview-day-title',
                len(overview_missing_title) == 0,
                f"{len(overview_missing_title)} card(s) missing .overview-day-title: "
                f"{overview_missing_title[:3]}" if overview_missing_title else "",
            )
            check(
                'Trip Overview вҖ” no stale .overview-day-stops div '
                '(retired 2026-05-26; stops are now inline in the title after " вҖ” ")',
                len(overview_stale_stops_div) == 0,
                f"{len(overview_stale_stops_div)} card(s) still contain retired "
                f".overview-day-stops div: {overview_stale_stops_div[:3]} вҖ” "
                f"merge stops into the .overview-day-title as "
                f"\"Day N В· рҹҺ’ вҖ” Stop1 В· Stop2 В· Stop3\""
                if overview_stale_stops_div else "",
            )
            check(
                'Trip Overview вҖ” no .overview-day-count div (forbidden extra line)',
                len(overview_has_count) == 0,
                f"{len(overview_has_count)} card(s) contain forbidden .overview-day-count: "
                f"{overview_has_count[:3]}" if overview_has_count else "",
            )
            check(
                'Trip Overview вҖ” day cards are a days-only grid, no full EoI card '
                'content (no <img>/<p>/<ul>/<table>/<hN>/media inside an .overview-day '
                'card; Trip Overview.html)',
                len(overview_eoi_content) == 0,
                f"{len(overview_eoi_content)} card(s) contain EoI/foreign content: "
                f"{overview_eoi_content[:3]}" if overview_eoi_content else "",
            )
            check(
                'Trip Overview вҖ” day-number label "Day N" appears exactly once per card '
                '(one nav chip = one label, carried by .overview-day-title; a repeated '
                'label вҖ” e.g. a stray .overview-day-num badge above the title вҖ” shows '
                'the same "Day N" twice in one card)',
                len(overview_day_label_repeated) == 0,
                f"{len(overview_day_label_repeated)} card(s) repeat their day label: "
                f"{overview_day_label_repeated[:3]}" if overview_day_label_repeated else "",
            )

    # в”Җв”Җв”Җ BANNER BODY FORMAT вҖ” strict, no parentheticals / prose в”Җ
    # (Tilde handled globally вҖ” see the GLOBAL TILDE BAN check.)
    banner_format_bad = []
    banner_body_re = re.compile(
        r'<div\s+class\s*=\s*"(next|hotel-first|depart|arrive-first)"[^>]*>\s*(.*?)\s*</div>',
        re.IGNORECASE | re.DOTALL,
    )
    for bm in banner_body_re.finditer(html):
        cls = bm.group(1)
        body = bm.group(2)
        # Skip the tram sub-line вҖ” it's `.next-tram`, not `.next`, and has
        # its own shape rule.
        bad_reason = None
        if "(" in body or ")" in body:
            bad_reason = "parenthetical prose in banner body"
        if bad_reason:
            snip = RE_WS.sub(' ', body)[:80]
            banner_format_bad.append(f'.{cls}: {bad_reason} вҖ” "{snip}вҖҰ"')
    check(
        "Banner body format вҖ” no parentheticals, no prose tails",
        len(banner_format_bad) == 0,
        f"{len(banner_format_bad)} banner(s) violate strict-format rule: "
        + "; ".join(banner_format_bad[:3])
        if banner_format_bad else ""
    )

    # в”Җв”Җв”Җ OVERVIEW EXTRAS LINKS вҖ” ICON MUST MATCH THE SECTION TITLE ICON в”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ OVERVIEW EXTRAS LINKS вҖ” icon must match section title icon в”Җв”Җ")

    def _extract_icon(html_fragment: str):
        """Return ('img', basename) for <img> icons or ('emoji', char) for
        emoji icons. Returns None if no icon found."""
        # Match any <img> that has class="section-icon" вҖ” src may come before or
        # after the class attribute, so we search for each independently.
        img_tag_m = re.search(
            r'<img\b([^>]+)>',
            html_fragment,
            re.IGNORECASE,
        )
        if img_tag_m:
            attrs = img_tag_m.group(1)
            if re.search(r'\bsection-icon\b', attrs, re.IGNORECASE):
                src_m = re.search(r'\bsrc\s*=\s*"([^"]+)"', attrs, re.IGNORECASE)
                if src_m:
                    import os
                    return ('img', os.path.basename(src_m.group(1)))
        # Strip tags, find leading emoji (any char with Unicode category So/Sm/etc.)
        plain = RE_STRIP_TAGS.sub( '', html_fragment).strip()
        # Match one or more leading emoji (Unicode > U+00FF, or common emoji ranges)
        emoji_m = re.match(
            r'^([\U0001F000-\U0001FFFF\U00002600-\U000027FF\U00002B00-\U00002BFF'
            r'\U0000FE00-\U0000FEFF\U000024C2-\U0001F251]+)',
            plain,
        )
        if emoji_m:
            return ('emoji', emoji_m.group(1))
        return None

    _overview_icon_mismatches: list[str] = []
    _gel_re = re.compile(
        r'<a\b[^>]*\bclass\s*=\s*"[^"]*\boverview-extra-link\b[^"]*"[^>]*\bhref\s*=\s*"#([^"]+)"[^>]*>(.*?)</a>',
        re.IGNORECASE | re.DOTALL,
    )
    for gel_m in _gel_re.finditer(html):
        section_id = gel_m.group(1)
        link_inner = gel_m.group(2)
        link_icon = _extract_icon(link_inner)

        # Find the matching extras-section
        sec_re = re.compile(
            r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bextras-section\b[^"]*"[^>]*\bid\s*=\s*"'
            + re.escape(section_id) + r'"[^>]*>',
            re.IGNORECASE,
        )
        sec_m = sec_re.search(html)
        if not sec_m:
            continue  # section not found вҖ” other checks handle missing sections

        sec_inner, _ = _walk_balanced_div(html, sec_m.end())

        # Find the extras-title inside the section
        title_m = re.search(
            r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bextras-title\b[^"]*"[^>]*>(.*?)</div>',
            sec_inner,
            re.IGNORECASE | re.DOTALL,
        )
        if not title_m:
            continue  # no title вҖ” other checks handle this
        title_icon = _extract_icon(title_m.group(1))

        if link_icon != title_icon:
            link_plain = RE_STRIP_TAGS.sub( '', link_inner).strip()[:30]
            if link_icon and link_icon[0] == 'img':
                link_desc = f'<img:{link_icon[1]}>'
            elif link_icon:
                link_desc = link_icon[1]
            else:
                link_desc = '(none)'

            if title_icon and title_icon[0] == 'img':
                title_desc = f'<img:{title_icon[1]}>'
            elif title_icon:
                title_desc = title_icon[1]
            else:
                title_desc = '(none)'

            _overview_icon_mismatches.append(
                f'#{section_id} "{link_plain}": link={link_desc} вү  section={title_desc}'
            )

    check(
        'Overview extra links вҖ” every icon in the .overview-extra-link jump list matches '
        'the corresponding extras-section title icon '
        '(emoji вҶ” emoji or <img src> filename вҶ” <img src> filename)',
        len(_overview_icon_mismatches) == 0,
        (f'{len(_overview_icon_mismatches)} icon mismatch(es): '
         + ' || '.join(_overview_icon_mismatches[:6]))
        if _overview_icon_mismatches else '',
    )

    # в”Җв”Җв”Җ OVERVIEW EXTRAS вҶ” EXTRAS SECTIONS SYNC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Two-direction cross-check:
    #   A. Every extras-section in the guide has a overview-extra-link pointing to it.
    #      (Missing link = reader can't jump to the section from the overview bar.)
    #   B. Every overview-extra-link points to an extras-section that exists.
    #      (Orphan link = dead jump button.)
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ OVERVIEW EXTRAS вҶ” EXTRAS SECTIONS SYNC в”Җв”Җ")

    # Collect all extras-section IDs present in the guide.
    _extras_ids: set[str] = set(re.findall(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bextras-section\b[^"]*"[^>]*\bid\s*=\s*"([^"]+)"',
        html, re.IGNORECASE,
    ))

    # Collect all overview-extra-link target IDs (href="#X" вҶ’ "X").
    _gel_ids: set[str] = set(re.findall(
        r'<a\b[^>]*\bclass\s*=\s*"[^"]*\boverview-extra-link\b[^"]*"[^>]*\bhref\s*=\s*"#([^"]+)"',
        html, re.IGNORECASE,
    ))

    # A вҖ” extras section with no overview link (section вҶ’ link).
    # skip-list is exempt: it is a footnote at the very bottom of the guide,
    # not a navigable section вҖ” it intentionally carries no overview jump link
    # (per Skip List - Extra Section.html В§ 2-3).
    _extras_no_link = sorted(_extras_ids - _gel_ids - {"skip-list", "also-on-this-site"})
    check(
        'Overview extras bar вҖ” every extras-section has a matching overview-extra-link '
        '(missing link = section is unreachable from the overview jump bar; '
        'skip-list footnote exempt)',
        len(_extras_no_link) == 0,
        f"{len(_extras_no_link)} section(s) with no overview link: "
        + ', '.join(f'#{x}' for x in _extras_no_link)
        if _extras_no_link else '',
    )

    # B вҖ” overview link pointing to a non-existent extras section (link вҶ’ section).
    # Claude Inspiration carries its own class (not extras-section) per
    # Claude Inspiration - Extra Section.html В§4, yet Trip Overview.html В§3
    # defines a canonical вңЁ pill for it. The вңЁ CI pill is REQUIRED (mandatory
    # 2026-07-12 вҖ” same DriftyCat rule that made the section itself required).
    # When ci_section_m is set, the guide has the div, so we require the pill.
    if ci_section_m:
        _ci_ids_present: set[str] = set(re.findall(
            r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bclaude-inspiration\b[^"]*"[^>]*\bid\s*=\s*"([^"]+)"',
            html, re.IGNORECASE,
        ))
        _ci_pill_present = bool(_ci_ids_present & _gel_ids)
        check(
            'Overview extras bar вҖ” вңЁ Claude Inspiration pill is REQUIRED '
            '(mandatory 2026-07-12; Trip Overview.html В§3)',
            _ci_pill_present,
            'No вңЁ Claude Inspiration pill found in overview-extra-link row вҖ” '
            'add the pill linking to the claude-inspiration section',
        )
    _ci_ids: set[str] = set(re.findall(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bclaude-inspiration\b[^"]*"[^>]*\bid\s*=\s*"([^"]+)"',
        html, re.IGNORECASE,
    ))
    _links_no_section = sorted(_gel_ids - _extras_ids - _ci_ids)
    check(
        'Overview extras bar вҖ” every overview-extra-link points to an existing '
        'extras-section (orphan link = dead jump button)',
        len(_links_no_section) == 0,
        f"{len(_links_no_section)} orphan link(s) with no matching section: "
        + ', '.join(f'#{x}' for x in _links_no_section)
        if _links_no_section else '',
    )

    # в”Җв”Җв”Җ EXTRA SECTION UNIQUENESS вҖ” no section written twice в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Each extra section (Cappuccino, Tours, Claude Inspiration, Michelin, вҖҰ)
    # ships exactly once. Multiple entries belong INSIDE a single section
    # container вҖ” Claude Inspiration is one <div class="claude-inspiration"> with
    # several <p> blocks (Claude Inspiration - Extra Section.html В§1/В§4), never two
    # separate section containers each repeating the вңЁ Claude Inspiration title;
    # every other section is unique by Guide Structure.html section order. A
    # repeated section title = a whole section block was duplicated instead of
    # adding entries to the existing one (renders as two identical headers stacked
    # on the page). Identity = the .extras-title text of each section container
    # (extras-section OR claude-inspiration); empty titles (the CSS-injected
    # 'Also on this site' block) are excluded.
    print("\nв”Җв”Җ EXTRA SECTION UNIQUENESS в”Җв”Җ")
    _sec_open_re = re.compile(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\b(?:extras-section|claude-inspiration)\b[^"]*"[^>]*>',
        re.IGNORECASE,
    )
    _sec_title_re = re.compile(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bextras-title\b[^"]*"[^>]*>(.*?)</div>',
        re.IGNORECASE | re.DOTALL,
    )
    _sec_starts = [m.start() for m in _sec_open_re.finditer(html)]
    _sec_title_counts: dict[str, int] = {}
    for _i, _p in enumerate(_sec_starts):
        _seg_end = _sec_starts[_i + 1] if _i + 1 < len(_sec_starts) else len(html)
        _tm = _sec_title_re.search(html, _p, _seg_end)
        if not _tm:
            continue
        _t = re.sub(r'<[^>]+>', '', _tm.group(1))
        _t = re.sub(r'\s+', ' ', _t).strip()
        if _t:
            _sec_title_counts[_t] = _sec_title_counts.get(_t, 0) + 1
    _dup_sections = sorted(t for t, c in _sec_title_counts.items() if c > 1)
    check(
        'Extra section uniqueness вҖ” no extra section is written twice; each section '
        '(Cappuccino, Tours, Claude Inspiration, Michelin, вҖҰ) ships once with all its '
        'entries inside a single container (per Claude Inspiration - Extra Section.html '
        'В§4 and Guide Structure.html section order). A repeated section title = a whole '
        'section block duplicated instead of adding entries to the existing one',
        len(_dup_sections) == 0,
        'section(s) written more than once: '
        + ', '.join(f'{t!r} Г—{_sec_title_counts[t]}' for t in _dup_sections)
        if _dup_sections else '',
    )

    # в”Җв”Җв”Җ OVERVIEW EXTRAS вҖ” no В· dots as text separators в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Per Trip Overview.html В§ 3 and guide-style.css: the extras pill row uses
    # CSS flex gap for spacing between pills. Middle dots (В·) placed as HTML text
    # nodes between .overview-extra-link anchors are drift вҖ” they create orphaned
    # trailing dots after visual line wraps, and indicate Claude copied the
    # day-card stop format by mistake.
    print("\nв”Җв”Җ OVERVIEW EXTRAS вҖ” no В· dot separators в”Җв”Җ")
    _ge_div_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\boverview-extras\b[^"]*"[^>]*>',
        re.IGNORECASE,
    )
    _ge_m = _ge_div_re.search(html)
    _ge_dot_found = False
    if _ge_m:
        _ge_inner, _ = _walk_balanced_div(html, _ge_m.end())
        # Strip all <a>вҖҰ</a> blocks, then check for В· in the leftover text.
        _ge_no_anchors = re.sub(
            r'<a\b[^>]*>.*?</a>', '', _ge_inner,
            flags=re.DOTALL | re.IGNORECASE,
        )
        _ge_text_only = re.sub(r'<[^>]+>', '', _ge_no_anchors)
        if 'В·' in _ge_text_only or 'вҖў' in _ge_text_only or ' В· ' in _ge_text_only:
            _ge_dot_found = True
    check(
        'Overview extras bar вҖ” no В· dot separators as HTML text nodes between pills '
        '(spacing comes from CSS flex gap; literal В· is drift from the day-card '
        'stop-list format вҖ” creates orphaned trailing dots on line wrap) '
        '(Trip Overview.html В§ 3)',
        not _ge_dot_found,
        'Found В· middle-dot text node(s) between .overview-extra-link anchors in '
        '.overview-extras вҖ” remove all В· separators; CSS flex gap handles spacing'
        if _ge_dot_found else '',
    )

    # в”Җв”Җв”Җ OVERVIEW EXTRAS вҖ” canonical order + canonical label text в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Per Trip Overview.html В§ 3: extras pills appear in the same sequence
    # as the canonical extras-section order (Guide Structure.html).
    # Keep this list in sync with eoi_canonical_order at ~line 9900.
    # Canonical label text is an owner-defined decision (not a formatting choice)
    # вҖ” locked 2026-05-25. Both href anchor AND visible label text are enforced.
    print("\nв”Җв”Җ OVERVIEW EXTRAS вҖ” canonical order + label text в”Җв”Җ")
    _OVERVIEW_PILL_CANONICAL_ORDER = [
        "weekly-closures",
        "tours",
        "cappuccino",
        "restaurants",
        "downtown",
        "local-tastes",
        "food-delivery",
        "shows",
        "getting-around",
        "stations-near-hotel",
        "day-trips-by-train",
        "pickleball",
        "michelin",
        # "heads-up" pill label is enforced separately below
    ]
    # Canonical visible label text per href anchor вҖ” owner-defined, hard-fail on deviation.
    _OVERVIEW_PILL_CANONICAL_LABELS = {
        "weekly-closures":    "рҹ—“пёҸ Weekly Closures",
        "tours":              "рҹ“… Tours",
        "cappuccino":         "вҳ• Cappuccino",
        "restaurants":        "рҹ«• Restaurants Near Hotel",
        "downtown":           "рҹҚҪпёҸ Downtown Restaurants",
        "local-tastes":       "рҹҚ® Local Tastes",
        "food-delivery":      "рҹҡ— Food Delivery",
        "shows":              "рҹҺӯ Shows",
        "getting-around":     "рҹҡҢ Getting Around",
        "stations-near-hotel":"рҹҡҶ Train Stations",
        "day-trips-by-train": "вӣІпёҸ Day Trips",
        "pickleball":         "рҹҸ“ Pickleball",
        "michelin":           "вӯҗ Michelin",
        "heads-up":     "вқ—пёҸ Heads Up",
        # NOTE: "claude-inspiration" pill label is deliberately NOT enforced here.
        # Trip Overview В§3 fixes it as "вңЁ Claude Inspiration", but Claude
        # Inspiration.html В§2 + Icon Order В§3 say the icon/title are chosen freely вҖ”
        # an unresolved CORE RULES contradiction parked in To_Do_List.md (Rules for
        # Update, item 3). Enforcing one side here would pre-empt that decision.
    }
    _pill_anchor_re = re.compile(
        r'<a\b[^>]*class\s*=\s*"[^"]*\boverview-extra-link\b[^"]*"[^>]*href\s*=\s*"#([^"]+)"[^>]*>(.*?)</a>',
        re.IGNORECASE | re.DOTALL,
    )
    _pill_href_only_re = re.compile(
        r'<a\b[^>]*class\s*=\s*"[^"]*\boverview-extra-link\b[^"]*"[^>]*href\s*=\s*"#([^"]+)"',
        re.IGNORECASE,
    )
    if _ge_m:
        _ge_inner_order, _ = _walk_balanced_div(html, _ge_m.end())
        _pill_hrefs_found = _pill_href_only_re.findall(_ge_inner_order)
        # Filter to only those that appear in the canonical list.
        _known_pills = [h for h in _pill_hrefs_found if h in _OVERVIEW_PILL_CANONICAL_ORDER]
        # Build expected order: canonical list filtered to pills actually present.
        _expected_order = [s for s in _OVERVIEW_PILL_CANONICAL_ORDER if s in _known_pills]
        _pills_order_ok = _known_pills == _expected_order
        check(
            'Overview extras pills appear in canonical section order '
            '(Guide Structure.html / Trip Overview.html В§ 3)',
            _pills_order_ok,
            f'Pills out of canonical order вҖ” found: {_known_pills} | '
            f'expected: {_expected_order}'
            if not _pills_order_ok else '',
        )
        # Label text check вҖ” every pill's visible text must match the canonical label exactly.
        _pill_label_failures = []
        for _pill_href, _pill_raw_label in _pill_anchor_re.findall(_ge_inner_order):
            _pill_label = re.sub(r'<[^>]+>', '', _pill_raw_label).strip()
            _expected_label = _OVERVIEW_PILL_CANONICAL_LABELS.get(_pill_href)
            if _expected_label is None:
                continue  # unknown anchor вҖ” not checked here
            # Normalize the invisible variation-selector U+FE0F on both sides so a
            # bare-vs-FE0F emoji difference is not reported as an undiagnosable
            # "got X, expected X" where the two strings look identical. (Lane1-06.)
            if _pill_label.replace('пёҸ', '') != _expected_label.replace('пёҸ', ''):
                _pill_label_failures.append(
                    f'#{_pill_href}: got {_pill_label!r}, expected {_expected_label!r}'
                )
        check(
            'Overview extras pill label text matches canonical name for every pill '
            '(owner-defined labels вҖ” locked 2026-05-25)',
            not _pill_label_failures,
            'Wrong pill label(s): ' + '; '.join(_pill_label_failures)
            if _pill_label_failures else '',
        )
        # Weekly Closures pill must be preceded by a | separator span with color:#d4b896.
        _wc_sep_re = re.compile(
            r'<span[^>]*color:\s*#d4b896[^>]*>\|</span>\s*<a[^>]*href="#weekly-closures"',
            re.IGNORECASE,
        )
        _has_wc_pill = '#weekly-closures' in _ge_inner_order
        check(
            'Weekly Closures pill preceded by | separator span (color:#d4b896) вҖ” added 2026-06-16',
            not _has_wc_pill or bool(_wc_sep_re.search(_ge_inner_order)),
            'Weekly Closures pill missing | separator span with color:#d4b896 before it'
            if _has_wc_pill and not _wc_sep_re.search(_ge_inner_order) else '',
        )
    else:
        warn(
            'Overview extras pills вҖ” .overview-extras div not found; '
            'pill order and label checks skipped',
        )

    # Backpack emoji hard-fail вҖ” рҹҺ’ (U+1F392) retired from guide HTML 2026-06-16.
    # CSS ::before is now empty; use .stop-name.self class only (no inline emoji).
    check(
        'No рҹҺ’ backpack emoji in guide HTML (retired 2026-06-16 вҖ” icon removed from both overview-day-title and stop-name; CSS ::before now empty)',
        '\U0001f392' not in html,
        'Backpack emoji рҹҺ’ found in guide HTML вҖ” removed 2026-06-16; use .stop-name.self class only (no inline emoji)',
    )

    # Overview day-title: no icon before "Day N" вҖ” locked 2026-06-16.
    # The .overview-day-title text must start with "Day " directly.
    # Any emoji or other character before "Day" means the backpack (or
    # other icon) was left in the HTML instead of being removed.
    _RE_STRIP_TAGS_DAYCHECK = re.compile(r'<[^>]+>')
    _daycard_title_re = re.compile(
        r'<div[^>]*class\s*=\s*"[^"]*overview-day-title[^"]*"[^>]*>(.*?)</div>',
        re.DOTALL | re.IGNORECASE,
    )
    _daycard_no_icon_bad: list[str] = []
    for _dtm in _daycard_title_re.finditer(html):
        _dt_text = _RE_STRIP_TAGS_DAYCHECK.sub('', _dtm.group(1)).strip()
        if _dt_text and not _dt_text.startswith('Day '):
            _daycard_no_icon_bad.append(_dt_text[:80])
    check(
        'Overview day-title cards start with "Day N" вҖ” no icon before day number (locked 2026-06-16)',
        not _daycard_no_icon_bad,
        (f"{len(_daycard_no_icon_bad)} overview-day-title div(s) whose text does not start with \"Day\": "
         + "; ".join(_daycard_no_icon_bad[:5])
         + (" вҖҰ" if len(_daycard_no_icon_bad) > 5 else ""))
        if _daycard_no_icon_bad else "",
    )

    # Check A: no emoji before Day N вҖ” hard-fail with exact description (2026-06-16).
    # Finds all .overview-day-title divs and fails if any text starts with a
    # non-letter/non-digit/non-space character before "Day" (emoji, icon, etc.).
    _RE_STRIP_TAGS_A = re.compile(r'<[^>]+>')
    _daycard_a_re = re.compile(
        r'<div[^>]*class\s*=\s*"[^"]*overview-day-title[^"]*"[^>]*>(.*?)</div>',
        re.DOTALL | re.IGNORECASE,
    )
    _daycard_a_bad: list[str] = []
    for _am in _daycard_a_re.finditer(html):
        _a_text = _RE_STRIP_TAGS_A.sub('', _am.group(1)).strip()
        if _a_text and not re.match(r'^Day \d+', _a_text):
            _daycard_a_bad.append(_a_text)
    check(
        'No emoji before Day N in overview-day-title (icon removed 2026-06-16 вҖ” format is "Day N вҖ“ Stop В· Stop")',
        not _daycard_a_bad,
        '; '.join(
            f'overview-day-title starts with icon/emoji instead of "Day N": {t[:40]!r}'
            for t in _daycard_a_bad[:5]
        ) + (' вҖҰ' if len(_daycard_a_bad) > 5 else '')
        if _daycard_a_bad else '',
    )

    # Check B: no inline emoji before stop names in HTML вҖ” hard-fail (2026-06-16).
    # The icon is CSS-only (::before, now empty). No emoji should appear in the
    # HTML text content of .stop-name spans.
    _RE_STRIP_TAGS_B = re.compile(r'<[^>]+>')
    _stopname_spans = re.findall(
        r'<span[^>]*class\s*=\s*"[^"]*stop-name[^"]*"[^>]*>([\s\S]+?)</span>',
        html,
    )
    _stopname_emoji_bad: list[str] = []
    for _sn_raw in _stopname_spans:
        _sn_text = _RE_STRIP_TAGS_B.sub('', _sn_raw).strip()
        if _sn_text and ord(_sn_text[0]) > 0x00FF:
            _stopname_emoji_bad.append(_sn_text)
    check(
        'No inline emoji before stop names in HTML (icon is CSS-only ::before, now empty вҖ” locked 2026-06-16)',
        not _stopname_emoji_bad,
        'stop-name spans with emoji prefix: ' + '; '.join(
            repr(s[:40]) for s in _stopname_emoji_bad[:5]
        ) + (' вҖҰ' if len(_stopname_emoji_bad) > 5 else '')
        if _stopname_emoji_bad else '',
    )

    # в”Җв”Җв”Җ TRIP OVERVIEW вҖ” STRICT FORMAT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ TRIP OVERVIEW STRICT FORMAT в”Җв”Җ")
    if "overview-section" in html:
        # Section title вҖ” search for the literal phrase. Allow optional
        # heading wrappers (h1/h2/h3, span with class).
        _overview_title_ok = bool(
            re.search(r'<div\b[^>]*class\s*=\s*"overview-title"[^>]*>\s*TRIP OVERVIEW\s*</div>', html)
        )
        check(
            "Trip Overview section title is `TRIP OVERVIEW` вҖ” all caps, no icon (updated 2026-06-16)",
            _overview_title_ok,
            "Section is present but `TRIP OVERVIEW` (all caps, no icon) wasn't found in .overview-title."
            if not _overview_title_ok else "",
        )
        check(
            "Trip Overview title must NOT contain рҹ“Ң вҖ” icon removed 2026-06-15 (Trip Overview.html)",
            'рҹ“Ң' not in re.search(
                r'<div\b[^>]*class\s*=\s*"overview-title"[^>]*>.*?</div>', html, re.DOTALL
            ).group(0) if re.search(r'<div\b[^>]*class\s*=\s*"overview-title"[^>]*>.*?</div>', html, re.DOTALL) else True,
            "рҹ“Ң icon found in .overview-title вҖ” remove it; title must be `TRIP OVERVIEW`",
        )
        # Check C: no emoji before overview-title text вҖ” hard-fail (2026-06-16).
        _ot_m = re.search(
            r'<div[^>]*class\s*=\s*"overview-title"[^>]*>(.*?)</div>', html, re.DOTALL
        )
        _ot_text = re.sub(r'<[^>]+>', '', _ot_m.group(1)).strip() if _ot_m else ''
        check(
            'No emoji before overview-title text (locked 2026-06-16 вҖ” must be plain "TRIP OVERVIEW")',
            not (_ot_text and ord(_ot_text[0]) > 0x00FF),
            f'overview-title starts with emoji: {_ot_text[:40]!r}'
            if (_ot_text and ord(_ot_text[0]) > 0x00FF) else '',
        )
        # Card titles вҖ” two valid formats (Trip Overview.html В§2, updated 2026-06-16):
        #   regular day  : "Day N вҖ“ Stop1 В· Stop2 В· Stop3"  (en dash, no icon before stops)
        #   train day    : "Day N В· рҹҡҶ Train Day вҖ” Destination"
        #                  (city suffix required so destination is visible at overview level)
        # Note: рҹҺ’ icon retired 2026-06-16; regular days now use en dash only.
        _valid_pat = re.compile(
            r"^\s*Day\s+\d+\s+"
            r"(?:"
            # regular day: en dash (вҖ“) then at least one stop
            r"вҖ“\s+\S.*"
            r"|"
            # рҹҡҶ train day: dot + icon + "Train Day"; destination suffix required
            r"В·\s+рҹҡҶ\s+Train\s+Day\s+вҖ”\s+\S.*"
            r")\s*$",
        )
        _overview_titles = re.findall(
            r'<[^>]*\bclass\s*=\s*"[^"]*\boverview-day-title\b[^"]*"[^>]*>([^<]+)<',
            html,
        )
        _bad_overview: list[str] = []
        for t in _overview_titles:
            if not _valid_pat.match(t):
                _bad_overview.append(t.strip()[:80])
        check(
            "Every .overview-day-title matches canonical format: "
            "\"Day N вҖ“ Stop1 В· Stop2\" or \"Day N В· рҹҡҶ Train Day вҖ” City\" "
            "(Trip Overview.html В§2, 2026-06-16 вҖ” рҹҺ’ icon retired; en dash replaces dot+icon)",
            not _bad_overview,
            (f"{len(_bad_overview)} card title(s) with non-canonical format: "
             + "; ".join(_bad_overview[:5])
             + (" вҖҰ" if len(_bad_overview) > 5 else ""))
            if _bad_overview else "",
        )

    # в”Җв”Җв”Җ TRIP OVERVIEW вҖ” STRICT FORMAT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ TRIP OVERVIEW вҖ” STRICT FORMAT в”Җв”Җ")

    # A. Position вҖ” .overview-section between .title-page and first .day-block.
    _tp_open = re.search(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\btitle-page\b[^"]*"',
        html, re.IGNORECASE,
    )
    _gs_open = re.search(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\boverview-section\b[^"]*"',
        html, re.IGNORECASE,
    )
    _db_open = re.search(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bday-block\b[^"]*"',
        html, re.IGNORECASE,
    )
    _position_problems: list[str] = []
    if _tp_open and _gs_open and _tp_open.start() > _gs_open.start():
        _position_problems.append(".overview-section appears BEFORE .title-page")
    if _gs_open and _db_open and _gs_open.start() > _db_open.start():
        _position_problems.append(".overview-section appears AFTER the first .day-block")
    check(
        'Trip Overview position вҖ” .overview-section sits between .title-page and the first .day-block (Trip Overview.html Section title)',
        len(_position_problems) == 0,
        "; ".join(_position_problems) if _position_problems else "",
    )

    # Card extraction вҖ” strict <a class="overview-day"> match, in document
    # order. The class attribute must contain the exact whole-word token
    # `overview-day` (whitespace-separated from any other classes); the
    # whole-word match excludes the hyphenated `.overview-day-title` /
    # `.overview-day-stops` cousins (which are <div>s anyway). Re-extracted
    # here rather than reusing the upper-section list so this block is
    # self-contained вҖ” easier to audit, no cross-block coupling.
    _overview_card_re = re.compile(
        r'<a\b([^>]*?)>(.*?)</a>',
        re.DOTALL | re.IGNORECASE,
    )
    _overview_cards: list[dict] = []
    for _m in _overview_card_re.finditer(html):
        _attrs = _m.group(1)
        if not re.search(
            r'\bclass\s*=\s*"(?:[^"]*\s)?overview-day(?:\s[^"]*)?"',
            _attrs,
        ):
            continue
        _inner = _m.group(2)
        _href_m = re.search(r'\bhref\s*=\s*"([^"]*)"', _attrs)
        _title_m = re.search(
            r'<div\b[^>]*\bclass\s*=\s*"[^"]*\boverview-day-title\b[^"]*"[^>]*>([^<]+)<',
            _inner, re.IGNORECASE,
        )
        # Stops are now inline in the title after " вҖ” " (2026-05-26).
        # Extract stops inline: "Day N вҖ“ Stop1 В· Stop2 В· Stop3" (en dash, 2026-06-16+)
        # or legacy "Day N В· рҹҺ’ вҖ” Stop1 В· Stop2 В· Stop3" (retired 2026-06-16).
        # Train Day cards have no inline stop list вҖ” stops field stays ''.
        _stops_inline = ''
        if _title_m:
            _title_txt = _title_m.group(1)
            # Train Day cards carry no inline stop list вҖ” the text after the
            # en-dash is the "рҹҡҶ Train Day вҖ” {Destination}" label, NOT stops.
            # Leaving stops='' here makes the count/name sync skip the card
            # (per the documented intent). Guided Coach days DO list real stops
            # in the overview title, so they are parsed normally.
            if 'Train Day' not in _title_txt:
                _tm = re.search(r'(?:рҹҺ’\s+вҖ”|вҖ“)\s+(.+)', _title_txt)
                if _tm:
                    _stops_inline = _tm.group(1).strip()
        _overview_cards.append({
            'href':  _href_m.group(1) if _href_m else '',
            'title': _title_m.group(1).strip() if _title_m else '',
            'stops': _stops_inline,
        })

    # B. Day order вҖ” non-Train-Day cards before рҹҡҶ Train Day cards.
    _seen_train = False
    _order_violations: list[str] = []
    for _card in _overview_cards:
        _is_train = 'рҹҡҶ Train Day' in _card['title']
        if _is_train:
            _seen_train = True
        elif _seen_train:
            _order_violations.append(_card['title'][:60])
    check(
        'Trip Overview day order вҖ” all non-рҹҡҶ Train Day cards come BEFORE all '
        'рҹҡҶ Train Day cards (Trip Overview.html В§2)',
        len(_order_violations) == 0,
        (f"{len(_order_violations)} non-Train-Day card(s) appear AFTER a "
         f"Train-Day card: {_order_violations[:3]}")
        if _order_violations else "",
    )

    # C. Card count = .day-block count.
    _day_block_count = len(re.findall(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bday-block\b[^"]*"',
        html, re.IGNORECASE,
    ))
    _overview_count = len(_overview_cards)
    check(
        'Trip Overview card count = .day-block count (1:1 symmetry вҖ” every touring day has exactly one card)',
        _overview_count == _day_block_count,
        (f"{_overview_count} overview card(s) vs {_day_block_count} .day-block(s) "
         f"вҖ” mismatch indicates a forgotten card or stray day-block")
        if _overview_count != _day_block_count else "",
    )

    # D. Day numbers sequential from 1, no gaps, no duplicates.
    _day_numbers: list[int] = []
    _bad_day_numbers: list[str] = []
    for _card in _overview_cards:
        _dm = re.match(r'^\s*Day\s+(\d+)\s+[В·вҖ“]', _card['title'])  # В· = Train Day / legacy; вҖ“ = regular day (2026-06-16+)
        if _dm:
            _day_numbers.append(int(_dm.group(1)))
        else:
            _bad_day_numbers.append(_card['title'][:60])
    _expected_seq = list(range(1, len(_day_numbers) + 1))
    _seq_ok = (_day_numbers == _expected_seq)
    check(
        'Trip Overview day numbers вҖ” sequential from Day 1, no gaps, no duplicates',
        _seq_ok and not _bad_day_numbers,
        (
            (f"{len(_bad_day_numbers)} card(s) without parseable day number: "
             f"{_bad_day_numbers[:3]}; "
             if _bad_day_numbers else "")
            + (f"day-number sequence is {_day_numbers[:10]} but expected "
               f"{_expected_seq[:10]} вҖ” gap, duplicate, or out-of-order"
               if not _seq_ok else "")
        )
        if (_bad_day_numbers or not _seq_ok) else "",
    )

    # E-pre. Day-type icon must match actual stop modifiers in the day-block.
    # The format check (above) validates the label is one of the two active
    # strings, but does not verify it is *true* вҖ” a day with only guided stops
    # could still carry "рҹҺ’ Self-Guided" and pass the format check. This closes
    # that gap.
    #
    # Rule (Trip Overview.html В§1):
    #   рҹҺ’ Self-Guided вҶ’ every stop in the day has the .self modifier
    #   рҹҡҶ Train Day   вҶ’ day-header contains "Train Day"
    # (рҹҡ© Guided and рҹҺ’ + рҹҡ© Self + Guided retired 2026-05-20)
    #
    # Correlation: card href="#day-N" вҶ’ <div class="day-block" id="day-N">.
    print("\nв”Җв”Җ OVERVIEW CARD ICON вҶ” STOP MODIFIERS SYNC в”Җв”Җ")
    _icon_sync_violations: list[str] = []

    # Build id вҶ’ inner-HTML map for every .day-block that has an id attribute.
    _day_block_map: dict[str, str] = {}
    for _dbsm in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bday-block\b[^"]*"[^>]*>',
        html, re.IGNORECASE,
    ):
        _full_open = _dbsm.group(0)
        _id_m2 = re.search(r'\bid\s*=\s*"([^"]+)"', _full_open, re.IGNORECASE)
        if _id_m2:
            _db_inn, _ = _walk_balanced_div(html, _dbsm.end())
            _day_block_map[_id_m2.group(1)] = _db_inn

    for _card in _overview_cards:
        _anchor = _card['href'].lstrip('#')
        if not _anchor or _anchor not in _day_block_map:
            continue  # no matching id вҖ” card-count check handles mismatch
        _db_body = _day_block_map[_anchor]
        _card_title = _card['title']

        # Extract everything after "Day N В· " or "Day N вҖ“ " as the label.
        _lm2 = re.match(r'^\s*Day\s+\d+\s+[В·вҖ“]\s+(.+?)\s*$', _card_title)
        if not _lm2:
            continue  # malformed title вҖ” format check handles this
        _card_label = _lm2.group(1).strip()

        # Determine day type from the .day-header text.
        _dhm = re.search(
            r'<div\b[^>]*\bclass\s*=\s*"[^"]*\bday-header\b[^"]*"[^>]*>([^<]+)<',
            _db_body, re.IGNORECASE,
        )
        _dh_text = RE_WS.sub(' ', _dhm.group(1).strip()) if _dhm else ''
        _is_train_day_block = 'Train Day' in _dh_text

        if _is_train_day_block:
            # Train Day header вҶ’ card MUST carry рҹҡҶ and "Train Day" label.
            if 'рҹҡҶ' not in _card_label or 'Train Day' not in _card_label:
                _icon_sync_violations.append(
                    f'"{_card_title[:60]}" вҖ” day-header says Train Day '
                    f'but card label does not use рҹҡҶ Train Day'
                )
            continue  # skip stop-modifier check for Train Days

        # Non-Train Day: .guided modifier was retired 2026-05-20.
        # Hard-fail on any .guided class вҖ” it must not appear in new builds.
        # Only valid non-Train type is .self вҶ’ рҹҺ’ Self-Guided.
        # (Stops Structure.html В§2 вҖ” two active labels only.)
        _has_guided_stop = bool(re.search(
            r'<span\b[^>]*\bclass\s*=\s*"[^"]*\bguided\b[^"]*"',
            _db_body, re.IGNORECASE,
        ))
        _has_self_stop = bool(re.search(
            r'<span\b[^>]*\bclass\s*=\s*"[^"]*\bself\b[^"]*"',
            _db_body, re.IGNORECASE,
        ))

        if _has_guided_stop:
            # .guided is a retired modifier вҖ” hard-fail regardless of mixed/pure.
            _icon_sync_violations.append(
                f'"{_card_title[:60]}" вҖ” .stop-name.guided modifier is retired '
                f'(2026-05-20); replace with .self for self-guided stops '
                f'(Stops Structure.html В§2)'
            )
        elif _has_self_stop:
            pass  # .self stops no longer require an icon (рҹҺ’ retired 2026-06-16)
        # else: no stops with known modifiers вҖ” stop-count check handles absence.

    check(
        'Overview card icon reflects actual stop types in the day-block вҖ” '
        'рҹҺ’ Self-Guided (only .self stops) В· '
        'рҹҡҶ Train Day (day-header says "Train Day") '
        '(Trip Overview.html В§1)',
        len(_icon_sync_violations) == 0,
        (f'{len(_icon_sync_violations)} card(s) with icon/day-type mismatch: '
         + '; '.join(_icon_sync_violations[:5]))
        if _icon_sync_violations else '',
    )

    # E. Day-card suffix rules (2026-05-26 format):
    #   - рҹҺ’ day       вҶ’  ` вҖ” Stop1 В· Stop2 В· вҖҰ` (stops inline after the dash;
    #                     the вҖ” is structural, NOT a city suffix вҖ” exempt from
    #                     the in-city suffix check)
    #   - рҹҡҶ Train Day вҶ’  ` вҖ” {Destination}` (city suffix required, no arrow)
    _train_format_violations: list[str] = []
    _incity_suffix_violations: list[str] = []
    # Flat set of every day-block stop name (lowercased, tags stripped). Used to
    # tell a legitimate em-dash INSIDE a real stop name (e.g. "MATE вҖ” Museo Mario
    # Testino", "Mount Pilatus вҖ” Golden Round Trip", "Mellah вҖ” Jewish Quarter")
    # from a stray train-day-style ` вҖ” City` suffix on an in-city card. A real
    # stop's em-dash is fine; a suffix that matches no day-block stop is not.
    _all_stop_names_lc = [
        re.sub(r'<[^>]+>', '', _html_unescape(_sm.group(1))).strip().lower()
        for _sm in re.finditer(
            r'<span\b[^>]*\bclass\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>([\s\S]+?)</span>',
            html, re.IGNORECASE)
    ]
    for _card in _overview_cards:
        _t = _card['title']
        _is_train = 'рҹҡҶ Train Day' in _t
        _is_backpack = 'рҹҺ’' in _t

        if _is_train:
            # Train Day: ` вҖ” {Destination}` (no arrow)
            _em_dash_idx = _t.find('вҖ”')
            _has_suffix = _em_dash_idx != -1
            _suffix = _t[_em_dash_idx + 1:].strip() if _has_suffix else ''
            if not (_has_suffix and _suffix and 'вҶ’' not in _suffix):
                _train_format_violations.append(
                    f"{_t[:70]} вҖ” Train Day needs `вҖ” {{City}}` (no arrow)"
                )
        elif not _is_backpack:
            # Non-рҹҺ’, non-train in-city card. Format (2026-06-16): `Day N вҖ“ Stop1
            # В· Stop2 В· вҖҰ`. An em-dash is only a city-suffix violation if it is
            # NOT part of a real stop name. Strip the `Day N вҖ“/вҖ”` prefix, split
            # the stop list on ` В· `, and flag only an em-dash segment that
            # matches no day-block stop (substring either direction, like the
            # name-sync check). Real em-dash stop names pass.
            if 'вҖ”' in _t:
                _stop_portion = re.sub(
                    r'^\s*Day\s+\d+\s*[вҖ“вҖ”]\s*', '', _html_unescape(_t))
                for _seg in re.split(r'\s*В·\s*', _stop_portion):
                    if 'вҖ”' not in _seg:
                        continue
                    _seg_lc = _seg.strip().lower()
                    if not any(_seg_lc in _sn or _sn in _seg_lc
                               for _sn in _all_stop_names_lc if _sn):
                        _incity_suffix_violations.append(
                            f"{_t[:70]} вҖ” in-city day must not carry a city suffix"
                        )
                        break

    check(
        'рҹҡҶ Train Day cards carry the right suffix вҖ” `вҖ” {City}` '
        '(Trip Overview.html вҖ” Each day card and day order)',
        not _train_format_violations,
        "; ".join(_train_format_violations[:3]) if _train_format_violations else "",
    )
    check(
        'In-city day cards must be bare вҖ” no city suffix '
        '(Trip Overview.html вҖ” Each day card and day order)',
        not _incity_suffix_violations,
        "; ".join(_incity_suffix_violations[:3]) if _incity_suffix_violations else "",
    )

    # F. Overview card href matches `#day{N}` pattern (not arbitrary anchor).
    _bad_href_pattern: list[str] = []
    for _card in _overview_cards:
        _h = _card['href']
        if not _h:
            continue  # Missing href caught by earlier href-presence check.
        if not re.match(r'^#day\d+$', _h):
            _bad_href_pattern.append(_h[:40])
    check(
        'Trip Overview card href matches `#day{N}` (Trip Overview.html Cross-links)',
        len(_bad_href_pattern) == 0,
        (f"{len(_bad_href_pattern)} card href(s) with non-`#day{{N}}` pattern: "
         f"{_bad_href_pattern[:3]} вҖ” locked shape is `href=\"#day{{N}}\"` "
         f"to match `id=\"day{{N}}\"` on the day-block")
        if _bad_href_pattern else "",
    )

    # G. Overview card titles don't reference Day 0 / arrival / departure.
    _overview_arrival_re = re.compile(
        r"\b(arrival|arriving|departure|departing|day\s*0|day\s*zero)\b",
        re.IGNORECASE,
    )
    _overview_arrival_hits: list[str] = []
    for _card in _overview_cards:
        if _overview_arrival_re.search(_card['title']):
            _overview_arrival_hits.append(_card['title'][:60])
    check(
        'Trip Overview cards exclude arrival/departure/Day 0 (Trip Overview.html Arrival / departure days excluded)',
        len(_overview_arrival_hits) == 0,
        (f"{len(_overview_arrival_hits)} card(s) reference "
         f"arrival/departure/Day 0: {_overview_arrival_hits[:3]} вҖ” "
         f"only real touring days appear as cards")
        if _overview_arrival_hits else "",
    )

    # в”Җв”Җв”Җ TRIP OVERVIEW вҖ” STOP COUNT & NAME SYNC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Cross-check: for every рҹҺ’ overview card, the number of stop entries inline
    # in the title ("Day N В· рҹҺ’ вҖ” Stop1 В· Stop2 В· Stop3") must equal the number
    # of .stop-name spans in the corresponding .day-block (href="#dayN" вҶ’ id="dayN").
    # A count mismatch means a stop was added/removed without updating the overview
    # card. A name mismatch means a stop was renamed without updating the title.
    # рҹҡҶ Train Day cards carry no inline stop list вҖ” skipped.
    #
    # Name matching uses substring: overview entries are allowed to be simplified
    # versions of the full stop name (e.g. "Luxembourg Garden" matches
    # "Luxembourg Garden or Palace"). Either direction passes вҖ” overview entry is
    # a substring of the stop name, OR the stop name is a substring of the entry.
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ TRIP OVERVIEW вҖ” STOP COUNT & NAME SYNC в”Җв”Җ")

    _overview_sync_count_bad: list[str] = []
    _overview_sync_name_bad:  list[str] = []

    # Build a map of day-id вҶ’ ordered list of stop names for every day-block.
    _gsync_stop_name_re = re.compile(
        r'<span\b[^>]*\bclass\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>([\s\S]+?)</span>',
        re.IGNORECASE,
    )
    _gsync_day_id_re = re.compile(
        r'<div\b[^>]*\bid\s*=\s*"(day\d+)"[^>]*>',
        re.IGNORECASE,
    )
    _day_stop_map: dict[str, list[str]] = {}
    for _dbm in _gsync_day_id_re.finditer(html):
        _db_inner, _ = _walk_balanced_div(html, _dbm.end())
        _day_stop_map[_dbm.group(1)] = [
            re.sub(r'<[^>]+>', '', _html_unescape(m.group(1))).strip()
            for m in _gsync_stop_name_re.finditer(_db_inner)
        ]

    for _card in _overview_cards:
        _href  = _card.get('href', '')
        _stops_raw = _card.get('stops', '')
        if not _href or not _stops_raw:
            continue
        _day_id = _href.lstrip('#')           # "#day1" вҶ’ "day1"
        if not re.match(r'^day\d+$', _day_id):
            continue  # malformed href already caught by check F

        # Decode HTML entities, split on ' В· '
        _overview_entries = [
            s.strip()
            for s in re.split(r'\s*В·\s*', _html_unescape(_stops_raw))
            if s.strip()
        ]
        _day_stops = _day_stop_map.get(_day_id, [])
        _card_label = f"#{_day_id} ({_card.get('title', '')[:40]})"

        # Count check first вҖ” if counts differ the positional name check is
        # meaningless (indices won't align), so we skip it.
        if len(_overview_entries) != len(_day_stops):
            _overview_sync_count_bad.append(
                f"{_card_label}: overview has {len(_overview_entries)} "
                f"entr(ies) but day-block has {len(_day_stops)} stop(s)"
            )
            continue

        # Name sync вҖ” positional, same order assumed.
        for _i, (_ge, _sn) in enumerate(zip(_overview_entries, _day_stops), 1):
            _ge_n = _ge.lower()
            _sn_n = _sn.lower()
            # Pass when either is a substring of the other.
            if _ge_n not in _sn_n and _sn_n not in _ge_n:
                _overview_sync_name_bad.append(
                    f"{_card_label} stop {_i}: "
                    f"overview=\"{_ge[:50]}\" vs day-block=\"{_sn[:50]}\""
                )

    check(
        'Trip Overview вҖ” stop count matches day-block stop count for each day '
        '(1 overview entry per stop вҖ” mismatch means a stop was added/removed '
        'without updating the overview card)',
        len(_overview_sync_count_bad) == 0,
        f"{len(_overview_sync_count_bad)} day(s) with count mismatch: "
        + "; ".join(_overview_sync_count_bad[:3])
        if _overview_sync_count_bad else "",
    )
    check(
        'Trip Overview вҖ” each overview stop entry matches its day-block stop '
        'name (substring match in either direction; overview may simplify вҖ” '
        'mismatch means a stop was renamed without updating the overview card)',
        len(_overview_sync_name_bad) == 0,
        f"{len(_overview_sync_name_bad)} stop(s) with name mismatch: "
        + "; ".join(_overview_sync_name_bad[:3])
        if _overview_sync_name_bad else "",
    )

    # в”Җв”Җв”Җ STOP DESCRIPTION LENGTH вҖ” вҶі rows вүӨ320 chars (4 lines) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Scoped to stop-block content only. The global document contains other вҶі
    # rows (extra sections use вҶі with their own caps вҖ” scoping to stop-block
    # bodies isolates the stop-level description rows).
    # Each stop-block body is extracted first; only вҶі rows within stop
    # content are measured here.
    _STOP_DESC_LIMIT = 320   # ~4 lines, per Icon Order and Format.html
    print("\nв”Җв”Җ STOP DESCRIPTION LENGTH вҖ” вҶі rows вүӨ320 chars (4 lines) в”Җв”Җ")
    _stop_desc_violations: list[str] = []
    _stop_block_bodies_desc = re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"[^>]*>(.*?)'
        r'(?=<div\b[^>]*class\s*=\s*"(?:stop-block|next|next-tram|next-metro|train|day-header|day-block|extras-section)\b|<hr\b|</body>)',
        html,
        re.DOTALL | re.IGNORECASE,
    )
    for _sb in _stop_block_bodies_desc:
        for _sdm in re.finditer(r'<div\b[^>]*>(вҶі.*?)</div>', _sb, re.DOTALL | re.IGNORECASE):
            _sd_text = RE_STRIP_TAGS.sub('', _sdm.group(1)).strip()
            if len(_sd_text) > _STOP_DESC_LIMIT:
                _stop_desc_violations.append(
                    f'{len(_sd_text)} chars: "{_sd_text[:70]}вҖҰ"'
                )
    check(
        'Stop description rows (вҶі) must be вүӨ320 chars / 4 lines '
        '(per Icon Order and Format.html вҖ” вҶі Stop description row)',
        len(_stop_desc_violations) == 0,
        f"{len(_stop_desc_violations)} вҶі row(s) over 320 chars (trim to вүӨ4 lines): "
        + "; ".join(_stop_desc_violations[:4])
        if _stop_desc_violations else "",
    )

    # в”Җв”Җв”Җ вҶі / рҹ“– ROW CLASS вҖ” must be .stop-row в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The вҶі description row and the рҹ“– Wikipedia row are .stop-row divs (CSS
    # `.stop-row { margin:4px 0 }` plus the wiki-tightening rule). A guide that
    # gives them a different class (e.g. Aix's `stop-desc` / `stop-wiki`) gets
    # NO matching CSS, so the row renders with browser-default block spacing вҖ”
    # the gap before the operational box balloons. Caught visually 2026-06-16
    # (Aix HГҙtel de Caumont). Bare class-less rows (`<div>вҶі` inside a
    # transit-box / operational box) are NOT matched here вҖ” only divs that
    # carry a class attribute, which must include the `stop-row` token.
    print("\nв”Җв”Җ вҶі / рҹ“– ROW CLASS вҖ” must be .stop-row в”Җв”Җ")
    _row_class_bad: list[str] = []
    for _rcm in re.finditer(
        r'<div\b[^>]*\bclass\s*=\s*"([^"]*)"[^>]*>\s*(вҶі|рҹ“–)',
        html,
    ):
        _cls_tokens = _rcm.group(1).split()
        if 'stop-row' not in _cls_tokens:
            _glyph = _rcm.group(2)
            _row_class_bad.append(f'{_glyph} row uses class="{_rcm.group(1)}" (must be "stop-row")')
    check(
        'вҶі description and рҹ“– Wikipedia rows must use class="stop-row" '
        '(non-canonical classes like stop-desc/stop-wiki have no CSS вҶ’ broken spacing)',
        len(_row_class_bad) == 0,
        f"{len(_row_class_bad)} row(s) with wrong class: " + "; ".join(_row_class_bad[:6])
        if _row_class_bad else "",
    )

    # в”Җв”Җв”Җ рҹ“Қ ROW CLASS вҖ” bare <div>рҹ“Қ must be <div class="stop-row">рҹ“Қ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every рҹ“Қ address row inside a ticket-box or tour-box must carry
    # class="stop-row" so CSS margin rules apply. A bare classless <div>рҹ“Қ
    # has no matching CSS and renders with browser-default block spacing вҖ”
    # the same visual defect that triggered the вҶі/рҹ“– class check above.
    # Scope: any <div> with NO class attribute that leads with рҹ“Қ. Rows
    # inside transit-box / day-trips are allowed bare, but stop-level рҹ“Қ
    # rows must always have the class.
    print("\nв”Җв”Җ рҹ“Қ ROW CLASS вҖ” must be .stop-row в”Җв”Җ")
    _pin_class_bad: list[str] = []
    for _pcm in re.finditer(
        r'<div(?![^>]*\bclass\s*=)[^>]*>\s*рҹ“Қ',
        html,
    ):
        _pin_class_bad.append(f'bare рҹ“Қ row at offset {_pcm.start()}')
    check(
        'рҹ“Қ address rows must use class="stop-row" (bare <div>рҹ“Қ has no CSS вҶ’ broken spacing)',
        len(_pin_class_bad) == 0,
        f"{len(_pin_class_bad)} bare рҹ“Қ row(s) missing stop-row class: "
        + "; ".join(_pin_class_bad[:6])
        if _pin_class_bad else "",
    )

    # в”Җв”Җв”Җ вҶі ROW FORMAT вҖ” no embedded <a> links in stop description в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ вҶі STOP ROW FORMAT вҖ” no embedded links в”Җв”Җ")
    _summ_link_bad: list[str] = []
    for _slm in re.finditer(
        r'<div\b[^>]*>\s*вҶі\s*(.*?)\s*</div>', html, re.DOTALL | re.IGNORECASE
    ):
        if re.search(r'<a\b', _slm.group(1), re.IGNORECASE):
            _st = RE_STRIP_TAGS.sub( '', _slm.group(1)).strip()
            _summ_link_bad.append(f'"{_st[:80]}"')
    check(
        'вҶі stop description must be plain text вҖ” no embedded <a> links '
        '(per Icon Order and Format.html Pos 1 (outside the blue box) вҖ” description is text only)',
        len(_summ_link_bad) == 0,
        f"{len(_summ_link_bad)} вҶі row(s) with embedded links: "
        + "; ".join(_summ_link_bad[:5])
        if _summ_link_bad else "",
    )

    # в”Җв”Җв”Җ вҶі ROW FORMAT вҖ” no build annotations in stop description в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # [UPDATE], [CHECK], [TBD], рҹ”ҙ etc. in the вҶі description mean a stop shipped
    # with a builder placeholder still in it. Same pattern as stop-name annotation
    # leakage, Weekly Closures WC-ANNOT, and Cappuccino CAP-ANNOT.
    # Scoped to stop-block bodies to isolate stop-level вҶі rows.
    print("\nв”Җв”Җ вҶі STOP ROW FORMAT вҖ” no build annotations в”Җв”Җ")
    _SD_ANNOT_RE = re.compile(
        r'\[\s*(?:UPDATE|CHECK|TBD|TODO|FIXME|VERIFY|RESEARCH|PLACEHOLDER)[^\]]*\]'
        r'|\U0001f534|\U0001f7e1|\U0001f7e2',   # рҹ”ҙ рҹҹЎ рҹҹў
        re.IGNORECASE,
    )
    _sd_annot_hits: list[str] = []
    for _sdab_sb in _stop_block_bodies_desc:     # reuse stop-block bodies from length check
        for _sdab_m in re.finditer(
            r'<div\b[^>]*>\s*вҶі\s*(.*?)\s*</div>', _sdab_sb, re.DOTALL | re.IGNORECASE
        ):
            _sdab_text = RE_STRIP_TAGS.sub('', _sdab_m.group(1)).strip()
            if _SD_ANNOT_RE.search(_sdab_text):
                _sd_annot_hits.append(f'"{_sdab_text[:80]}"')
    check(
        'вҶі stop description must not contain build annotations вҖ” '
        '[UPDATE]/[CHECK]/рҹ”ҙ/[TBD] etc. must be stripped before shipping '
        '(per Icon Order and Format.html В§ 2 Pos 1 вҖ” description is shipped narrative, '
        'same rule as stop-name annotation leakage)',
        len(_sd_annot_hits) == 0,
        f"{len(_sd_annot_hits)} вҶі row(s) with build annotation: "
        + "; ".join(_sd_annot_hits[:5])
        if _sd_annot_hits else "",
    )

    # в”Җв”Җв”Җ TIME FORMAT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ TIME FORMAT в”Җв”Җ")

    # Strip tags once for all time-format checks so we don't match times
    # buried in href attributes, CSS class strings, or other HTML attributes.
    _html_text_only = RE_STRIP_TAGS.sub(' ', html)

    # Bare hours (9 am / 1 pm without :00)
    # (?<!:) prevents false-positives on minutes-inside-time (e.g. "6:10 pm"
    # previously matched "10 pm" because the colon is a word boundary).
    bare_hours = re.findall(r'(?<!:)\b([1-9]|1[0-2])\s+(?:am|pm)\b', _html_text_only)
    check(
        "No bare hours (use 9:00am, not 9 am)",
        len(bare_hours) == 0,
        f"Found bare hours: {list(set(bare_hours[:5]))}" if bare_hours else ""
    )

    # Space before am/pm вҖ” must be attached: "9:00am" not "9:00 am"
    spaced_ampm = re.findall(r'\d{1,2}:\d{2}\s+(?:am|pm)', _html_text_only, re.IGNORECASE)
    check(
        'am/pm must be attached directly to time digits вҖ” "9:00am" not "9:00 am"',
        len(spaced_ampm) == 0,
        f"{len(spaced_ampm)} occurrence(s) with space before am/pm: "
        + "; ".join(f'"{v.strip()}"' for v in spaced_ampm[:5])
        if spaced_ampm else "",
    )

    # AM/PM uppercase вҖ” \d{1,2} catches both single and double-digit hours (9, 10, 11)
    uppercase_ampm = re.findall(r'\d{1,2}:\d{2}\s*(?:AM|PM)', _html_text_only)
    check(
        "Time am/pm is lowercase (not AM/PM)",
        len(uppercase_ampm) == 0,
        f"Found uppercase: {uppercase_ampm[:3]}" if uppercase_ampm else ""
    )

    # 24-hour times вҖ” only flag when NOT followed by am/pm (those are valid 12h).
    # Strip tags and HTML comments so the validation stamp timestamp is excluded.
    _html_no_comments = RE_HTML_COMMENT.sub('', _html_text_only)
    twentyfour = re.findall(
        r'\b(?:0[0-9]|1[0-9]|2[0-3]):[0-5][0-9]\b(?!\s*[ap]m)',
        _html_no_comments,
        flags=re.IGNORECASE,
    )
    check(
        "No 24-hour times (use 12-hour format)",
        len(twentyfour) == 0,
        f"Found 24h times: {list(set(twentyfour[:5]))}" if twentyfour else ""
    )

    # в”Җв”Җв”Җ рҹҸӣ ROW FORMAT вҖ” STRICT POSITIVE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ рҹҸӣ ROW FORMAT вҖ” strict positive в”Җв”Җ")
    _WEEKDAY_PAT = r'(?:Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday)'
    _TIME_PAT    = r'\d{1,2}:\d{2}(?:am|pm)'  # no space вҖ” "9:00am" not "9:00 am"
    # Time format: am/pm attached directly to digits вҖ” no space: "9:00am"
    # Time range separator: space-hyphen-space: "9:00am - 5:00pm"
    # Day range: space-hyphen-space: "Monday - Friday" (en-dash banned, locked 2026-05-19)
    # Three valid forms: "Open 24/7", "Daily вҖҰ", "{Weekday}( - {Weekday}) вҖҰ"
    _DAY_PAT     = r'(?:Daily|' + _WEEKDAY_PAT + r'(?:\s+-\s+' + _WEEKDAY_PAT + r')?)'
    _TIME_RANGE  = _TIME_PAT + r'\s+-\s+' + _TIME_PAT
    _ONE_SEGMENT = _DAY_PAT + r'\s+' + _TIME_RANGE
    # Continuation segment: may be a full day-prefixed segment OR a bare time range
    # (implied same day вҖ” split lunch/dinner like "Daily 12:00pm - 2:30pm В· 7:00pm - 10:30pm")
    _CONT_SEG    = r'(?:' + _ONE_SEGMENT + r'|' + _TIME_RANGE + r')'
    # Full valid format: "Open 24/7" OR one or more В·-separated hour segments
    # Optional trailing parenthetical qualifier e.g. "(FriвҖ“Sat until 10:30pm)"
    # used by Option B consolidated hours rows.
    _PAREN_QUAL = r'(?:\s*\([^)]+\))?'
    _HRS_STRICT_RE = re.compile(
        r'^(?:'
        r'Open\s+24/7'
        r'|'
        + _ONE_SEGMENT
        + r'(?:\s*В·\s*' + _CONT_SEG + r')*'
        + _PAREN_QUAL
        + r')'
        + r'\s*$',
        re.IGNORECASE,
    )
    _hrs_strict_bad: list[str] = []
    for _hsfm in re.finditer(
        # Require рҹҸӣ (with optional U+FE0F variation selector) вҖ” do NOT use (?:рҹҸӣпёҸ?)
        # which makes the emoji optional and matches every div in the file.
        # Also skip extras-title divs (section headings like "рҹҸӣ What the ResearchвҖҰ").
        r'<div(?![^>]*class\s*=\s*"[^"]*extras-title[^"]*")[^>]*>\s*рҹҸӣпёҸ?\s*(.*?)\s*</div>',
        html, re.DOTALL | re.IGNORECASE
    ):
        _hs_txt = RE_STRIP_TAGS.sub( '', _hsfm.group(1)).strip()
        if not _hs_txt:
            continue
        if not _HRS_STRICT_RE.match(_hs_txt):
            _hrs_strict_bad.append(f'"{_hs_txt[:80]}"')
    check(
        'рҹҸӣ row format: must match "рҹҸӣ Open 24/7", "рҹҸӣ Daily {H:MMam} - {H:MMpm}", '
        '"рҹҸӣ {Weekday}( - {Weekday}) {H:MMam} - {H:MMpm}", or multi-segment '
        '"рҹҸӣ {segment} В· {segment} В· вҖҰ" вҖ” closed-day qualifiers belong on a рҹҡ« row, '
        'not the рҹҸӣ row '
        '(per Icon Order and Format.html Pos 2a вҖ” inside the blue box)',
        len(_hrs_strict_bad) == 0,
        f"{len(_hrs_strict_bad)} рҹҸӣ row(s) not matching strict format: "
        + "; ".join(_hrs_strict_bad[:5])
        if _hrs_strict_bad else "",
    )

    # в”Җв”Җв”Җ рҹҡ« ROW FORMAT вҖ” "Closed" must be capitalised в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every рҹҡ« row must begin "рҹҡ« Closed [Day]" вҖ” capital C.
    # Lowercase "closed" is a typo drift: "рҹҡ« closed Tuesday" fails.
    # Rule source: Icon Order and Format.html Pos 5.
    print("\nв”Җв”Җ рҹҡ« ROW FORMAT вҖ” 'Closed' must be capitalised в”Җв”Җ")
    _closed_cap_bad: list[str] = []
    for _cfm in re.finditer(
        r'<div[^>]*>\s*(рҹҡ«\s+.*?)\s*</div>',
        html, re.DOTALL | re.IGNORECASE,
    ):
        _closed_txt = RE_STRIP_TAGS.sub('', _cfm.group(1)).strip()
        if not _closed_txt:
            continue
        # Must start with "рҹҡ« Closed" (capital C) вҖ” "рҹҡ« closed" fails
        if re.match(r'^рҹҡ«\s+closed\b', _closed_txt):
            _closed_cap_bad.append(f'"{_closed_txt[:60]}"')
    check(
        'рҹҡ« row вҖ” "Closed" must be capitalised: "рҹҡ« Closed Tuesday", not "рҹҡ« closed Tuesday" '
        '(per Icon Order and Format.html Pos 3 вҖ” inside the blue box)',
        not _closed_cap_bad,
        f'{len(_closed_cap_bad)} рҹҡ« row(s) with lowercase "closed": '
        + '; '.join(_closed_cap_bad[:5])
        if _closed_cap_bad else '',
    )

    # в”Җв”Җв”Җ 3+ CONSECUTIVE рҹҸӣпёҸ ROWS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # 3 or more consecutive рҹҸӣ rows in the same entry must be consolidated into
    # an Option B row: "рҹҸӣпёҸ Daily H:MMam - H:MMpm В· вҖҰ (exception qualifier)".
    # Two or fewer consecutive rows are acceptable (e.g. MonвҖ“Sat / Sun).
    # "Consecutive" = each рҹҸӣ div starts within 400 chars of the previous one.
    print("\nв”Җв”Җ 3+ CONSECUTIVE рҹҸӣпёҸ ROWS в”Җв”Җ")
    _hrs_pos = [
        (m.start(), m.end())
        for m in re.finditer(
            r'<div(?![^>]*class\s*=\s*"[^"]*extras-title[^"]*")[^>]*>\s*рҹҸӣпёҸ?\s*.*?\s*</div>',
            html, re.DOTALL | re.IGNORECASE
        )
    ]
    _triple_hrs: list[str] = []
    _ci = 0
    while _ci < len(_hrs_pos):
        _cj = _ci + 1
        while _cj < len(_hrs_pos) and _hrs_pos[_cj][0] - _hrs_pos[_cj - 1][1] < 400:
            # Stop crossing entry-body boundaries: if there's an extras-sub or entry-body
            # opening tag between the two рҹҸӣпёҸ rows, they belong to different entries.
            _gap_html = html[_hrs_pos[_cj - 1][1]:_hrs_pos[_cj][0]]
            if re.search(r'<div\b[^>]*class\s*=\s*"[^"]*\b(?:extras-sub|entry-body)\b[^"]*"', _gap_html, re.IGNORECASE):
                break  # new entry starts here вҖ” not consecutive
            _cj += 1
        if _cj - _ci >= 3:
            _run_snippet = RE_STRIP_TAGS.sub('', html[_hrs_pos[_ci][0]:_hrs_pos[_cj-1][1]]).strip()[:100]
            _triple_hrs.append(f'"{_run_snippet}"')
        _ci = _cj if _cj > _ci else _ci + 1
    check(
        '3+ consecutive рҹҸӣпёҸ rows must be consolidated to Option B format: '
        '"рҹҸӣпёҸ Daily H:MMam - H:MMpm В· вҖҰ (exception qualifier)" '
        '(per Icon Order and Format.html)',
        len(_triple_hrs) == 0,
        f"{len(_triple_hrs)} entry/entries with 3+ consecutive рҹҸӣпёҸ rows: "
        + "; ".join(_triple_hrs[:3])
        if _triple_hrs else "",
    )

    # в”Җв”Җв”Җ рҹҸӣпёҸ VARIATION SELECTOR REQUIRED в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Hours rows must use рҹҸӣпёҸ (U+1F3DB U+FE0F) not bare рҹҸӣ (U+1F3DB alone).
    # The bare form renders inconsistently across platforms and OS versions.
    # Caught 2026-05-15: Bloom Coffee Room + Simpli Coffee (Lisbon cappuccino section).
    print("\nв”Җв”Җ рҹҸӣпёҸ VARIATION SELECTOR REQUIRED в”Җв”Җ")
    _bare_bldg_hits: list[str] = []
    for _bbm in re.finditer(
        # Match a <div> that opens with bare рҹҸӣ (U+1F3DB) NOT followed by U+FE0F.
        r'<div(?![^>]*class\s*=\s*"[^"]*extras-title[^"]*")[^>]*>\s*\U0001F3DB(?!пёҸ)',
        html, re.DOTALL | re.IGNORECASE,
    ):
        _bb_snippet = html[_bbm.start():min(len(html), _bbm.start() + 100)]
        _bb_text = RE_STRIP_TAGS.sub('', _bb_snippet).strip()[:60]
        _bare_bldg_hits.append(f'"{_bb_text}"')
    check(
        'рҹҸӣпёҸ rows must use рҹҸӣпёҸ (U+1F3DB + U+FE0F variation selector), '
        'not bare рҹҸӣ (U+1F3DB alone) вҖ” bare form renders inconsistently '
        'across platforms. (Icon Order and Format.html)',
        len(_bare_bldg_hits) == 0,
        (f'{len(_bare_bldg_hits)} row(s) with bare рҹҸӣ missing U+FE0F: '
         + '; '.join(_bare_bldg_hits[:5])) if _bare_bldg_hits else '',
    )

    # в”Җв”Җв”Җ вқ— HEADS UP GLYPH вҖ” VARIATION SELECTOR REQUIRED (everywhere) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every вқ— in a guide вҖ” the Heads Up pill label, the section title, and each
    # entry marker вҖ” must be вқ—пёҸ (U+2757 + U+FE0F). A bare вқ— (U+2757 alone) is a
    # hard fail anywhere it appears. The bare form is byte-distinct from +VS16 and
    # was the source of the title/entry/pill drift unified on 2026-06-05.
    # Decision: Dani 2026-06-05 (A4) вҖ” require +VS16 on every вқ— and fail if not.
    print("\nв”Җв”Җ вқ— HEADS UP GLYPH вҖ” VARIATION SELECTOR REQUIRED в”Җв”Җ")
    _bare_excl_hits: list[str] = []
    for _bxm in re.finditer(r'вқ—(?!пёҸ)', html):
        _bx_snippet = html[max(0, _bxm.start() - 40):_bxm.start() + 40]
        _bx_text = RE_STRIP_TAGS.sub('', _bx_snippet).strip()[:60]
        _bare_excl_hits.append(f'"{_bx_text}"')
    check(
        'вқ— must be вқ—пёҸ (U+2757 + U+FE0F variation selector) everywhere вҖ” '
        'Heads Up pill, section title, and every entry marker; bare вқ— '
        '(U+2757 alone) is a hard fail (Dani 2026-06-05; Icon Order and Format.html)',
        len(_bare_excl_hits) == 0,
        (f'{len(_bare_excl_hits)} bare вқ— missing U+FE0F: '
         + '; '.join(_bare_excl_hits[:5])) if _bare_excl_hits else '',
    )

    # в”Җв”Җв”Җ вҸі ROW вҖ” NO PROSE TAIL (standalone) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule source: Icon Order and Format.html Pos 4b
    # вҸі at position 5b (alternative to рҹҸӣ) must be exactly вҸі {duration} вҖ”
    # no prose, qualifiers, or extra notes after the duration value.
    # вҸі inside a рҹ•җ combined row starts mid-div-text (never leads a <div>) so
    # it is not matched here; those rows are caught by the рҹ•җ combined-row check.
    print("\nв”Җв”Җ вҸі ROW вҖ” no prose tail (standalone) в”Җв”Җ")
    _hg_prose_violations: list[str] = []
    _hg_row_re = re.compile(
        r'<div[^>]*>\s*вҸі\s*(.*?)\s*</div>',
        re.DOTALL | re.IGNORECASE,
    )
    # Strip all valid duration tokens; anything left = prose tail
    _hg_strip_re = re.compile(
        r'\d+(?:[.,]\d+)?'       # numbers (including decimals like 1.5)
        r'|h(?:rs?|ours?)?'      # h В· hr В· hrs В· hour В· hours
        r'|min(?:utes?)?'        # min В· mins В· minute В· minutes
        r'|[В·\s]',               # separators and whitespace
        re.IGNORECASE,
    )
    for _hgm in _hg_row_re.finditer(html):
        _hg_txt = RE_STRIP_TAGS.sub('', _hgm.group(1)).strip()
        if not _hg_txt:
            continue
        _hg_leftover = _hg_strip_re.sub('', _hg_txt).strip()
        if _hg_leftover:
            _hg_prose_violations.append(f'"{_hg_txt[:80]}"')
    check(
        'вҸі standalone rows must contain duration only вҖ” no prose tail after '
        'the duration value (per Icon Order and Format.html Pos 4b)',
        len(_hg_prose_violations) == 0,
        f"{len(_hg_prose_violations)} вҸі row(s) with prose tail: "
        + "; ".join(_hg_prose_violations[:5])
        if _hg_prose_violations else "",
    )

    # в”Җв”Җв”Җ INLINE STYLES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ INLINE STYLES в”Җв”Җ")

    inline_imgs = re.findall(r'<img\b[^>]*\bstyle\s*=', html)
    check(
        "<img> tags have no inline style attribute",
        len(inline_imgs) == 0,
        f"{len(inline_imgs)} <img> with inline style вҖ” use .stop-photos CSS class instead"
        if inline_imgs else ""
    )

    inline_wrappers = re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos\b[^"]*"[^>]*\bstyle\s*=',
        html
    )
    check(
        '<div class="stop-photos"> has no inline style attribute',
        len(inline_wrappers) == 0,
        f"{len(inline_wrappers)} .stop-photos wrapper(s) with inline style вҖ” use CSS class only"
        if inline_wrappers else ""
    )

    # в”Җв”Җв”Җ STOP TITLE SHAPE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ STOP TITLES в”Җв”Җ")

    h3_in_stop_block = []
    missing_span_pair = []
    wrong_num_format = []
    stopname_empty: list[str] = []
    stopname_inner_html: list[str] = []
    for idx, blk in enumerate(stop_blocks_raw := re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"[^>]*>(.*?)(?=<div\b[^>]*class\s*=\s*"(?:stop-block|next|next-tram|next-metro|train|day-header|day-block|extras-section)\b|<hr\b|</body>)',
        html,
        re.DOTALL,
    )):
        name_m = RE_STOP_NAME.search( blk)
        name = name_m.group(1).strip() if name_m else f"(stop #{idx + 1})"
        if re.search(r'<h3\b', blk):
            h3_in_stop_block.append(name)
        num_m = re.search(r'<span\b[^>]*class\s*=\s*"[^"]*\bstop-num\b[^"]*"[^>]*>([^<]+)</span>', blk)
        nm_m = re.search(r'<span\b[^>]*class\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>', blk)
        if not (num_m and nm_m):
            missing_span_pair.append(name)
        elif not re.fullmatch(r'\s*\d+\.\s*', num_m.group(1)):
            wrong_num_format.append(f"{name} вҶ’ '{num_m.group(1).strip()}'")

        # (E) .stop-name must be non-empty plain text.
        # Use DOTALL match to capture the full inner content including any tags.
        _sn_full_m = re.search(
            r'<span\b[^>]*class\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>(.*?)</span>',
            blk, re.DOTALL | re.IGNORECASE,
        )
        if _sn_full_m:
            _sn_raw = _sn_full_m.group(1)
            _sn_text_only = RE_STRIP_TAGS.sub('', _sn_raw).strip()
            # Empty stop name (span present, no text content).
            if not _sn_text_only:
                stopname_empty.append(f"(stop #{idx + 1})")
            # Inner HTML вҖ” any tag inside the stop-name span.
            if re.search(r'<[a-z]', _sn_raw, re.IGNORECASE):
                stopname_inner_html.append(
                    f'"{_sn_text_only[:50]}" contains inner HTML tag'
                )

    check(
        "No <h3> inside .stop-block (use .stop-num + .stop-name spans)",
        len(h3_in_stop_block) == 0,
        f"{len(h3_in_stop_block)} stop(s) with banned <h3>: {h3_in_stop_block[:5]}"
        + (" вҖҰ" if len(h3_in_stop_block) > 5 else "")
        if h3_in_stop_block else "",
    )
    check(
        "Every .stop-block has one .stop-num span and one .stop-name span",
        len(missing_span_pair) == 0,
        f"{len(missing_span_pair)} stop(s) missing the span pair: {missing_span_pair[:5]}"
        + (" вҖҰ" if len(missing_span_pair) > 5 else "")
        if missing_span_pair else "",
    )
    check(
        ".stop-num format is '{N}.' (digit + period), not 'Stop {N}'",
        len(wrong_num_format) == 0,
        f"{len(wrong_num_format)} stop(s) with wrong number format: {wrong_num_format[:5]}"
        + (" вҖҰ" if len(wrong_num_format) > 5 else "")
        if wrong_num_format else "",
    )

    # (E-i) Empty .stop-name
    check(
        ".stop-name span must have non-empty text content "
        "(per Stops Structure.html В§3 вҖ” every stop is named after the venue)",
        not stopname_empty,
        f"{len(stopname_empty)} stop(s) with blank .stop-name: "
        + "; ".join(stopname_empty[:5])
        if stopname_empty else "",
    )

    # (E-ii) No inner HTML in .stop-name вҖ” must be plain text only
    check(
        ".stop-name span contains plain text only вҖ” no inner HTML tags "
        "(<a>, <em>, <span>, <br>, etc. inside the title span are format violations)",
        not stopname_inner_html,
        f"{len(stopname_inner_html)} stop(s) with HTML inside .stop-name: "
        + "; ".join(stopname_inner_html[:5])
        if stopname_inner_html else "",
    )

    # Stop-title connector: `or`, never `+`. Per Stops Structure.html
    # "Stop-title connector: `or`, never `+`." When a stop name pairs two
    # venues, the connector is the word `or` (spaces on both sides), not the
    # `+` symbol. `+` reads as arithmetic ("do both in sequence") and
    # misrepresents stop-level semantics вҖ” Dani picks one venue or the
    # other within the time budget, or wanders freely between them. `or`
    # carries that meaning on one scannable line with no legend. The `&`
    # connector is used only in the em-dash "City вҖ” VenueA & VenueB" pattern
    # for grouped sub-components of a single destination, and is allowed
    # there; this check targets the standalone-pair case only.
    #
    # Scope covers BOTH surfaces a stop name appears:
    #   1. `.stop-name` span inside each `.stop-block` (the stop title)
    #   2. `.overview-day-stops` line inside each Trip Overview card
    # Without the second surface, the overview card can drift out of sync with
    # the stop block while the first check alone passes.
    bad_plus_connectors = []
    for blk in stop_blocks_raw:
        nm_m = re.search(
            r'<span\b[^>]*class\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>([^<]+)</span>',
            blk,
        )
        if not nm_m:
            continue
        nm_text = nm_m.group(1).strip()
        # `+` between two word-chars (allowing surrounding spaces). Hyphenated
        # venue names use `-`, not `+`, so `+` only appears as a venue
        # connector вҖ” this check has no false positives.
        if re.search(r'\w\s*\+\s*\w', nm_text):
            bad_plus_connectors.append(nm_text)

    # Overview-card inline stop lists: stops now live in the .overview-day-title
    # after the " вҖ” " separator: "Day N В· рҹҺ’ вҖ” Stop1 В· Stop2 В· Stop3".
    # The same connector rule applies вҖ” any `+` between two word-chars in
    # the stop portion is a banned pair-connector.
    bad_plus_in_overview = []
    for overview_title_m in re.finditer(
        r'<div\b[^>]*class\s*=\s*"[^"]*\boverview-day-title\b[^"]*"[^>]*>[^<]*рҹҺ’[^<]*вҖ”\s*([^<]+)</div>',
        html,
    ):
        line = overview_title_m.group(1).strip()
        if re.search(r'\w\s*\+\s*\w', line):
            bad_plus_in_overview.append(line)

    check(
        "Stop-title connector is `or`, never `+`",
        len(bad_plus_connectors) == 0 and len(bad_plus_in_overview) == 0,
        (
            f"{len(bad_plus_connectors)} stop name(s) in .stop-name spans "
            f"with banned `+` connector (use `or`): {bad_plus_connectors[:5]}"
            + (" вҖҰ" if len(bad_plus_connectors) > 5 else "")
            if bad_plus_connectors else ""
        ) + (
            (" В· " if bad_plus_connectors else "")
            + f"{len(bad_plus_in_overview)} overview-day-stops line(s) with "
            f"banned `+` connector: {bad_plus_in_overview[:3]}"
            + (" вҖҰ" if len(bad_plus_in_overview) > 3 else "")
            if bad_plus_in_overview else ""
        ),
    )

    # в”Җв”Җв”Җ STOP-TITLE ICON (type-modifier class) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    stopname_missing_modifier: list[str] = []
    stopname_multi_modifier: list[str] = []
    stopname_literal_icon: list[str] = []
    modifier_body_mismatch: list[str] = []

    # Duplicate "stop names within a day" check removed 2026-05-18 вҖ” was enforced twice.
    # Surviving copy lives below at the NO DUPLICATE STOP NAMES WITHIN A DAY section
    # (cleaner accounting, single failure per violation).

    # `train` modifier retired 2026-04-26 вҖ” Train Day is a day-level pattern,
    # not a stop type (per Day Structure.html В§ 7 / Stops Structure.html В§ 3c). Inner
    # stops on a train day are normal Self-Guided stops using the `self`
    # modifier. The рҹҡҶ glyph still appears in day-headers and Trip Overview
    # day-overview labels вҖ” but never as a stop-name modifier.
    #
    # `guided` modifier retired 2026-05-20 вҖ” the Guided Tour stop type was
    # removed from CORE RULES. Only valid modifier is `self` (рҹҺ’ Self-Guided
    # per Stops Structure.html В§2). Any .stop-name.guided class now
    # hard-fails via check (A) below вҖ” "guided" is not in MOD_CLASSES so it
    # contributes nothing to `present`, and the missing-modifier branch fires.
    # The Trip Overview section also hard-fails on .guided independently (lines ~1883).
    MOD_CLASSES = ("self",)
    # Both рҹҺҹ (bare) and рҹҺҹпёҸ (U+FE0F) are listed: a substring test against only the
    # FE0F form misses a bare рҹҺҹ typed into a stop-name. (Lane1-04 fix.)
    STOP_TYPE_ICONS = ("рҹҡ©", "рҹҺ’", "рҹҡҶ", "рҹҺҹпёҸ", "рҹҺҹ", "рҹ“…")

    # Helper used by the modifier-body mismatch check (C) below.
    # Defined once here вҖ” not inside the loop вҖ” since it closes over nothing.
    def _box_leads_with(box_class: str, icon: str, body: str) -> bool:
        """Return True when the first box of `box_class` opens with `icon`
        as its first non-whitespace content (optional inner <div> allowed)."""
        pat = (
            r'<div\b[^>]*class\s*=\s*"[^"]*\b'
            + re.escape(box_class)
            + r'\b[^"]*"[^>]*>\s*(?:<div\b[^>]*>\s*)?'
            + re.escape(icon)
        )
        return bool(re.search(pat, body))

    for idx, blk in enumerate(stop_blocks_raw):
        nm_open = re.search(
            r'<span\b[^>]*class\s*=\s*"([^"]*\bstop-name\b[^"]*)"[^>]*>([^<]*)</span>',
            blk,
        )
        if not nm_open:
            # Already reported by the span-pair check above; skip.
            continue
        cls_attr = nm_open.group(1)
        nm_text = nm_open.group(2).strip()
        label = nm_text if nm_text else f"(stop #{idx + 1})"

        # (A) Modifier-class count.
        present = [m for m in MOD_CLASSES if re.search(rf'\b{m}\b', cls_attr)]
        if len(present) == 0:
            stopname_missing_modifier.append(label)
        elif len(present) > 1:
            stopname_multi_modifier.append(f"{label} вҶ’ {'+'.join(present)}")

        # (B) No literal stop-type icon inside the .stop-name text.
        for icon in STOP_TYPE_ICONS:
            if icon in nm_text:
                stopname_literal_icon.append(f"{label} carries literal {icon}")
                break

        # (C) Modifier matches body shape.
        # The .tour-box / .ticket-box interior can either be loose text
        # with <br> separators OR nested row <div>s вҖ” both shapes ship.
        # The lead glyph (рҹ“…/рҹ“Қ/рҹҺҹпёҸ) must be the first non-whitespace
        # character after the opening box <div>, with either an optional
        # inner <div ...> open tag in between.

        if len(present) == 1:
            mod = present[0]
            has_tour_box = bool(
                re.search(r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b', blk)
            )
            has_ticket_box = bool(
                re.search(r'<div\b[^>]*class\s*=\s*"[^"]*\bticket-box\b', blk)
            )

            # в”Җв”Җ RETIRED 2026-05-25 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            # `guided` modifier branch: validated tour-box+рҹ“… shape and optional
            # ticket-box for Type 3 Alternation. Retired 2026-05-20 along with
            # the Guided Tour stop type. "guided" is no longer in MOD_CLASSES
            # so this branch can never be reached вҖ” kept as a tombstone only.
            # Any .guided stop-name now fails check (A) as "missing modifier."
            # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
            if mod == "self":
                # self is EITHER Option 1 (.tour-box containing рҹ“Қ вҖ” pure
                # walk; рҹ“Қ is the LAST row per synced 2026-05-03) OR
                # Option 2 (.ticket-box led by рҹҺҹпёҸ вҖ” ticket-gated self-walk).
                # XOR вҖ” never both. Type 3 alternation (both boxes together)
                # uses the `guided` modifier, not `self`. (D) below catches
                # the misclassification.
                #
                # 2026-05-03: Option 1 check relaxed from "led by рҹ“Қ" to
                # "contains рҹ“Қ" because the synced rule moved рҹ“Қ to the
                # bottom row of the box. The B18 row-order check enforces
                # position; this check only enforces presence.
                tb_contains_pin = has_tour_box and bool(
                    re.search(
                        r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"[^>]*>'
                        r'(?:(?!</div>\s*</div>).)*?рҹ“Қ',
                        blk, re.DOTALL,
                    )
                )
                # 2026-06-16: .tour-box for operational rows retired; now
                # individual .stop-row divs. Accept a .stop-row containing
                # рҹ“Қ as a valid self-walk shape (replaces the old self-walk box).
                # Strip ticket-box content first вҖ” a рҹ“Қ address row INSIDE a
                # ticket-box is the stop's address, not a self-walk indicator.
                # Only рҹ“Қ rows outside any box count toward shape_a.
                # Strip ticket-box blocks inline (can't call _strip_balanced_div
                # here вҖ” it's defined later in validate(); replicate the logic).
                _tbox_re = re.compile(
                    r'<div\b[^>]*class\s*=\s*"[^"]*\bticket-box\b[^"]*"[^>]*>'
                )
                _blk_no_tbox_parts: list[str] = []
                _tb_i = 0
                while _tb_i < len(blk):
                    _tm = _tbox_re.search(blk, _tb_i)
                    if not _tm:
                        _blk_no_tbox_parts.append(blk[_tb_i:])
                        break
                    _blk_no_tbox_parts.append(blk[_tb_i:_tm.start()])
                    _, _tb_end = _walk_balanced_div(blk, _tm.end())
                    _tb_i = _tb_end
                _blk_no_tbox = ''.join(_blk_no_tbox_parts)
                stoprow_contains_pin = bool(
                    re.search(
                        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-row\b[^"]*"[^>]*>[^<]*рҹ“Қ',
                        _blk_no_tbox,
                    )
                )
                shape_a = tb_contains_pin or stoprow_contains_pin
                shape_b = has_ticket_box and _box_leads_with("ticket-box", "рҹҺҹпёҸ", blk)
                if not (shape_a or shape_b):
                    modifier_body_mismatch.append(
                        f"{label} вҶ’ self, but body has neither "
                        f".tour-box containing рҹ“Қ nor .ticket-box led by рҹҺҹпёҸ"
                    )
                # (D) self never ships both shapes. Type 3 Alternation Stop
                # (both .tour-box+рҹ“Қ and .ticket-box+рҹҺҹпёҸ in the same block)
                # was retired 2026-05-20 along with the `guided` modifier.
                # A `self` stop that ships both shapes is always a fail.
                elif shape_a and shape_b:
                    modifier_body_mismatch.append(
                        f"{label} вҶ’ self, but ships BOTH .tour-box+рҹ“Қ AND "
                        f".ticket-box+рҹҺҹпёҸ (self is XOR; Type 3 alternation was "
                        f"retired 2026-05-20 along with the `guided` modifier)"
                    )
            # `train` modifier branch retired 2026-04-26 вҖ” see MOD_CLASSES
            # comment above. Train Day is a day-level pattern; inner stops
            # use the `self` modifier. Any element that still ships
            # `<span class="stop-name train">` will fail the missing-modifier
            # check (A) above вҖ” exactly the catch we want.

    check(
        'Every .stop-name carries a type-modifier class (self вҖ” only valid modifier; guided retired 2026-05-20; train retired 2026-04-26)',
        len(stopname_missing_modifier) == 0,
        f"{len(stopname_missing_modifier)} stop-name(s) with no modifier class "
        f"(icon won't render вҖ” CSS ::before is keyed off the modifier): "
        + "; ".join(stopname_missing_modifier[:5])
        + (" вҖҰ" if len(stopname_missing_modifier) > 5 else "")
        if stopname_missing_modifier else "",
    )
    check(
        'Every .stop-name carries exactly ONE type-modifier class',
        len(stopname_multi_modifier) == 0,
        f"{len(stopname_multi_modifier)} stop-name(s) with multiple modifier classes "
        f"(stylesheet stacks ::before вҖ” two icons render): "
        + "; ".join(stopname_multi_modifier[:5])
        + (" вҖҰ" if len(stopname_multi_modifier) > 5 else "")
        if stopname_multi_modifier else "",
    )
    check(
        'No literal рҹҡ© / рҹҺ’ / рҹҡҶ / рҹҺҹпёҸ / рҹ“… typed into .stop-name text (CSS renders via ::before)',
        len(stopname_literal_icon) == 0,
        f"{len(stopname_literal_icon)} stop-name(s) with hard-coded icon "
        f"(remove it вҖ” the modifier class renders the glyph): "
        + "; ".join(stopname_literal_icon[:5])
        + (" вҖҰ" if len(stopname_literal_icon) > 5 else "")
        if stopname_literal_icon else "",
    )
    check(
        'Stop-name modifier class matches body shape '
        '(selfвҶ’XOR of .tour-box containing рҹ“Қ or .ticket-box+рҹҺҹпёҸ вҖ” never both; '
        'guided modifier retired 2026-05-20; train modifier retired 2026-04-26)',
        len(modifier_body_mismatch) == 0,
        f"{len(modifier_body_mismatch)} stop(s) with modifier/body mismatch "
        f"(title says one type, body is another вҖ” classification contradiction): "
        + "; ".join(modifier_body_mismatch[:5])
        + (" вҖҰ" if len(modifier_body_mismatch) > 5 else "")
        if modifier_body_mismatch else "",
    )
    # Mutual-exclusion hard-fail removed 2026-04-25 (Type 3 Alternation was
    # briefly valid). Re-enforced 2026-05-20 via check (D) in the self branch
    # above: `self` is XOR вҖ” never both shapes. Type 3 Alternation and the
    # `guided` modifier that drove it were retired 2026-05-20. A .stop-block
    # carrying both .tour-box+рҹ“Қ and .ticket-box+рҹҺҹпёҸ now always hard-fails.

    # в”Җв”Җв”Җ NO рҹ“… INSIDE .ticket-box в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    ticket_box_with_calendar: list[str] = []
    for tb in re.finditer(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bticket-box\b[^"]*"[^>]*>(.*?)(?=<div\b[^>]*class\s*=\s*"(?:stop-photos|tour-box|stop-block|next)\b|</section|</body>)',
        html,
        re.DOTALL,
    ):
        body = tb.group(1)
        if "рҹ“…" in body:
            preceding = html[max(0, tb.start() - 600): tb.start()]
            nm = re.search(
                r'<span\b[^>]*class\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>([^<]+)</span>',
                preceding,
            )
            lbl = nm.group(1).strip() if nm else "(unlabeled ticket-box)"
            ticket_box_with_calendar.append(lbl)
    check(
        'No рҹ“… appears inside any .ticket-box (tickets lead with рҹҺҹпёҸ, never рҹ“…)',
        len(ticket_box_with_calendar) == 0,
        f"{len(ticket_box_with_calendar)} .ticket-box(es) contain рҹ“… вҖ” "
        f"skip-the-line ticket stops lead with рҹҺҹпёҸ only; рҹ“… belongs in .tour-box. "
        + "; ".join(ticket_box_with_calendar[:5])
        + (" вҖҰ" if len(ticket_box_with_calendar) > 5 else "")
        if ticket_box_with_calendar else "",
    )

    # в”Җв”Җв”Җ рҹҺҹ ROW MUST BE BOOKING LINK ONLY вҖ” no text before the link в”Җв”Җв”Җв”Җ
    _ticket_rows_with_text = []
    for _full_div in re.findall(r'<div[^>]*>\s*(?:рҹҺҹпёҸ|рҹҺҹ)\s*.*?</div>', html, re.DOTALL):
        # Skip extras-title divs (section headings use рҹҺҹпёҸ structurally, not as a booking row)
        if 'extras-title' in _full_div[:80]:
            continue
        # Extract content after the opening tag
        _div = re.sub(r'^<div[^>]*>\s*(?:рҹҺҹпёҸ|рҹҺҹ)\s*', '', _full_div, count=1)
        _div = re.sub(r'\s*</div>$', '', _div)
        # Only look at text BEFORE the first <a href вҖ” the link text itself is fine
        _before_link = re.split(r'<a\b', _div, maxsplit=1)[0]
        _before_text = RE_STRIP_TAGS.sub( '', _before_link).strip()
        if _before_text:
            _ticket_rows_with_text.append(_before_text[:70])
    check(
        'рҹҺҹ row must be booking link only вҖ” no text before the link '
        '(descriptions, genre labels, qualifiers belong in the stop paragraph above the box, '
        'not on the рҹҺҹ row; caught 2026-05-08)',
        len(_ticket_rows_with_text) == 0,
        f"Remove text from these рҹҺҹ rows (keep only the <a> link): "
        f"{_ticket_rows_with_text}" if _ticket_rows_with_text else "",
    )

    # в”Җв”Җв”Җ рҹҺҹ ROW вҖ” MUST END AT </a> в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _ticket_rows_with_tail = []
    for _full_div in re.findall(r'<div[^>]*>\s*(?:рҹҺҹпёҸ|рҹҺҹ)\s*.*?</div>', html, re.DOTALL):
        # Skip extras-title divs (рҹ“… Tours section heading uses the icon structurally,
        # not as a booking row) вҖ” mirrors the guard on the sibling check above.
        if 'extras-title' in _full_div[:80]:
            continue
        _tm = re.search(r'</a>(.*?)</div>\s*$', _full_div, re.DOTALL)
        if not _tm:
            continue
        _tail_text = RE_STRIP_TAGS.sub('', _tm.group(1)).strip()
        if _tail_text:
            _ticket_rows_with_tail.append(_tail_text[:70])
    check(
        'рҹҺҹ row must end at </a> вҖ” ( '
        'advisory text belongs on a вҡ пёҸ row вҖ” drift: "рҹҺҹ amtrak.com В· reserve a seat" 2026-05-08)',
        len(_ticket_rows_with_tail) == 0,
        f"Remove trailing text from these рҹҺҹ rows: "
        f"{_ticket_rows_with_tail}" if _ticket_rows_with_tail else "",
    )

    # в”Җв”Җв”Җ рҹҺҹ ROW вҖ” MUST NOT BE USED FOR FREE VENUES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule: рҹҶ“ is the only icon for free admission. рҹҺҹ must always be a
    # booking link. "рҹҺҹ Free вҖ” no booking needed" is a hard fail вҖ” use рҹҶ“.
    # Locked 2026-05-24 (Marrakech shows-box drift: Jemaa el-Fnaa entry)
    _ticket_free_violations: list[str] = []
    for _full_div in re.findall(r'<div[^>]*>\s*(?:рҹҺҹпёҸ|рҹҺҹ)\s*.*?</div>', html, re.DOTALL):
        if 'extras-title' in _full_div[:80]:
            continue
        _row_text = RE_STRIP_TAGS.sub('', _full_div).strip()
        # Strip the leading ticket icon
        _row_text_clean = re.sub(r'^(?:рҹҺҹпёҸ|рҹҺҹ)\s*', '', _row_text).strip()
        if re.search(r'\bfree\b|no booking|no reservation', _row_text_clean, re.IGNORECASE):
            _ticket_free_violations.append(_row_text_clean[:80])
    check(
        'рҹҺҹ must not be used for free venues вҖ” use рҹҶ“ instead; '
        '"рҹҺҹ Free вҖ” no booking needed" is always wrong (locked 2026-05-24)',
        len(_ticket_free_violations) == 0,
        f"Replace these рҹҺҹ rows with рҹҶ“ Free: {_ticket_free_violations}"
        if _ticket_free_violations else "",
    )

    # в”Җв”Җв”Җ рҹ“Қ / рҹ“– ROWS вҖ” MUST END AT </a> в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule source: Icon Order and Format.html (rows рҹ“Қ at Pos 9, рҹ“– at Pos 2 outside the blue box)
    # рҹ“Қ rows contain exactly one Google Maps link вҖ” the address IS the link text,
    # nothing should follow </a>.  рҹ“– rows contain exactly one Wikipedia link вҖ”
    # again, the link is the complete row content.  (рҹҺҹ / рҹҺ« have their own
    # dedicated tail checks above вҖ” excluded here to avoid double-reporting.)
    _icon_link_tail_violations: list[str] = []
    for _icon in ['рҹ“Қ', 'рҹ“–']:
        for _div_m in re.finditer(
            rf'<div[^>]*>\s*{re.escape(_icon)}\s*.*?</div>',
            html, re.DOTALL
        ):
            _div_raw = _div_m.group(0)
            _last_a_close = _div_raw.rfind('</a>')
            if _last_a_close == -1:
                continue  # no link in this div вҖ” skip (рҹ“– without a link is caught elsewhere)
            _after = _div_raw[_last_a_close + 4:]
            _tail_text = RE_STRIP_TAGS.sub('', _after).strip()
            if _tail_text:
                _icon_link_tail_violations.append(
                    f'{_icon} row tail: "{_tail_text[:60]}"'
                )
    check(
        'рҹ“Қ / рҹ“– rows must end at </a> вҖ” '
        '(address and Wikipedia link are the complete row content; '
        ''
        'per Icon Order and Format.html )',
        len(_icon_link_tail_violations) == 0,
        (f"{len(_icon_link_tail_violations)} row(s) with trailing text after </a>: "
         + "; ".join(_icon_link_tail_violations[:5]))
        if _icon_link_tail_violations else "",
    )

    # в”Җв”Җв”Җ рҹҺ« ROW вҖ” GLOBAL FORMAT: exactly "рҹҺ« book at: <a>site</a>" в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _ticket_fmt_errors: list[str] = []
    for _div_raw in re.findall(
        r'<div\b(?![^>]*\bextras-sub\b)[^>]*>\s*рҹҺ«(.*?)</div>', html, re.DOTALL
    ):
        _row_txt = RE_STRIP_TAGS.sub( '', _div_raw).strip()
        # (a) must have "book at:"
        _ba_match = re.search(r'book\s+at\s*:', _div_raw, re.IGNORECASE)
        if not _ba_match:
            _ticket_fmt_errors.append(f'missing "book at:": "{_row_txt[:80]}"')
            continue
        # (b) nothing before "book at:" (between рҹҺ« and "book at:")
        _before_ba = RE_STRIP_TAGS.sub( '', _div_raw[:_ba_match.start()]).strip()
        if _before_ba:
            _ticket_fmt_errors.append(
                f'text before "book at:": "{_before_ba[:60]}" вҖ” row: "{_row_txt[:80]}"'
            )
        # (c) nothing between "book at:" and <a
        _after_ba = _div_raw[_ba_match.end():]
        _before_a = re.split(r'<a\b', _after_ba, maxsplit=1)[0]
        _between_text = RE_STRIP_TAGS.sub( '', _before_a).strip()
        if _between_text:
            _ticket_fmt_errors.append(
                f'text between "book at:" and link: "{_between_text[:60]}" вҖ” row: "{_row_txt[:80]}"'
            )
        # (d) nothing after the LAST </a>
        # Day Trips rows use two links: <a>operator</a> or <a>omio</a> вҖ” both valid.
        # Check after the LAST </a> only (not the first) so the "or omio" second link
        # is allowed; the omio check separately enforces the omio link is present.
        _all_a_closes = list(re.finditer(r'</a>', _div_raw, re.IGNORECASE))
        if _all_a_closes:
            _last_close_end = _all_a_closes[-1].end()
            _tail = RE_STRIP_TAGS.sub('', _div_raw[_last_close_end:]).strip()
            if _tail:
                _ticket_fmt_errors.append(
                    f'text after booking link: "{_tail[:60]}" вҖ” row: "{_row_txt[:80]}"'
                )
    check(
        'рҹҺ« row format вҖ” must be exactly: рҹҺ« book at: <a>site</a> '
        'вҖ” nothing before "book at:", nothing between "book at:" and the link, nothing after </a> '
        '(global rule, 2026-05-10)',
        len(_ticket_fmt_errors) == 0,
        "; ".join(_ticket_fmt_errors[:4]) if _ticket_fmt_errors else "",
    )

    # в”Җв”Җв”Җ NO TICKET-SIGNAL PRODUCT INSIDE .tour-box в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    TICKET_SIGNAL_TOKENS = (
        "fast-track entry",
        "fast track entry",
        "hosted entry",
        "timed entry",
        "timed-entry",
        "rooftop pass",
        "admission",
        "ticket",  # catches "Skip-the-Line Ticket", "Museum Ticket", etc.
    )
    tour_box_with_ticket_signal: list[str] = []
    for tb in re.finditer(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"[^>]*>(.*?)(?=<div\b[^>]*class\s*=\s*"(?:stop-photos|tour-box|ticket-box|stop-block|next|tour-meet)\b|</section|</body>)',
        html,
        re.DOTALL,
    ):
        body = tb.group(1)
        # Only inspect рҹ“… rows (guided-tour product rows). Self-walk logistics
        # boxes lead with рҹ“Қ and are not products вҖ” skip them.
        if "рҹ“…" not in body:
            continue
        # Iterate rows: each <div>вҖҰ</div> (or the loose leading text before
        # the first nested <div>). We only care about the рҹ“… row, which is
        # the first visible row of a guided-tour box.
        for row_match in re.finditer(r'(?:<div\b[^>]*>|^)([^<]*рҹ“…[^<]*(?:<[^>]+>[^<]*)*?)(?=</div>|$)', body):
            row_html = row_match.group(1)
            # Strip tags to get visible text; lower-case for token match.
            row_text = RE_STRIP_TAGS.sub( ' ', row_html)
            row_text_lc = row_text.lower()
            if "рҹ“…" not in row_text_lc:
                continue
            matched = [t for t in TICKET_SIGNAL_TOKENS if t in row_text_lc]
            if not matched:
                continue
            # Label: preceding .stop-name.
            preceding = html[max(0, tb.start() - 600): tb.start()]
            nm = re.search(
                r'<span\b[^>]*class\s*=\s*"[^"]*\bstop-name\b[^"]*"[^>]*>([^<]+)</span>',
                preceding,
            )
            stop_label = nm.group(1).strip() if nm else "(unlabeled stop)"
            # Extract product name roughly вҖ” text between "рҹ“…" and the first
            # " вҖ” " or " В· " separator, or the whole row if neither present.
            prod = re.split(r'\s[вҖ”В·]\s', row_text.split("рҹ“…", 1)[1].strip(), maxsplit=1)[0].strip()
            if len(prod) > 80:
                prod = prod[:77] + "вҖҰ"
            tour_box_with_ticket_signal.append(
                f"{stop_label} вҶ’ рҹ“… row \"{prod}\" (hits: {', '.join(matched)})"
            )
    check(
        'No ticket-signal product (ticket / fast-track entry / hosted entry / '
        'timed-entry / admission / rooftop pass) inside any .tour-box '
        '(those rows belong in .ticket-box led by рҹҺҹпёҸ)',
        len(tour_box_with_ticket_signal) == 0,
        f"{len(tour_box_with_ticket_signal)} рҹ“… row(s) inside .tour-box carry "
        f"ticket-signal tokens вҖ” move to .ticket-box led by рҹҺҹпёҸ per guide-style.css .ticket-box В§: "
        + "; ".join(tour_box_with_ticket_signal[:5])
        + (" вҖҰ" if len(tour_box_with_ticket_signal) > 5 else "")
        if tour_box_with_ticket_signal else "",
    )

    # в”Җв”Җв”Җ PHOTOS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ PHOTOS в”Җв”Җ")

    # Structural presence check вҖ” every .stop-block must contain exactly one
    # .stop-photos wrapper. Without this check, stops with no photo block
    # silently slip through because older checks only validated wrappers that
    # already existed.
    #
    # Exception: a stop preceded by a <!-- no-photo: reason --> sentinel
    # (within ~400 chars before the opening <div class="stop-block">) is
    # exempt вҖ” the sentinel documents that Commons and official-site fallback
    # were both checked and came up empty. Per Photos Rules.html:
    # "Drop the .stop-photos block entirely вҖ” a stop without photo is fine;
    # a stop with a placeholder is not." Sentinel pattern mirrors tour-first
    # and meeting-point-unreachable. Without the sentinel, the missing wrapper
    # is still a hard fail вҖ” silent omission is not an accepted state.
    stop_block_iter = list(re.finditer(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"[^>]*>',
        html,
    ))
    stop_blocks_raw = re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"[^>]*>(.*?)(?=<div\b[^>]*class\s*=\s*"(?:stop-block|next|next-tram|train|day-header|day-block|extras-section)\b|<hr\b|</body>|\Z)',
        html,
        re.DOTALL,
    )
    missing_photos_blocks = []
    multi_photos_blocks = []
    for idx, blk in enumerate(stop_blocks_raw):
        name_m = RE_STOP_NAME.search( blk)
        name = name_m.group(1).strip() if name_m else "(unnamed stop)"
        wrapper_count = len(
            re.findall(
                r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos\b[^"]*"',
                blk,
            )
        )
        if wrapper_count == 0:
            # Check for <!-- no-photo: вҖҰ --> sentinel in the 400 chars before
            # this stop-block's opening tag.
            blk_start = stop_block_iter[idx].start() if idx < len(stop_block_iter) else 0
            preamble = html[max(0, blk_start - 400):blk_start]
            sentinel_ok = bool(re.search(
                r'<!--\s*no-photo\s*:.{5,}?-->',
                preamble,
                re.DOTALL,
            ))
            if not sentinel_ok:
                missing_photos_blocks.append(name)
        elif wrapper_count > 1:
            multi_photos_blocks.append((name, wrapper_count))

    check(
        "Every .stop-block contains a .stop-photos wrapper",
        len(missing_photos_blocks) == 0,
        (
            f"{len(missing_photos_blocks)} stop(s) missing photos: "
            f"{missing_photos_blocks[:5]}"
            + (" вҖҰ" if len(missing_photos_blocks) > 5 else "")
        ) if missing_photos_blocks else "",
    )
    check(
        "No .stop-block contains more than one .stop-photos wrapper",
        len(multi_photos_blocks) == 0,
        f"{len(multi_photos_blocks)} stop(s) with >1 wrapper: {multi_photos_blocks[:3]}"
        if multi_photos_blocks else "",
    )

    # в”Җв”Җв”Җ STOP-BLOCK HOURS ROW (рҹҸӣпёҸ) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every .stop-block must contain at least one рҹҸӣпёҸ row giving opening
    # hours / days.  Hard-fail вҖ” a stop without hours leaves the reader blind
    # to closures and wasted trips.
    print("\nв”Җв”Җ STOP-BLOCK вҖ” рҹҸӣпёҸ hours row required в”Җв”Җ")
    _sb_missing_hours: list[str] = []
    for _idx, _blk in enumerate(stop_blocks_raw):
        _nm = RE_STOP_NAME.search(_blk)
        _label = _nm.group(1).strip()[:70] if _nm else f"(stop #{_idx + 1})"
        if 'рҹҸӣпёҸ' not in _blk:
            _sb_missing_hours.append(_label)
    check(
        "Every .stop-block contains at least one рҹҸӣпёҸ opening-hours row",
        len(_sb_missing_hours) == 0,
        (
            f"{len(_sb_missing_hours)} stop(s) missing рҹҸӣпёҸ hours row: "
            + "; ".join(_sb_missing_hours[:5])
            + (" вҖҰ" if len(_sb_missing_hours) > 5 else "")
        ) if _sb_missing_hours else "",
    )

    # в”Җв”Җв”Җ STOP-BLOCK WALK TIME CAP (рҹҡ¶ > 44 min hard fail) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Cap is 40 min; validator gives 4 min lean (hard fail at > 44).
    # No sentinel override вҖ” always a hard fail.
    print("\nв”Җв”Җ STOP-BLOCK вҖ” walk >44 min hard cap в”Җв”Җ")
    _RE_WALK_MIN = re.compile(r'рҹҡ¶\s*(\d+)\s*min', re.IGNORECASE)
    _sb_walk_too_far: list[str] = []
    for _idx, _blk in enumerate(stop_blocks_raw):
        _nm = RE_STOP_NAME.search(_blk)
        _label = _nm.group(1).strip()[:70] if _nm else f"(stop #{_idx + 1})"
        for _wm in _RE_WALK_MIN.finditer(_blk):
            _mins = int(_wm.group(1))
            if _mins > 44:
                _sb_walk_too_far.append(f'"{_label}" ({_mins} min)')
                break  # one report per stop is enough
    check(
        "No .stop-block has a рҹҡ¶ walk time > 44 min (cap is 40 min; 4 min lean applied)",
        len(_sb_walk_too_far) == 0,
        (
            f"{len(_sb_walk_too_far)} stop(s) with walk > 44 min: "
            + "; ".join(_sb_walk_too_far[:5])
            + (" вҖҰ" if len(_sb_walk_too_far) > 5 else "")
        ) if _sb_walk_too_far else "",
    )

    # в”Җв”Җв”Җ GLOBAL WALK TIME CAP (рҹҡ¶ > 44 min hard fail вҖ” ALL sections) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Cap is 40 min; validator gives 4 min lean (hard fail at > 44).
    # Covers every section: stop-blocks, extras, stations, shows, tours, etc.
    # No sentinel override вҖ” always a hard fail. Remove the walk or use рҹҡ• only.
    print("\nв”Җв”Җ GLOBAL вҖ” walk >44 min hard cap (all sections) в”Җв”Җ")
    _global_walk_hits: list[str] = []
    for _gwm in _RE_WALK_MIN.finditer(html):
        _gmins = int(_gwm.group(1))
        if _gmins <= 44:
            continue
        # Extract a readable label вҖ” nearest extras-sub or stop name before match
        _gctx = html[max(0, _gwm.start() - 400):_gwm.start()]
        _glbl_m = re.search(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bextras-sub\b[^"]*"[^>]*>(.*?)</div>',
            _gctx, re.DOTALL,
        )
        if not _glbl_m:
            _glbl_m = RE_STOP_NAME.search(_gctx)
        _glbl = RE_STRIP_TAGS.sub('', _glbl_m.group(1)).strip()[:60] \
            if _glbl_m else '(unknown location)'
        _global_walk_hits.append(f'"{_glbl}" вҖ” рҹҡ¶ {_gmins} min')
    check(
        'Global walk cap вҖ” no рҹҡ¶ time exceeds 44 min in any section '
        '(cap is 40 min; 4 min lean applied; hard fail вҖ” remove walk or use рҹҡ• only)',
        len(_global_walk_hits) == 0,
        (
            f'{len(_global_walk_hits)} violation(s): '
            + '; '.join(_global_walk_hits[:5])
            + (' вҖҰ' if len(_global_walk_hits) > 5 else '')
        ) if _global_walk_hits else '',
    )

    wrappers = re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos\b[^"]*"[^>]*>(.*?)</div>',
        html,
        re.DOTALL,
    )

    wrong_count = []
    missing_alt = 0
    total_imgs_in_wrappers = 0

    # Per Photos Rules.html (2026-04-26): a `.stop-photos.stop-photos-empty` wrapper
    # holding the literal "No pictures found." negative-finding line is a valid
    # alternative to a wrapper holding 1 <img>. Only fire the "exactly 1 img" check
    # on wrappers that DON'T have the empty-modifier class.
    wrappers_full = re.findall(
        r'(<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos\b[^"]*"[^>]*>)(.*?)</div>',
        html,
        re.DOTALL,
    )
    # Photos Rules.html audit pass (added 2026-04-27): four content-shape checks
    # land in this same wrappers_full loop:
    #   C вҖ” <img src> starts with "_build/assets/" (positive shape вҖ” complements the
    #       wikimedia/base64/placeholder-service negative bans below)
    #   D вҖ” <img alt> doesn't start with "photo of" / "image of" / "picture of"
    #   E вҖ” <img src> filename starts with "800px-" (Harvest recipe step 6)
    #   F вҖ” .stop-photos-empty wrapper holds the literal `<em>No pictures
    #       found.</em>` (em-tag wrap, exact period вҖ” tightened from the
    #       prior substring-only check, which let bare text and other tag
    #       wraps through)
    src_not_relative: list[str] = []        # C вҖ” src does NOT start with assets/
    alt_photo_of_prefix: list[str] = []     # D вҖ” alt has banned prefix
    src_not_800px: list[str] = []           # E вҖ” filename missing 800px- prefix
    empty_wrong_format: list[int] = []      # F вҖ” empty wrapper missing <em>...</em>
    src_artwork_hits: list[str] = []        # G вҖ” filename matches artwork/painting patterns
    src_weak_filename_hits: list[str] = []  # H вҖ” weak-filename pattern (building exterior)
    empty_has_img: list[int] = []           # I вҖ” .stop-photos-empty wrapper contains an <img>
    alt_annotation_hits: list[str] = []     # J вҖ” alt text contains build annotation
    src_missing_on_disk: list[str] = []     # P вҖ” _build/assets/ file referenced but not on disk
    src_blank_on_disk: list[str] = []       # P2 вҖ” file exists but is a solid-colour placeholder
    alt_too_long: list[str] = []            # Q вҖ” WARN: alt reads like a sentence, not a subject name

    # Annotation pattern reused from alt-text check (same set as stop-name / tour-box).
    _alt_annot_re = re.compile(
        r'\[UPDATE\]|\[CHECK\]|\[TBD\]|\[FIXME\]|\[TODO\]|рҹ”ҙ|\[PLACEHOLDER\]',
        re.IGNORECASE,
    )

    # Artwork filename patterns вҖ” Wikimedia filenames for paintings, drawings,
    # engravings, and other non-photo media follow recognisable patterns:
    #   c_YYYY or c_YYYY-YY  вҶ’ "circa" date (e.g. c_1863-65)
    #   _by_                 вҶ’ artist attribution (e.g. Painting_by_Turner)
    #   keywords             вҶ’ painting/illustration/drawing/engraving/lithograph/
    #                          watercolor/aquarelle/fresco/mosaic/miniature/print
    # Root cause: Boca_do_Inferno_Cascais_c_1863-65_Joao_Cristino_da_Silva.png
    # slipped through as a valid 800px- asset because it was in assets/ with the
    # right prefix вҖ” nothing checked whether it was an actual photograph.
    # Added 2026-05-08 (Lisbon audit: 1863 painting shipped as a stop photo).
    _artwork_filename_re = re.compile(
        r'(?:'
        r'_c_\d{4}'                    # circa date: _c_1863 / _c_1863-65
        r'|_c_\d{4}-\d{2,4}'          # circa range: _c_1863-65
        r'|\bc\.\d{4}\b'              # c.1863 (dot form)
        # Medium keywords вҖ” use (?<![a-z]) / (?![a-z]) instead of \b because
        # underscores (_) are word chars in Python regex, so \b fails to fire
        # on _painting_ or _mosaic_ (common in Wikimedia filenames).
        r'|(?<![a-z])(?:painting|illustration|drawing|engraving|lithograph|'
        r'watercolor|watercolour|aquarelle|fresco|mosaic|miniature|'
        r'woodcut|etching|sketch|tapestry|illumination)(?![a-z])'
        r')',
        re.IGNORECASE,
    )
    # NOTE: "_by_" (artist attribution) was removed вҖ” it fires on common
    # photo descriptions like "Ponte_by_Night" or "View_by_the_Sea".
    # The circa-date patterns (_c_YYYY) reliably catch the real artwork case.

    # Weak-filename patterns вҖ” Wikimedia filenames containing these fragments
    # reliably indicate a building exterior or generic architectural shot rather
    # than the subject experience. Per Photos Rules.html В§ 9:
    #   Building, Main_Building вҶ’ building exterior shot
    #   Exterior, Facade/FaГ§ade вҶ’ front-of-building shot
    #   Outside, Front_view     вҶ’ architectural/entrance shot
    # A <!-- photo-ok: reason --> sentinel in the ~500 chars before the
    # .stop-photos div exempts the stop (e.g. when no better-licensed photo
    # exists, as documented in Photos Rules.html В§ 10).
    # Added 2026-05-15 (Iceland audit: Blue_Lagoon_Main_Building.JPG shipped
    # as the Blue Lagoon stop photo вҖ” a building exterior for a spa stop).
    _weak_filename_re = re.compile(
        r'(?<![a-z])(?:building|main_building|exterior|facade|fa[Г§c]ade|outside|front_view)(?![a-z])',
        re.IGNORECASE,
    )
    _photo_ok_re = re.compile(r'<!--\s*photo-ok\s*:.{5,}?-->', re.DOTALL)

    # no-photo-reason sentinel вҖ” required immediately before any .stop-photos-empty
    # div (within 600 chars).  Format: <!-- no-photo-reason: {reason вүҘ 10 chars} -->
    # Photos Rules.html В§7: a single genuinely empty stop is acceptable only when
    # accompanied by a written reason confirming Commons was fully searched.
    # Added 2026-06-20 (Dani: "the 1 empty needs to have a written reason to pass").
    _no_photo_reason_re = re.compile(
        r'<!--\s*no-photo-reason\s*:\s*.{10,}?-->',
        re.DOTALL,
    )
    empty_missing_reason: list[int] = []  # K вҖ” empty wrapper has no reason comment

    # Banned alt-text lead patterns. Anchored on string start with optional
    # leading article ("a "/"the ") so "Photo of {Venue}" / "A picture of
    # {Venue}" / "The image of {Subject}" all fire, but a real venue name
    # that legitimately contains the word (e.g. "Photographic Museum") does
    # not вҖ” the pattern requires "of" to follow the noun.
    _photo_of_prefix_re = re.compile(
        r'^\s*(?:a\s+|the\s+)?(?:photo|image|picture|pic|photograph)\s+of\b',
        re.IGNORECASE,
    )

    # Guide-level cap вҖ” at most 1 stop across the whole guide may carry the
    # "No pictures found." empty wrapper.  More than 1 means the photo-harvest
    # step was skipped or abandoned вҖ” a process violation per Photos Rules.html
    # В§ 4 ("harvest during research, not as a separate cleanup phase").
    # Empty wrappers are legitimate for individual stops where Commons genuinely
    # comes up empty, but 2+ empty stops signals the harvest was never properly
    # completed.
    # Root cause: per-stop structural checks pass when every stop has a valid
    # empty wrapper, so an all-empty guide publishes silently.
    # Added 2026-05-17. Tightened from вүӨ2 to вүӨ1 on 2026-06-20.
    _guide_empty_photo_count = sum(
        1
        for _open_tag, _inner in wrappers_full
        if RE_STOP_PHOTOS_EMPTY.search(_open_tag)
    )
    check(
        'Guide has at most 1 "No pictures found." stop (Photos Rules.html В§ 4 вҖ” harvest during research)',
        _guide_empty_photo_count <= 1,
        f'Guide contains {_guide_empty_photo_count} "No pictures found." stop(s) вҖ” '
        'maximum 1 allowed; harvest photos for the remaining stops before publishing'
        if _guide_empty_photo_count > 1 else '',
    )

    for i, (open_tag, inner) in enumerate(wrappers_full, 1):
        is_empty = bool(RE_STOP_PHOTOS_EMPTY.search(open_tag))
        if is_empty:
            # F (tightened 2026-04-27): empty wrapper must hold the literal
            # `<em>No pictures found.</em>` (em-tag wrap, exact period). Per
            # Photos Rules.html When Commons truly has nothing usable. Prior check was
            # substring-only ("No pictures found" anywhere in inner), which
            # let bare text and other tag wraps through.
            if not re.search(
                r'<em>\s*No\s+pictures\s+found\.?\s*</em>',
                inner, re.IGNORECASE,
            ):
                empty_wrong_format.append(i)
            # Also keep the prior substring sentinel firing as a fallback
            # signal in `wrong_count` so the legacy "exactly 1 img or
            # negative line" check still surfaces empty wrappers that have
            # no recognizable negative-finding text at all.
            if not re.search(r'No\s+pictures\s+found', inner, re.IGNORECASE):
                wrong_count.append((i, 0))
            # I вҖ” empty wrapper must contain ZERO <img> tags.
            # An empty wrapper that also holds an <img> is contradictory вҖ”
            # either the wrapper is empty (no photo found) or it has a photo.
            if re.search(r'<img\b', inner, re.IGNORECASE):
                empty_has_img.append(i)
            continue
        # (K populated below via raw-HTML position scan, outside this loop)
        # Standard wrapper вҖ” must contain exactly 1 <img> with non-empty alt.
        imgs = RE_IMG_TAG.findall( inner)
        total_imgs_in_wrappers += len(imgs)
        if len(imgs) != 1:
            wrong_count.append((i, len(imgs)))
        for img in imgs:
            m = re.search(r'\balt\s*=\s*"([^"]*)"', img)
            alt_val = m.group(1) if m else ""
            if not alt_val.strip():
                missing_alt += 1
            elif _photo_of_prefix_re.search(alt_val):
                # D вҖ” alt with banned "photo of"/"image of" prefix.
                alt_photo_of_prefix.append(alt_val[:60])
            # J вҖ” alt text must not contain build annotations.
            if _alt_annot_re.search(alt_val):
                alt_annotation_hits.append(alt_val[:60])
            # Q вҖ” WARN: alt reads like a full descriptive sentence rather than
            # "just the subject name" (Photos Rules.html В§8 вҖ” "short" has no
            # numeric threshold defined, so this is a warn, not a hard-fail).
            # Added 2026-07-11, audit Gap 9.
            if alt_val.strip() and (
                len(alt_val.strip().split()) > 6
                or len(alt_val) > 40
                or re.search(r'[.!?]', alt_val)
            ):
                alt_too_long.append(alt_val[:60])

            sm = re.search(r'\bsrc\s*=\s*"([^"]*)"', img)
            src_val = sm.group(1) if sm else ""
            if src_val:
                # C вҖ” src must start with the relative `_build/assets/` path.
                # Remote URLs (http/https) and data: URIs are violations
                # of C as well, but the dedicated wikimedia/base64/
                # placeholder-service bans below already report those вҖ”
                # exclude them here to avoid double-reporting. C catches
                # the residue: absolute paths (`/Users/...`), sibling-
                # folder paths (`../assets/...`), other CDNs, etc.
                if not src_val.startswith(('_build/assets/', 'data:', 'http://', 'https://')):
                    src_not_relative.append(src_val[:80])
                if src_val.startswith('_build/assets/'):
                    # P вҖ” file must exist on disk (guide shipped without photos = 404)
                    _disk_path = Path(filename).parent / src_val
                    if not _disk_path.exists():
                        src_missing_on_disk.append(src_val.rsplit('/', 1)[-1])
                    else:
                        # P2 вҖ” file exists but may be a solid-colour placeholder
                        # (commons_photo.py download silently saved a blue/grey JPEG)
                        try:
                            from PIL import Image as _PILImage, ImageStat as _PILStat
                            import statistics as _pstats
                            _pimg = _PILImage.open(_disk_path)
                            _pbands = _pimg.split()
                            _psd = max(_pstats.stdev(list(_b.getdata())) for _b in _pbands)
                            if _psd < 10:
                                src_blank_on_disk.append(src_val.rsplit('/', 1)[-1])
                        except Exception:
                            pass  # PIL unavailable or unreadable вҖ” skip silently
                    # E вҖ” Commons thumbnails ship as 800px-{Filename}.
                    base = src_val.rsplit('/', 1)[-1]
                    if not base.startswith('800px-'):
                        src_not_800px.append(base[:60])
                    # G вҖ” filename must not match artwork/painting patterns.
                    # A Wikimedia filename for a painting typically contains a
                    # circa date (_c_1863), an artist attribution (_by_),  or
                    # a medium keyword (painting/illustration/engravingвҖҰ).
                    # These slip past C/E because they ARE in assets/ with the
                    # 800px- prefix вҖ” only the filename content reveals the
                    # non-photo nature. (Surfaced 2026-05-08: Boca do Inferno
                    # shipped an 1863 painting instead of a real photo.)
                    if _artwork_filename_re.search(base):
                        src_artwork_hits.append(base[:80])

    # H вҖ” weak-filename detection (position-aware, separate pass).
    # wrappers_full carries no offset info, so we re-scan the HTML to locate
    # each .stop-photos div and check the 500 chars before it for a sentinel.
    for _wm in re.finditer(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos\b[^"]*"[^>]*>.*?</div>',
        html,
        re.DOTALL,
    ):
        _wsrc = re.search(r'\bsrc\s*=\s*"([^"]*)"', _wm.group(0))
        if not _wsrc:
            continue
        _wval = _wsrc.group(1)
        if not _wval.startswith('_build/assets/'):
            continue
        _wbase = _wval.rsplit('/', 1)[-1]
        if not _weak_filename_re.search(_wbase):
            continue
        # Weak filename вҖ” check for photo-ok sentinel in preceding 500 chars.
        _wpre = html[max(0, _wm.start() - 500):_wm.start()]
        if not _photo_ok_re.search(_wpre):
            src_weak_filename_hits.append(_wbase[:80])

    # в”Җв”Җв”Җ PHOTOS вҖ” K: populate empty_missing_reason via raw-HTML position scan в”Җв”Җ
    # Scan every .stop-photos-empty div position in the raw HTML and check
    # whether a <!-- no-photo-reason: {вүҘ10 chars} --> comment appears in the
    # 600 chars immediately before it.  Uses finditer so the empty-wrapper index
    # is independent of the all-wrappers `i` counter above.
    # Added 2026-06-20 (Dani: "the 1 empty needs to have a written reason to pass").
    _empty_div_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos-empty\b[^"]*"'
    )
    for _k_idx, _km in enumerate(_empty_div_re.finditer(html), 1):
        _preceding = html[max(0, _km.start() - 600):_km.start()]
        if not _no_photo_reason_re.search(_preceding):
            empty_missing_reason.append(_k_idx)

    check(
        "Every .stop-photos wrapper contains exactly 1 <img> tag (or .stop-photos-empty negative-finding line)",
        len(wrong_count) == 0,
        f"{len(wrong_count)} wrapper(s) off-count (wrapper#, imgs): {wrong_count[:3]}"
        if wrong_count else ""
    )

    check(
        "Every <img> inside .stop-photos has a non-empty alt attribute",
        missing_alt == 0,
        f"{missing_alt} of {total_imgs_in_wrappers} photo(s) missing/empty alt"
        if missing_alt else ""
    )

    # в”Җв”Җв”Җ PHOTOS вҖ” CONTENT SHAPE (Photos Rules.html) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    check(
        '<img src> inside .stop-photos starts with "_build/assets/" (Photos Rules.html Storage вҖ” relative path)',
        len(src_not_relative) == 0,
        (f"{len(src_not_relative)} <img> src(s) not under _build/assets/ "
         f"(remote URLs / absolute paths / sibling-folder paths slip past "
         f"the wikimedia/base64/placeholder-service bans): {src_not_relative[:3]}")
        if src_not_relative else "",
    )
    check(
        '<img alt> inside .stop-photos does not start with "photo of"/"image of"/"picture of" (Photos Rules.html Alt text вҖ” "Just the subject name. No \'photo of\' prefix.")',
        len(alt_photo_of_prefix) == 0,
        (f"{len(alt_photo_of_prefix)} alt(s) with banned prefix: "
         f"{alt_photo_of_prefix[:3]}")
        if alt_photo_of_prefix else "",
    )
    if alt_too_long:
        warn(
            f'{len(alt_too_long)} <img alt> inside .stop-photos reads like a full '
            f'sentence rather than just the subject name '
            f'(Photos Rules.html Alt text вҖ” "short, plain, just the subject name")',
            detail=f"{alt_too_long[:3]}",
            tag='alt-text-too-long',
        )
    check(
        '<img src> filename starts with "800px-" (Photos Rules.html Harvest recipe step 6 вҖ” preserve the 800px-{Filename} thumb)',
        len(src_not_800px) == 0,
        (f"{len(src_not_800px)} <img> filename(s) without 800px- prefix "
         f"(Commons canonical thumb resolution is locked at 800px): "
         f"{src_not_800px[:3]}")
        if src_not_800px else "",
    )
    check(
        '.stop-photos-empty wrapper holds the literal <em>No pictures found.</em> (Photos Rules.html When Commons truly has nothing usable)',
        len(empty_wrong_format) == 0,
        (f"{len(empty_wrong_format)} empty wrapper(s) with wrong format "
         f"(missing <em>...</em> wrap or period; wrapper#): {empty_wrong_format[:3]}")
        if empty_wrong_format else "",
    )

    check(
        'Photo filenames must not match artwork/painting patterns вҖ” no paintings, '
        'illustrations, engravings, or circa-dated Wikimedia files '
        '(stop photos must be real photographs, not artwork)',
        len(src_artwork_hits) == 0,
        (f"{len(src_artwork_hits)} photo(s) appear to be artwork, not photographs "
         f"(filename contains circa date, artist attribution, or medium keyword): "
         f"{src_artwork_hits[:3]}")
        if src_artwork_hits else "",
    )
    check(
        'Photo filenames must not contain weak-filename patterns (Building, Exterior, '
        'Facade, Outside, Front_view) without a <!-- photo-ok: reason --> sign-off вҖ” '
        'building exteriors are a last resort for non-architectural stops '
        '(Photos Rules.html В§ 9)',
        len(src_weak_filename_hits) == 0,
        (f"{len(src_weak_filename_hits)} photo(s) with weak-filename pattern "
         f"(replace with a better candidate, or add <!-- photo-ok: no better-licensed "
         f"alternative found for {{stop name}} --> before the stop-photos div): "
         f"{src_weak_filename_hits[:3]}")
        if src_weak_filename_hits else "",
    )

    # в”Җв”Җв”Җ PHOTOS вҖ” P: PHOTO FILES MUST EXIST ON DISK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # A guide can pass all path-shape checks (src starts with _build/assets/,
    # 800px- prefix, no artwork) while the files were never actually downloaded
    # вҖ” every img 404s on the live site. Check that each referenced file is
    # physically present next to the guide HTML. (Added 2026-06-26.)
    check(
        'Every photo referenced in _build/assets/ must exist on disk вҖ” '
        'missing files = broken images on the live site '
        '(run commons_photo.py --download for each missing file)',
        len(src_missing_on_disk) == 0,
        (f"{len(src_missing_on_disk)} photo file(s) missing from _build/assets/: "
         f"{src_missing_on_disk[:5]}")
        if src_missing_on_disk else "",
    )
    check(
        'Photo files in _build/assets/ must not be solid-colour placeholders вҖ” '
        'stddev < 10 = blank/blue placeholder saved instead of real photo '
        '(commons_photo.py download failed silently; re-run --download with correct Commons filename)',
        len(src_blank_on_disk) == 0,
        (f"{len(src_blank_on_disk)} photo file(s) are solid-colour placeholders (blue boxes on site): "
         f"{src_blank_on_disk[:5]}")
        if src_blank_on_disk else "",
    )

    # в”Җв”Җв”Җ PHOTOS вҖ” I: NO <img> INSIDE .stop-photos-empty в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # An empty wrapper that also contains an <img> is structurally contradictory.
    # Per Photos Rules.html В§ 6 the empty wrapper holds only the negative-finding
    # <em> line вҖ” no image tag. Added 2026-05-17.
    check(
        '.stop-photos-empty wrapper must contain no <img> tag вҖ” '
        'empty wrapper holds only <em>No pictures found.</em> (Photos Rules.html В§ 6)',
        len(empty_has_img) == 0,
        f'{len(empty_has_img)} .stop-photos-empty wrapper(s) contain an <img> tag '
        f'(wrapper#): {empty_has_img[:5]} вҖ” remove either the <img> or the empty class'
        if empty_has_img else '',
    )

    # в”Җв”Җв”Җ PHOTOS вҖ” K: no-photo-reason COMMENT REQUIRED в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every .stop-photos-empty wrapper must be preceded (within 600 chars) by a
    # <!-- no-photo-reason: {reason вүҘ 10 chars} --> comment confirming that
    # Commons was fully searched.  Photos Rules.html В§7 (Dani 2026-06-20:
    # "the 1 empty needs to have a written reason to pass").
    # If the stop genuinely has no Commons photo and the reason comment is present,
    # the guide-level cap (вүӨ1 empty) enforces that only one such stop per guide
    # may ship; a second empty requires the stop to be replaced entirely.
    # Added 2026-06-20.
    check(
        'Every "No pictures found." stop must be preceded by '
        '<!-- no-photo-reason: {reason} --> confirming Commons was fully searched '
        '(Photos Rules.html В§7)',
        len(empty_missing_reason) == 0,
        f'{len(empty_missing_reason)} "No pictures found." stop(s) missing the '
        f'<!-- no-photo-reason: reason --> sentinel (wrapper#): {empty_missing_reason[:5]} вҖ” '
        'add <!-- no-photo-reason: no suitable licensed photo found on Commons for {stop name} --> '
        'immediately before the <div class="stop-photos stop-photos-empty"> line'
        if empty_missing_reason else '',
    )

    # в”Җв”Җв”Җ PHOTOS вҖ” J: NO BUILD ANNOTATIONS IN alt TEXT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # [TODO], [UPDATE], [CHECK], [TBD], рҹ”ҙ etc. must be stripped before
    # shipping вҖ” same annotation-leakage rule as stop-name / tour-box / alt text.
    # Added 2026-05-17.
    check(
        'No build annotations in <img alt> text вҖ” [TODO], [UPDATE], [CHECK], рҹ”ҙ etc. '
        'must be stripped before shipping (same rule as stop-name annotation leakage)',
        len(alt_annotation_hits) == 0,
        f'{len(alt_annotation_hits)} <img> alt(s) contain build annotations: '
        + '; '.join(f'"{h}"' for h in alt_annotation_hits[:3])
        if alt_annotation_hits else '',
    )

    # в”Җв”Җв”Җ PHOTOS вҖ” K: NO DUPLICATE src FILENAMES ACROSS STOPS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Two stops sharing the same photo file is almost always a copy-paste
    # mistake вҖ” each stop needs its own unique Wikimedia image.
    # Added 2026-05-17.
    _src_to_wrappers: dict[str, list[int]] = {}
    for _di, (_dopen, _dinner) in enumerate(wrappers_full, 1):
        if RE_STOP_PHOTOS_EMPTY.search(_dopen):
            continue
        _dsm = re.search(r'\bsrc\s*=\s*"([^"]*)"', _dinner)
        if _dsm:
            _src_to_wrappers.setdefault(_dsm.group(1), []).append(_di)
    _dup_srcs = {k: v for k, v in _src_to_wrappers.items() if len(v) > 1}
    check(
        'No duplicate photo src filenames across stops вҖ” each stop needs its own unique photo',
        not _dup_srcs,
        f'{len(_dup_srcs)} duplicate src(s): '
        + '; '.join(f'"{k.rsplit("/", 1)[-1]}" used at wrapper#{v}' for k, v in list(_dup_srcs.items())[:3])
        if _dup_srcs else '',
    )

    # в”Җв”Җв”Җ PLACEHOLDER PHOTO SERVICES (Photos Rules.html вҖ” forbidden) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    placeholder_hits = re.findall(
        r'<img\b[^>]*\bsrc\s*=\s*"[^"]*\b(picsum\.photos|placehold\.co|placeholder\.com|loremflickr\.com|source\.unsplash\.com)\b[^"]*"',
        html,
        flags=re.IGNORECASE,
    )
    check(
        "No placeholder-photo services in <img> src (picsum/placehold/etc.)",
        len(placeholder_hits) == 0,
        f"{len(placeholder_hits)} placeholder src(s) found: {list(set(placeholder_hits))[:3]}"
        if placeholder_hits else ""
    )

    # в”Җв”Җв”Җ BASE64 DATA URLS (not allowed in dev artifact) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    data_uri_imgs = re.findall(r'<img\b[^>]*\bsrc\s*=\s*"data:image/', html)
    check(
        'No base64 "data:image/" src in <img> (dev guide uses relative _build/assets/ paths)',
        len(data_uri_imgs) == 0,
        f"{len(data_uri_imgs)} <img> with data: URL вҖ” use relative _build/assets/ path instead"
        if data_uri_imgs else ""
    )

    # в”Җв”Җв”Җ BANNED TOUR-PLATFORM CITY-LANDING PATTERNS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    viator_city = re.findall(r'https?://(?:www\.)?viator\.com/(?:[^"\s]+/)?d\d+-ttd\b', html, re.IGNORECASE)
    viator_no_ttd = re.findall(
        r'https?://(?:www\.)?viator\.com/(?!tours/)(?:[^"\s]+/)?d\d+\b(?!-)',
        html, re.IGNORECASE
    )
    gyg_city = re.findall(r'https?://(?:www\.)?getyourguide\.com/[A-Za-z0-9\-]+-l\d+/?(?=["\s])', html, re.IGNORECASE)
    banned_hits = viator_city + viator_no_ttd + gyg_city
    check(
        "No city-landing tour links (viator /d\\d+-ttd or /d\\d+ bare, getyourguide /l\\d+/)",
        len(banned_hits) == 0,
        f"{len(banned_hits)} city-landing link(s): {banned_hits[:3]}"
        if banned_hits else ""
    )

    # в”Җв”Җв”Җ WIKIMEDIA HOTLINKS (Rule: photos must ship locally) в”Җв”Җв”Җв”Җ
    # Sentinel exemption removed 2026-05-31: commons_photo.py --download fetches
    # the original file and resizes with PIL, bypassing the CDN thumbnail 400.
    # The `<!-- hotlink: CDN download blocked in Cowork sandbox -->` comment no
    # longer authorises a hotlink вҖ” ALL upload.wikimedia.org src values fail.
    wikimedia_hotlinks = re.findall(
        r'<img\b[^>]*\bsrc\s*=\s*"(https?://upload\.wikimedia\.org/[^"]*)"',
        html, re.IGNORECASE,
    )
    check(
        "No Wikimedia hotlinks in <img> src вҖ” use commons_photo.py --download to fetch locally (Photos Rules.html В§5)",
        len(wikimedia_hotlinks) == 0,
        f"{len(wikimedia_hotlinks)} hotlink(s) to upload.wikimedia.org вҖ” run: "
        f"python3 Brain/scripts/commons_photo.py --download Guides/{{City}}/_build/assets/800px-Foo.jpg \"File:Foo.jpg\""
        if wikimedia_hotlinks else ""
    )

    # в”Җв”Җв”Җ ANY OTHER EXTERNAL HOTLINKS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Catches http/https URLs not already covered by the Wikimedia check or the
    # placeholder-service ban. All photos must be local вҖ” no hotlinking to
    # restaurant sites, Google Images, CDNs, or any other external source.
    _ALREADY_CAUGHT_DOMAINS = (
        'upload.wikimedia.org',          # Wikimedia check above
        'picsum.photos', 'placehold.co', # placeholder-service check below
        'placeholder.com', 'loremflickr.com', 'source.unsplash.com',
    )
    _other_hotlinks = [
        url for url in re.findall(
            r'<img\b[^>]*\bsrc\s*=\s*"(https?://[^"]*)"',
            html, re.IGNORECASE,
        )
        if not any(d in url for d in _ALREADY_CAUGHT_DOMAINS)
    ]
    check(
        'No external hotlinks in <img> src вҖ” all photos must be local files '
        'in _build/assets/ (photos must be downloaded, not hotlinked from '
        'external sites, restaurant pages, CDNs, or any other remote source)',
        len(_other_hotlinks) == 0,
        f"{len(_other_hotlinks)} external hotlink(s) found вҖ” download and store locally: "
        + "; ".join(u[:80] for u in _other_hotlinks[:3])
        if _other_hotlinks else "",
    )

    # в”Җв”Җв”Җ ASSETS ON DISK (Photos Rules.html Storage) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _guide_dir = None  # set inside `if filename:` below; default None so downstream `if _guide_dir:` is safe
    if filename:
        _guide_dir = Path(filename).resolve().parent
        _assets_dir = _guide_dir / "_build" / "assets"
        if _assets_dir.is_dir():
            missing_assets: list[str] = []
            for (open_tag, inner) in wrappers_full:
                if RE_STOP_PHOTOS_EMPTY.search(open_tag):
                    continue
                for img in RE_IMG_TAG.findall( inner):
                    sm = re.search(r'\bsrc\s*=\s*"([^"]+)"', img)
                    if not sm:
                        continue
                    src_val = sm.group(1)
                    # Only check relative paths under assets/. Remote URLs
                    # and data: URIs already fail the dedicated bans above.
                    if not src_val.startswith('_build/assets/'):
                        continue
                    asset_path = (_guide_dir / src_val).resolve()
                    if not asset_path.is_file():
                        missing_assets.append(src_val[:80])
            check(
                'Every <img src="_build/assets/..."> resolves to a real file on disk (Photos Rules.html Storage)',
                len(missing_assets) == 0,
                (f"{len(missing_assets)} referenced asset(s) missing from disk "
                 f"(<img src> exists in HTML but the file under Guides/{{City}}/_build/assets/ "
                 f"does not): {missing_assets[:3]}")
                if missing_assets else "",
            )

            # Magic-byte check вҖ” every referenced asset file is a valid image.
            # Drift class (added 2026-04-27): an earlier guide build silently
            # saved Wikimedia error pages (HTML, ~2KB) with `.jpg`/`.png`
            # extensions because the download script didn't verify the
            # response. The file existed, the file-on-disk check passed, but
            # the bytes weren't an image вҖ” the browser rendered a broken-image
            # icon. Fix at the validator layer: every referenced
            # asset's first 8 bytes must match a recognized image magic
            # signature (JPEG: FF D8 FF В· PNG: 89 50 4E 47 0D 0A 1A 0A В· GIF:
            # 47 49 46 38 В· WebP container check via RIFF + WEBP). Bytes that
            # start with `<` are HTML вҖ” the most common silent-failure mode.
            broken_images: list[str] = []
            for (open_tag, inner) in wrappers_full:
                if RE_STOP_PHOTOS_EMPTY.search(open_tag):
                    continue
                for img in RE_IMG_TAG.findall( inner):
                    sm = re.search(r'\bsrc\s*=\s*"([^"]+)"', img)
                    if not sm:
                        continue
                    src_val = sm.group(1)
                    if not src_val.startswith('_build/assets/'):
                        continue
                    asset_path = (_guide_dir / src_val).resolve()
                    if not asset_path.is_file():
                        continue  # already flagged by missing_assets check
                    try:
                        head = asset_path.read_bytes()[:12]
                    except OSError:
                        broken_images.append(f"{src_val[:60]} (unreadable)")
                        continue
                    is_jpeg = head[:3] == b'\xff\xd8\xff'
                    is_png = head[:8] == b'\x89PNG\r\n\x1a\n'
                    is_gif = head[:6] in (b'GIF87a', b'GIF89a')
                    is_webp = head[:4] == b'RIFF' and head[8:12] == b'WEBP'
                    if not (is_jpeg or is_png or is_gif or is_webp):
                        # Identify the most likely failure mode for the message
                        if head[:1] == b'<':
                            why = "HTML (likely a Wikimedia 404/error page saved with an image extension)"
                        else:
                            why = f"unrecognized format, magic={head[:8].hex()}"
                        broken_images.append(f"{src_val[:60]} ({why})")
            check(
                'Every <img src="_build/assets/..."> file is a valid image (JPEG/PNG/GIF/WebP magic-byte check, per Photos Rules.html вҖ” catches silent-download-failure drift)',
                len(broken_images) == 0,
                (f"{len(broken_images)} broken image file(s) on disk вҖ” exists "
                 f"but bytes aren't an image: " + "; ".join(broken_images[:3]))
                if broken_images else "",
            )

    # в”Җв”Җв”Җ IMAGE MINIMUM DIMENSIONS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ IMAGE MINIMUM DIMENSIONS (max(w,h) вүҘ 250 px) в”Җв”Җ")
    _tiny_images: list[str] = []
    try:
        from PIL import Image as _PIL_Image   # type: ignore
        _pil_available = True
    except ImportError:
        _pil_available = False

    if _guide_dir:
        for (open_tag, inner) in wrappers_full:
            if RE_STOP_PHOTOS_EMPTY.search(open_tag):
                continue
            for img in RE_IMG_TAG.findall( inner):
                sm = re.search(r'\bsrc\s*=\s*"([^"]+)"', img)
                if not sm:
                    continue
                src_val = sm.group(1)
                if not src_val.startswith('_build/assets/'):
                    continue
                asset_path = (_guide_dir / src_val).resolve()
                if not asset_path.is_file():
                    continue  # already flagged by file-on-disk check
                w, h = 0, 0
                if _pil_available:
                    try:
                        with _PIL_Image.open(asset_path) as _im:
                            w, h = _im.size
                    except Exception:
                        continue  # unreadable вҖ” magic-byte check already flags it
                else:
                    # Struct fallback: PNG only (most common failure format).
                    try:
                        _hdr = asset_path.read_bytes()[:24]
                    except OSError:
                        continue
                    if _hdr[:8] == b'\x89PNG\r\n\x1a\n':
                        import struct as _struct
                        w, h = _struct.unpack('>II', _hdr[16:24])
                    else:
                        continue  # JPEG/WebP parsing skipped without PIL
                # Portrait photos (e.g. 394Г—525) are real images вҖ” only tiny in
                # BOTH dimensions signals a placeholder. Use max(w,h) < 250.
                if w > 0 and h > 0 and max(w, h) < 250:
                    _tiny_images.append(
                        f"{src_val[:60]} ({w}Г—{h} px вҖ” likely placeholder)"
                    )
        check(
            'Every <img src="_build/assets/..."> has at least one dimension вүҘ 250 px вҖ” '
            'images where max(width, height) < 250 are almost certainly download-failure '
            'placeholders (e.g. 60Г—60 PNG icons). Real guide photos are always much larger. '
            'Caught 2026-05-08.',
            len(_tiny_images) == 0,
            (f"{len(_tiny_images)} image(s) below minimum size: "
             + "; ".join(_tiny_images[:5]))
            if _tiny_images else "",
        )

    # в”Җв”Җв”Җ MEETING-POINT INSIDE EVERY GUIDED-TOUR BOX в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    def _strip_balanced_div(text, start_tag_re):
        """Remove <div class="..."> blocks that may contain nested <div>s."""
        out = []
        i = 0
        while i < len(text):
            m = start_tag_re.search(text, i)
            if not m:
                out.append(text[i:])
                break
            out.append(text[i:m.start()])
            _, end = _walk_balanced_div(text, m.end())
            i = end
        return ''.join(out)

    stop_block_open = re.compile(r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"[^>]*>')
    tour_box_open = re.compile(r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"[^>]*>')
    # ticket-box (any ticket: skip-the-line / timed-entry / hosted-entry /
    # fast-track / admission / rooftop pass, etc.). Stop-level рҹ“Қ/вҸ°/рҹҸӣпёҸ checks
    # must strip both tour-box AND ticket-box content: a self-guided Shape-B
    # stop legitimately carries a рҹ“Қ and вҸ° inside its ticket-box per profile
    # В§Self-Guided Stop (Shape B). Counting those as "stop-level" would
    # false-fail every ticket-gated stop.
    ticket_box_open = re.compile(r'<div\b[^>]*class\s*=\s*"[^"]*\bticket-box\b[^"]*"[^>]*>')
    stop_starts = [m.start() for m in stop_block_open.finditer(html)]

    # Bound each stop block with the next natural boundary so the LAST
    # stop doesn't slurp the end-of-itinerary extras sections
    # (#shows / #michelin etc.) вҖ” those contain their own рҹ“Қ lines inside
    # .shows-box / .entry-body which are valid but would otherwise
    # show up as "stop-level рҹ“Қ" hits on the final stop.
    _boundary_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\b(?:stop-block|next|next-tram|next-metro|hotel-first|arrive-first|train|day-header|day-block|extras-section)\b|<hr\b|</body',
        re.IGNORECASE,
    )
    def _stop_end(i: int) -> int:
        start_search = stop_starts[i] + 1   # skip past this stop's own opening tag
        m = _boundary_re.search(html, start_search)
        return m.start() if m else len(html)
    stop_ends = [_stop_end(i) for i in range(len(stop_starts))]

    stop_level_lifts = 0       # guided stop with a рҹ“Қ outside the tour-boxes
    boxes_missing_pin = 0      # individual рҹ“… tour-box with no рҹ“Қ inside
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]

        # Collect all tour-boxes that carry рҹ“… (guided tours only).
        # .ticket-box (any ticket) uses a separate class вҖ” not collected here.
        guided_boxes = []   # list of inner-HTML strings
        for tb in tour_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tb.end())
            if 'рҹ“…' in inner[:200]:
                guided_boxes.append(inner)

        # Skip stops with no guided tour boxes (self-guided and skip-the-line).
        if not guided_boxes:
            continue

        # Rule A: no stop-level рҹ“Қ outside the tour/ticket boxes. Ticket-gated
        # stops legitimately carry a рҹ“Қ inside their .ticket-box вҖ” strip both
        # box classes before scanning (the tour-box+ticket-box mutual-exclusion
        # check elsewhere will hard-fail any stop that ships both, so this
        # strip is defense-in-depth only).
        block_outside_boxes = _strip_balanced_div(block, tour_box_open)
        block_outside_boxes = _strip_balanced_div(block_outside_boxes, ticket_box_open)
        if 'рҹ“Қ' in block_outside_boxes:
            stop_level_lifts += 1

        # Rule B: every рҹ“… tour-box must carry its own рҹ“Қ line.
        for inner in guided_boxes:
            if 'рҹ“Қ' not in inner:
                boxes_missing_pin += 1

    check(
        "All guided stops have NO stop-level рҹ“Қ (meeting point lives inside each tour box)",
        stop_level_lifts == 0,
        f"{stop_level_lifts} guided stop-block(s) have a stop-level рҹ“Қ outside the tour boxes"
        if stop_level_lifts else ""
    )
    check(
        "Every рҹ“… tour-box carries its own рҹ“Қ meeting point",
        boxes_missing_pin == 0,
        f"{boxes_missing_pin} рҹ“… tour-box(es) missing an internal рҹ“Қ line"
        if boxes_missing_pin else ""
    )

    # в”Җв”Җв”Җ GUIDED STOP TOUR-COUNT CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    thin_tour_stops: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        guided_count = sum(
            1 for tb in tour_box_open.finditer(block)
            if 'рҹ“…' in _walk_balanced_div(block, tb.end())[0][:200]
        )
        if guided_count == 0:
            continue   # not a guided stop
        if guided_count >= 3:
            continue   # meets the target
        # Sentinel: <!-- tour-count-ok: reason --> suppresses when research is exhausted
        _tc_ok_m = re.search(r'<!--\s*tour-count-ok\s*:([^>]*?)-->', block, re.IGNORECASE)
        if _tc_ok_m and _tc_ok_m.group(1).strip():
            continue  # documented exhaustion вҖ” suppress
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        missing = 3 - guided_count
        thin_tour_stops.append(
            f'{label} ({guided_count} box{"es" if guided_count != 1 else ""}'
            f' вҖ” {missing} more needed)'
        )

    if thin_tour_stops:
        warn(
            f"{len(thin_tour_stops)} guided stop(s) have fewer than 3 tour-boxes "
            f"вҖ” target is 3; keep searching Viator / GYG / TripAdvisor if possible",
            "; ".join(thin_tour_stops[:5]),
        )

    # в”Җв”Җв”Җ STOPS PER DAY вҖ” floor вүҘ4 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Rule source: Day Structure.html вҖ” full day вүҘ4 stops.
    # Hard-fails when any day block has fewer than 4 stop-blocks (B3 audit fix
    # 2026-06-19 вҖ” was a warn; Index documents this as an enforced hard fail).
    # Sentinel-aware: <!-- day-count: N вҖ” reason --> with a recognised carve-out
    # keyword suppresses this check (same keyword list as the phase-4 check).
    print("\nв”Җв”Җ STOPS PER DAY вҖ” floor вүҘ4 в”Җв”Җ")
    _thin_days: list[str] = []
    _day_block_open_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bday-block\b[^"]*"[^>]*>',
        re.IGNORECASE,
    )
    _stop_block_count_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-block\b[^"]*"',
        re.IGNORECASE,
    )
    _dc_carveout_kw = [
        'half', 'train', 'tour-anchor', 'tour anchor', 'conference',
        'arrival', 'departure', 'one tour', 'full-day tour', 'full day tour',
        'single-venue', 'single venue', 'disney',
        'distant', 'far', 'all-day', 'all day',  # distant/all-day stop sets the day's pace (Day Structure В§ 6)
    ]
    for _dbm in _day_block_open_re.finditer(html):
        _day_inner, _ = _walk_balanced_div(html, _dbm.end())
        _hdr_m = re.search(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bday-header\b[^"]*"[^>]*>([^<]+)<',
            _day_inner,
        )
        _day_label = _hdr_m.group(1).strip()[:60] if _hdr_m else '(unknown day)'
        _stop_count = len(_stop_block_count_re.findall(_day_inner))
        if _stop_count < 4:
            # Check for a valid day-count sentinel before flagging
            _dc_sent_m = re.search(
                r'<!--\s*day-count\s*:([^>-][^>]*?)-->',
                _day_inner,
                re.IGNORECASE | re.DOTALL,
            )
            if _dc_sent_m:
                _sent_body = _dc_sent_m.group(1).lower()
                if any(kw in _sent_body for kw in _dc_carveout_kw):
                    continue  # valid sentinel вҖ” suppress
            _thin_days.append(
                f'"{_day_label}" ({_stop_count} stop{"s" if _stop_count != 1 else ""})'
            )
    check(
        'Stops per day вүҘ4 вҖ” every full day must have at least 4 stops '
        '(Day Structure.html В§5; suppress with <!-- day-count: N вҖ” reason --> '
        'containing a carve-out keyword)',
        not _thin_days,
        f"{len(_thin_days)} day(s) with fewer than 4 stops: "
        + "; ".join(_thin_days[:5])
        if _thin_days else '',
    )

    # в”Җв”Җв”Җ TOTAL TOUR BOXES IN GUIDE вҖ” must have at least one в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Catches guides where the crib skipped tour research entirely.
    # Accepts EITHER old-format .tour-box divs (stop-block guided tours, retired 2026-05-20)
    # OR new flat-format extras-sub entries inside the #tours extras-section.
    # Fixed 2026-05-30: old check only counted .tour-box which always fires 0 on new-format
    # guides where guided stops were retired and Tours section uses flat extras-sub entries.
    print("\nв”Җв”Җ TOTAL TOUR BOXES вҖ” guide must have at least one в”Җв”Җ")
    _total_tour_boxes = len(re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"', html, re.IGNORECASE
    ))
    # Also count flat-format extras-sub entries in the #tours section
    _tours_sec_m2 = re.search(
        r'<div\b(?=[^>]*\bextras-section\b)(?=[^>]*\bid\s*=\s*"tours")[^>]*>',
        html, re.IGNORECASE,
    )
    _flat_tour_entries = 0
    if _tours_sec_m2:
        _tours_inner2, _ = _walk_balanced_div(html, _tours_sec_m2.end())
        _flat_tour_entries = len(re.findall(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bextras-sub\b[^"]*"[^>]*>',
            _tours_inner2, re.IGNORECASE,
        ))
    _total_tours_evidence = _total_tour_boxes + _flat_tour_entries
    check(
        'Guide must contain at least one рҹ“… tour-box вҖ” zero tour boxes means '
        'tour-first research was skipped entirely (Tours - Extra Section.html)',
        _total_tours_evidence >= 1,
        f"Guide has zero tour-boxes and no flat-format Tours section entries вҖ” "
        f"Viator / GYG / TripAdvisor tour research is required before shipping"
        if _total_tours_evidence == 0 else "",
    )

    # в”Җв”Җв”Җ TOTAL TICKET BOXES IN GUIDE вҖ” must have at least one в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Every guide should ship at least one skip-the-line / timed-entry ticket.
    # If none exist, the builder must document why with <!-- no-skip-the-line: reason -->.
    # Hard fail when zero ticket-boxes AND no explanatory comment.
    print("\nв”Җв”Җ TOTAL TICKET BOXES вҖ” guide must have at least one в”Җв”Җ")
    _total_ticket_boxes = len(re.findall(
        r'<div\b[^>]*class\s*=\s*"[^"]*\bticket-box\b[^"]*"', html, re.IGNORECASE
    ))
    _stl_comment = bool(re.search(r'<!--\s*no-skip-the-line\s*:', html, re.IGNORECASE))
    if _total_ticket_boxes == 0 and not _stl_comment:
        check(
            'Guide must contain at least one рҹҺҹ ticket-box (skip-the-line / timed-entry / '
            'hosted-entry ticket) вҖ” if no qualifying ticket exists for any stop, '
            'add <!-- no-skip-the-line: reason --> explaining why (Tickets.html)',
            False,
            'Guide has zero ticket-boxes and no <!-- no-skip-the-line: reason --> comment вҖ” '
            'research skip-the-line options for every stop; if genuinely none exist, '
            'add <!-- no-skip-the-line: reason --> to document why',
        )
    else:
        check(
            'Guide must contain at least one рҹҺҹ ticket-box (skip-the-line / timed-entry), '
            'or explain absence with <!-- no-skip-the-line: reason --> (Tickets.html)',
            True,
        )

    # в”Җв”Җв”Җ TOUR-BOX CLASS INTEGRITY CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    bad_tour_box: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        for tb in tour_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tb.end())
            first = RE_STRIP_TAGS.sub( '', inner[:300]).strip()
            full_text = RE_STRIP_TAGS.sub( '', inner).strip()
            # Valid:
            #   - Type 1 Guided: leads with рҹ“… (anywhere in head window)
            #   - Type 2 Option 1 self-walk: рҹ“Қ anywhere in the box
            #     (B18 row-order check enforces it lands in the last row)
            # Invalid:
            #   - leads with рҹҺҹпёҸ (belongs in .ticket-box)
            #   - neither рҹ“… nor рҹ“Қ anywhere in the box
            if first.startswith('рҹҺҹпёҸ'):
                bad_tour_box.append(label)
                break
            if 'рҹ“…' not in first[:50] and 'рҹ“Қ' not in full_text:
                bad_tour_box.append(label)
                break   # one report per stop
    if bad_tour_box:
        check(
            ".tour-box classes used correctly (Type 1 Guided leads with рҹ“…; "
            "Type 2 Option 1 self-walk contains рҹ“Қ вҖ” last row per )",
            False,
            f"{len(bad_tour_box)} stop(s) have a .tour-box that does not lead with рҹ“… "
            f"(Type 1 Guided) and contains no рҹ“Қ (Type 2 Option 1 self-walk) вҖ” "
            f"рҹҺҹпёҸ-led belongs in .ticket-box: " + "; ".join(bad_tour_box[:5]),
        )
    else:
        check(
            ".tour-box classes used correctly (Type 1 Guided leads with рҹ“…; "
            "Type 2 Option 1 self-walk contains рҹ“Қ вҖ” last row per )",
            True,
        )

    # в”Җв”Җв”Җ TICKET-BOX CLASS INTEGRITY CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    bad_ticket_box: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        for tb in ticket_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tb.end())
            first = RE_STRIP_TAGS.sub( '', inner[:300]).strip()
            if 'рҹҺҹпёҸ' not in first[:50]:
                bad_ticket_box.append(label)
                break   # one report per stop
    if bad_ticket_box:
        check(
            ".ticket-box classes used correctly (every ticket-box leads with рҹҺҹпёҸ)",
            False,
            f"{len(bad_ticket_box)} stop(s) have a .ticket-box without рҹҺҹпёҸ вҖ” "
            f"every .ticket-box must lead with рҹҺҹпёҸ (any ticket category): "
            + "; ".join(bad_ticket_box[:5]),
        )
    else:
        check(".ticket-box classes used correctly (every ticket-box leads with рҹҺҹпёҸ)", True)

    # Ticket rows (any category) use `.ticket-box`, not `.tour-box`.
    # Detection signal: a `.tour-box` that contains a рҹҺҹпёҸ row anywhere
    # inside. Per guide-style.css .ticket-box В§ (two-booking-box rule), a рҹҺҹпёҸ row
    # belongs in a `.ticket-box` вҖ” mixing it into a `.tour-box` breaks
    # the class separation. The .tour-box integrity check above catches
    # рҹҺҹпёҸ as the LEAD of a .tour-box; this check catches рҹҺҹпёҸ as any ROW
    # inside a .tour-box.
    tour_box_with_ticket_row: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        for tb in tour_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tb.end())
            if 'рҹҺҹпёҸ' in inner:
                tour_box_with_ticket_row.append(label)
                break
    if tour_box_with_ticket_row:
        check(
            "Ticket rows live in .ticket-box, never in .tour-box",
            False,
            f"{len(tour_box_with_ticket_row)} stop(s) have a .tour-box containing a "
            f"рҹҺҹпёҸ row вҖ” move the ticket row into a .ticket-box per guide-style.css .ticket-box В§: "
            + "; ".join(tour_box_with_ticket_row[:5]),
        )
    else:
        check("Ticket rows live in .ticket-box, never in .tour-box", True)

    # в”Җв”Җв”Җ TOUR-BOX RATING AND PLATFORM CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    rating_re = re.compile(r'\d\.\d\s*[вҳ…вӯҗ]')
    tour_platforms = ('viator', 'getyourguide', 'tripadvisor', 'klook')
    tb_missing_rating: list[str] = []
    tb_missing_platform: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        accepted_platforms = tour_platforms
        for tb in tour_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tb.end())
            if 'рҹ“…' not in inner[:200]:
                continue   # not a guided tour box вҖ” skip
            text = RE_STRIP_TAGS.sub( '', inner)
            # URLs in <a href="..."> are stripped by the tag-strip above,
            # but the visible link text often carries the operator domain.
            # Scan visible text for known tour platforms.
            text_lc = text.lower()
            if not rating_re.search(text):
                tb_missing_rating.append(label)
            if not any(p in text_lc for p in accepted_platforms):
                tb_missing_platform.append(label)
    check(
        "Every рҹ“… tour-box carries a star rating (e.g. 4.5вҳ…)",
        len(tb_missing_rating) == 0,
        f"{len(tb_missing_rating)} tour-box(es) missing a star rating: "
        + "; ".join(tb_missing_rating[:5]) if tb_missing_rating else "",
    )
    check(
        "Every рҹ“… tour-box names the booking platform "
        "(Viator / GetYourGuide / TripAdvisor / Klook)",
        len(tb_missing_platform) == 0,
        f"{len(tb_missing_platform)} tour-box(es) missing platform name: "
        + "; ".join(tb_missing_platform[:5]) if tb_missing_platform else "",
    )

    # в”Җв”Җв”Җ BARE рҹ“… OUTSIDE .tour-box CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    bare_calendar_stops: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        # Build a mask of which byte offsets in `block` fall inside a .tour-box.
        covered: list[tuple[int, int]] = []
        for tb in tour_box_open.finditer(block):
            inner, consumed = _walk_balanced_div(block, tb.end())
            # `consumed` is the absolute end offset in `block` (not relative to
            # tb.end()) вҖ” _walk_balanced_div returns (inner_text, abs_end_pos).
            # Inclusive span: from the opening <div ...> to just past the closing </div>
            covered.append((tb.start(), consumed))
        # Find every рҹ“… position in the stop block.
        for cm in re.finditer(r'рҹ“…', block):
            pos = cm.start()
            inside_tour_box = any(lo <= pos < hi for lo, hi in covered)
            if not inside_tour_box:
                bare_calendar_stops.append(label)
                break   # one report per stop
    check(
        'Every рҹ“… tour block is wrapped in <div class="tour-box"> (no bare рҹ“… outside a .tour-box)',
        len(bare_calendar_stops) == 0,
        f"{len(bare_calendar_stops)} stop(s) have a рҹ“… tour outside any .tour-box wrapper "
        f"(renders uncolored, breaks visual uniformity): "
        + "; ".join(bare_calendar_stops[:5]) if bare_calendar_stops else "",
    )

    # в”Җв”Җв”Җ BARE рҹҺҹпёҸ OUTSIDE .ticket-box CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    bare_ticket_stops: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"
        # Build a mask of which byte offsets in `block` fall inside a .ticket-box.
        covered: list[tuple[int, int]] = []
        for tb in ticket_box_open.finditer(block):
            inner, consumed = _walk_balanced_div(block, tb.end())
            # `consumed` is the absolute end offset in `block` вҖ” not relative to
            # tb.end(). Adding tb.end() would double-count and inflate hi to ~2Г—
            # the actual end, making every рҹҺҹпёҸ appear "inside" a ticket-box.
            covered.append((tb.start(), consumed))
        # Find every рҹҺҹпёҸ position in the stop block.
        for cm in re.finditer(r'рҹҺҹпёҸ?', block):
            pos = cm.start()
            inside_ticket_box = any(lo <= pos < hi for lo, hi in covered)
            if not inside_ticket_box:
                bare_ticket_stops.append(label)
                break  # one report per stop
    check(
        'Every рҹҺҹпёҸ skip-the-line ticket row is wrapped in <div class="ticket-box"> (no bare рҹҺҹпёҸ outside a .ticket-box, regardless of stop type)',
        len(bare_ticket_stops) == 0,
        f"{len(bare_ticket_stops)} stop(s) have a рҹҺҹпёҸ skip-the-line row outside any .ticket-box wrapper "
        f"(renders browser-default, breaks visual uniformity): "
        + "; ".join(bare_ticket_stops[:5]) if bare_ticket_stops else "",
    )

    # в”Җв”Җв”Җ INLINE STYLE ON .tour-box CHECK в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    tour_box_with_style_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"[^>]*\bstyle\s*=',
        re.IGNORECASE,
    )
    inline_styled_tour_boxes = tour_box_with_style_re.findall(html)
    check(
        '<div class="tour-box"> has no inline style attribute',
        len(inline_styled_tour_boxes) == 0,
        f"{len(inline_styled_tour_boxes)} .tour-box(es) with inline style вҖ” "
        f"overrides the palette and breaks tour-color uniformity; use CSS class only",
    )

    # в”Җв”Җв”Җ NESTED TOUR-BOXES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ NESTED TOUR-BOXES в”Җв”Җ")
    _nested_tb_bad: list[str] = []
    for _ntm in re.finditer(r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"[^>]*>', html, re.IGNORECASE):
        _tb_start = _ntm.end()
        # Walk forward to find this tour-box's closing </div> (balanced)
        _depth = 1
        _pos = _tb_start
        while _pos < len(html) and _depth > 0:
            _next_open  = html.find('<div', _pos)
            _next_close = html.find('</div', _pos)
            if _next_open == -1:
                _next_open = len(html)
            if _next_close == -1:
                _next_close = len(html)
            if _next_open < _next_close:
                _depth += 1
                _pos = _next_open + 4
            else:
                _depth -= 1
                _pos = _next_close + 5
        _tb_body = html[_tb_start:_pos]
        if re.search(r'<div\b[^>]*class\s*=\s*"[^"]*\btour-box\b[^"]*"', _tb_body, re.IGNORECASE):
            # Find nearby stop name for context
            _before = html[max(0, _ntm.start() - 400):_ntm.start()]
            _name_m = re.findall(r'class="stop-name[^"]*">([^<]+)<', _before)
            _label  = _name_m[-1].strip() if _name_m else "unknown stop"
            _nested_tb_bad.append(f'"{_label}"')
    check(
        'tour-boxes must be flat siblings вҖ” never nested (double blue bar = missing </div> after tour-meet)',
        len(_nested_tb_bad) == 0,
        f"{len(_nested_tb_bad)} stop(s) with nested tour-box: " + "; ".join(_nested_tb_bad[:5]),
    )

    # в”Җв”Җв”Җ TOUR-BOX HARDENING BATCH в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    tb_name_not_linked: list[str] = []       # рҹ“… not immediately followed by <a>
    tb_lead_multi_link: list[str] = []       # рҹ“… lead row has >1 <a> (platform must be plain text)
    tb_missing_clock: list[str] = []         # no рҹ•җ in box
    tb_missing_hourglass: list[str] = []     # no вҸі in box
    tb_missing_group: list[str] = []         # no рҹ‘Ҙ in box
    tb_price_leak: list[str] = []            # $/вӮ¬/ВЈ/ВҘ or "per person" in box
    tb_count_missing: list[str] = []         # no "N+ reviews" pattern
    tb_count_unrounded: list[str] = []       # has digits+reviews but not rounded
    tb_dup_url: list[str] = []               # two boxes in same stop вҶ’ same URL
    tb_dup_address: list[str] = []           # two boxes in same stop вҶ’ same рҹ“Қ
    tb_has_wiki: list[str] = []              # рҹ“– link inside tour-box
    tb_has_summary: list[str] = []           # вҶі stop description row inside tour-box
    tb_has_stop_photos: list[str] = []       # .stop-photos div inside tour-box
    tb_not_encapsulated: list[str] = []      # рҹ“… lead row has text after </a> (operator/rating outside link)
    tb_link_format_bad: list[str] = []       # рҹ“… link text doesn't end with В· N.Nвҳ… В· N+ reviews
    tb_name_not_strong: list[str] = []       # рҹ“… tour name not wrapped in <strong> inside the <a>

    price_re = re.compile(r'[\$вӮ¬ВЈВҘ]')
    # Rounded review-count: digits immediately before "+ reviews" must end
    # in 0 (rounded down to nearest 10 for <100, nearest 100 for вүҘ100).
    # Accepts "10+", "20+", "90+", "100+", "2,100+", "10,000+". Per profile
    # line 893 (rounded-down-plus signals "at least this many" without false
    # precision); refined 2026-04-26 to handle small counts (<100) cleanly.
    rounded_count_re = re.compile(
        r'(?:\b\d{1,3}(?:,\d{3})*0\+|\b\d*0\+)\s*reviews',
        re.IGNORECASE,
    )
    # Any review-count mention at all (for "present-but-unrounded" check).
    any_count_re = re.compile(r'\d[\d,]*\+?\s*reviews', re.IGNORECASE)
    # Tour name hyperlink: рҹ“… followed (possibly with whitespace) by <a.
    name_link_re = re.compile(r'рҹ“…\s*<a\b', re.IGNORECASE)
    # Extract href values from anchors inside a tour-box (for dup-URL).
    href_re = re.compile(r'<a\b[^>]*\bhref\s*=\s*"([^"]+)"', re.IGNORECASE)
    # Extract the address text inside the рҹ“Қ Google-Maps anchor.
    # Pattern: рҹ“Қ ... <a ...>ADDRESS</a>. The address is everything between
    # the first > after рҹ“Қ and the matching </a>.
    pin_addr_re = re.compile(
        r'рҹ“Қ\s*<a\b[^>]*>([^<]+)</a>',
        re.IGNORECASE,
    )

    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        _nm = RE_STOP_NAME.search(block)
        label = _nm.group(1).strip()[:70] if _nm else "(unnamed stop)"

        urls_this_stop: list[str] = []
        addrs_this_stop: list[str] = []

        for tb in tour_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tb.end())
            # Only run the рҹ“…-specific checks on guided tour boxes.
            if 'рҹ“…' not in inner[:200]:
                continue

            text = RE_STRIP_TAGS.sub( '', inner)

            # Tour name hyperlink.
            if not name_link_re.search(inner):
                tb_name_not_linked.append(label)

            # Lead row must contain exactly ONE <a> link (the tour name).
            # Drift class: a second link gets added for the venue site (e.g.
            # `рҹ“… <a>Tour Name</a> вҖ” <a>venue.org</a> В· Platform 4.5вҳ… ...`).
            # The platform name must be plain text, never a hyperlink.
            _cal_pos = inner.find('рҹ“…')
            if _cal_pos != -1:
                _lead_end = inner.find('</div>', _cal_pos)
                _lead_html = inner[_cal_pos:_lead_end] if _lead_end != -1 else inner[_cal_pos:_cal_pos + 500]
                if len(re.findall(r'<a\b', _lead_html, re.IGNORECASE)) > 1:
                    tb_lead_multi_link.append(label)

            # Logistics trio.
            if 'рҹ•җ' not in text:
                tb_missing_clock.append(label)
            if 'вҸі' not in text:
                tb_missing_hourglass.append(label)
            if 'рҹ‘Ҙ' not in text:
                tb_missing_group.append(label)

            # Review count вҖ” rounded and present.
            if not any_count_re.search(text):
                tb_count_missing.append(label)
            elif not rounded_count_re.search(text):
                tb_count_unrounded.append(label)

            # Price leak.
            if price_re.search(text):
                tb_price_leak.append(label)

            # Stop-level elements inside a tour-box вҖ” wrong location.
            if 'рҹ“–' in text:
                tb_has_wiki.append(label)
            if 'вҶі' in text:
                tb_has_summary.append(label)
            if re.search(r'class\s*=\s*"[^"]*\bstop-photos\b', inner):
                tb_has_stop_photos.append(label)

            # Encapsulation check: operator В· rating В· reviews must be INSIDE
            # the <a> tag on the рҹ“… row вҖ” not trailing after </a>.
            # Correct:  рҹ“… <a href="...">Tour Name В· Viator В· 4.7вҳ… В· 900+ reviews</a>
            # Broken:   рҹ“… <a href="...">Tour Name</a> В· Viator В· 4.7вҳ… В· 900+ reviews
            # Per Tours - Extra Section.html (locked 2026-05-19, Tours.html retired 2026-05-20).
            _cal_pos_enc = inner.find('рҹ“…')
            if _cal_pos_enc != -1:
                _lead_end_enc = inner.find('</div>', _cal_pos_enc)
                _lead_html_enc = inner[_cal_pos_enc:_lead_end_enc] if _lead_end_enc != -1 else inner[_cal_pos_enc:_cal_pos_enc + 600]
                # After the last </a> in the рҹ“… row, there must be no non-whitespace text.
                _after_close_a = re.split(r'</a>', _lead_html_enc, maxsplit=1)
                if len(_after_close_a) == 2 and re.search(r'\S', _after_close_a[1]):
                    tb_not_encapsulated.append(label)

                # <strong> presence: tour name must be wrapped in <strong> inside the <a>.
                # Correct:  рҹ“… <a href="..."><strong>Tour Name</strong> В· Viator В· 4.7вҳ… В· 900+ reviews</a>
                # Wrong:    рҹ“… <a href="...">Tour Name В· Viator В· 4.7вҳ… В· 900+ reviews</a>
                # Per guide-style.css locked 2026-05-19: .tour-box a font-weight:normal, only <strong> is bold.
                _a_raw_m = re.search(r'<a\b[^>]*>(.*?)</a>', _lead_html_enc, re.IGNORECASE | re.DOTALL)
                if _a_raw_m:
                    _a_raw_inner = _a_raw_m.group(1).strip()
                    if not re.match(r'<strong\b', _a_raw_inner, re.IGNORECASE):
                        _a_plain = RE_STRIP_TAGS.sub('', _a_raw_inner).strip()
                        tb_name_not_strong.append(f'{label}: "{_a_plain[:60]}"')

                # Link text strict format: must end with "В· N.N[вҳ…вӯҗ] В· N+ reviews"
                # and carry вүҘ2 В· separators (Title В· Operator В· Rating В· Reviews).
                # NOTE: uses (.*?) + tag-strip so <strong>-wrapped names are also checked.
                # Correct:  Small Group Rome Tour В· Viator В· 4.7вҳ… В· 900+ reviews
                # Wrong:    Small Group Rome Tour В· Viator В· 4.7вҳ… (missing reviews)
                # Wrong:    Small Group Rome Tour В· Viator 4.7вҳ… В· 900+ reviews (missing В· before rating)
                # Wrong:    Small Group Rome Tour В· Viator В· 4.7вҳ… В· 900+ reviews В· free cancellation (trailing text)
                _tlt_m = re.search(r'<a\b[^>]*>(.*?)</a>', _lead_html_enc, re.IGNORECASE | re.DOTALL)
                if _tlt_m:
                    _tlt = RE_STRIP_TAGS.sub('', _tlt_m.group(1)).strip()
                    _tlt_ok = bool(
                        re.search(r'В·\s+\d+\.\d[вҳ…вӯҗ]\s+В·\s+\d[\d,]*\+\s*reviews\s*$', _tlt, re.IGNORECASE)
                        and _tlt.count('В·') >= 2
                    )
                    if not _tlt_ok:
                        tb_link_format_bad.append(f'{label}: "{_tlt[:80]}"')

            # Collect booking URL (first <a href> after рҹ“…) for dup-URL check.
            # The рҹ“… line format: рҹ“… <a href="{booking URL}">{tour name}</a>.
            cal_pos = inner.find('рҹ“…')
            if cal_pos != -1:
                m = href_re.search(inner, cal_pos)
                if m:
                    urls_this_stop.append(m.group(1))

            # Collect рҹ“Қ address text for dup-address check.
            pm = pin_addr_re.search(inner)
            if pm:
                addrs_this_stop.append(pm.group(1).strip().lower())

        # Intra-stop duplicate detection.
        if len(urls_this_stop) != len(set(urls_this_stop)):
            # Suppress if author documented the shared URL is intentional.
            # Use sentinel: <!-- shared-booking-ok: reason --> inside or just before the block.
            preceding_block = html[max(0, s - 300):s]
            if '<!-- shared-booking-ok:' not in block and '<!-- shared-booking-ok:' not in preceding_block:
                tb_dup_url.append(label)
        if len(addrs_this_stop) != len(set(addrs_this_stop)):
            # Suppress if author documented the shared address is intentional.
            # Check both inside the block and in the 300 chars immediately
            # preceding it (same convention as inclusion-bar sentinels).
            preceding_block = html[max(0, s - 300):s]
            if '<!-- shared-address-ok:' not in block and '<!-- shared-address-ok:' not in preceding_block:
                tb_dup_address.append(label)

    check(
        'Every рҹ“… tour-box has its tour name hyperlinked (рҹ“… <a>Tour Name</a>)',
        len(tb_name_not_linked) == 0,
        f"{len(tb_name_not_linked)} tour-box(es) with a bare-text tour name "
        f"(Tours - Extra Section.html вҖ” tour name format: рҹ“… [Tour Name](link)): " + "; ".join(tb_name_not_linked[:5]),
    )
    check(
        'рҹ“… tour-box lead row has exactly one <a> link вҖ” platform name is plain text, not a hyperlink '
        '(drift: second link added for venue site, e.g. `рҹ“… <a>Tour</a> вҖ” <a>venue.org</a> В· Platform 4.5вҳ…`)',
        len(tb_lead_multi_link) == 0,
        f"{len(tb_lead_multi_link)} tour-box(es) with multiple links in the рҹ“… lead row "
        f"(only the tour name is hyperlinked; platform is plain text): "
        + "; ".join(tb_lead_multi_link[:5]),
    )
    check(
        'рҹ“… lead row fully encapsulated вҖ” operator В· rating В· reviews inside the <a> tag '
        '(broken: `рҹ“… <a>Name</a> В· Viator В· 4.7вҳ…`; correct: `рҹ“… <a>Name В· Viator В· 4.7вҳ…</a>`; '
        'per Tours - Extra Section.html locked 2026-05-19)',
        len(tb_not_encapsulated) == 0,
        f"{len(tb_not_encapsulated)} tour-box(es) with operator/rating outside the <a> tag: "
        + "; ".join(tb_not_encapsulated[:5]) if tb_not_encapsulated else "",
    )
    check(
        'рҹ“… link text must end with "В· N.N[вҳ…/вӯҗ] В· N+ reviews" and carry вүҘ2 В· separators '
        '(format: Title В· Operator В· 4.7вҳ… В· 900+ reviews вҖ” no trailing text, no missing В· before rating) '
        '(per Tours - Extra Section.html)',
        len(tb_link_format_bad) == 0,
        f"{len(tb_link_format_bad)} рҹ“… link(s) with wrong text format: "
        + "; ".join(tb_link_format_bad[:5]) if tb_link_format_bad else "",
    )
    check(
        'рҹ“… tour name must be wrapped in <strong> inside the <a> link вҖ” bare text fails '
        '(correct: `рҹ“… <a><strong>Tour Name</strong> В· Viator В· 4.7вҳ… В· 900+ reviews</a>`; '
        'per guide-style.css locked 2026-05-19: only <strong> is bold inside .tour-box a)',
        len(tb_name_not_strong) == 0,
        f"{len(tb_name_not_strong)} рҹ“… link(s) missing <strong> wrapper on tour name: "
        + "; ".join(tb_name_not_strong[:5]) if tb_name_not_strong else "",
    )
    check(
        'Every рҹ“… tour-box carries рҹ•җ start time',
        len(tb_missing_clock) == 0,
        f"{len(tb_missing_clock)} tour-box(es) missing рҹ•җ: " + "; ".join(tb_missing_clock[:5]),
    )

    # в”Җв”Җв”Җ рҹ•җ START-TIME FORMAT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _clock_fmt_re = re.compile(r'^\d{1,2}:\d{2}(?:am|pm)$')  # attached: "9:00am" not "9:00 am"
    _clock_row_re = re.compile(
        r'<div[^>]*>\s*рҹ•җ\s*(.*?)\s*</div>',
        re.DOTALL | re.IGNORECASE,
    )
    _clock_fmt_bad: list[str] = []
    for _cm in _clock_row_re.finditer(html):
        _full = RE_STRIP_TAGS.sub( '', _cm.group(1)).strip()
        # Only check the segment before the first В· separator
        _time_seg = _full.split(' В· ')[0].strip()
        if not _clock_fmt_re.match(_time_seg):
            _clock_fmt_bad.append(_time_seg[:60])
    check(
        'рҹ•җ start-time format: H:MMam or H:MMpm only вҖ” attached, lowercase, nothing else before the В· separator',
        len(_clock_fmt_bad) == 0,
        f"{len(_clock_fmt_bad)} рҹ•җ row(s) with wrong format: "
        + "; ".join(f'"{v}"' for v in _clock_fmt_bad[:5]),
    )

    # в”Җв”Җв”Җ рҹ•җ COMBINED ROW вҖ” вҸі AND рҹ‘Ҙ MUST BE ON THE SAME DIV в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _clock_combined_bad: list[str] = []
    for _cm2 in _clock_row_re.finditer(html):
        _full2 = RE_STRIP_TAGS.sub( '', _cm2.group(1)).strip()
        _segs = [s.strip() for s in _full2.split(' В· ')]
        # Check вҸі is present after рҹ•җ on same row
        _has_hourglass = any(s.startswith('вҸі') for s in _segs[1:])
        # Check рҹ‘Ҙ is present after вҸі on same row
        _has_group = any(s.startswith('рҹ‘Ҙ') for s in _segs[1:])
        # Check order: вҸі must come before рҹ‘Ҙ
        _hg_idx = next((i for i, s in enumerate(_segs) if s.startswith('вҸі')), None)
        _gp_idx = next((i for i, s in enumerate(_segs) if s.startswith('рҹ‘Ҙ')), None)
        _order_ok = (_hg_idx is not None and _gp_idx is not None and _hg_idx < _gp_idx)
        if not _has_hourglass or not _has_group or not _order_ok:
            _reason = []
            if not _has_hourglass: _reason.append('missing вҸі')
            if not _has_group:     _reason.append('missing рҹ‘Ҙ')
            if _has_hourglass and _has_group and not _order_ok: _reason.append('wrong order (must be рҹ•җ В· вҸі В· рҹ‘Ҙ)')
            _clock_combined_bad.append(f'"{_full2[:60]}" вҖ” {", ".join(_reason)}')
    check(
        'рҹ•җ combined row вҖ” вҸі and рҹ‘Ҙ must be on the same div in order: '
        'рҹ•җ {H:MM am/pm} В· вҸі {duration} В· рҹ‘Ҙ {N or descriptor} '
        '(per Icon Order and Format.html Pos 6a)',
        len(_clock_combined_bad) == 0,
        f"{len(_clock_combined_bad)} рҹ•җ row(s) missing вҸі / рҹ‘Ҙ or wrong order: "
        + "; ".join(_clock_combined_bad[:5]),
    )

    # в”Җв”Җв”Җ вҸі DURATION VALUE вҖ” exact number-led duration, in ANY row context в”Җв”Җв”Җв”Җ
    # Rule source: Icon Order and Format.html Pos 2b / 4a вҖ” вҸі {duration} must be
    # an exact time value ("45 min", "1 hr 30 min", "3 hr", "2вҖ“3 hr"). Vague prose
    # ("Full day") is banned. The standalone вҸі prose-tail check (Pos 4b) and the
    # рҹ•җ combined-row check both require the emoji to LEAD its <div>; tour and
    # guided-stop meta rows carry the whole line behind a leading вҶі, so вҸі sits
    # mid-div and escaped every value check. This reads the вҸі segment wherever it
    # appears. Distinguisher: every valid duration begins with a digit (incl.
    # ranges / hybrid hВ·m / "N days"); a vague value like "Full day" starts with a
    # letter. HTML comments are stripped first (a low-count note may cite "вҸі /").
    print("\nв”Җв”Җ вҸі DURATION VALUE вҖ” number-led duration only (any row) в”Җв”Җ")
    _dur_html = re.sub(r'<!--.*?-->', '', html, flags=re.DOTALL)
    _dur_val_bad: list[str] = []
    for _dvm in re.finditer(r'вҸі\s*([^В·<]*)', _dur_html):
        _val = RE_STRIP_TAGS.sub('', _dvm.group(1)).strip()
        if not _val:
            continue
        if not _val[0].isdigit():
            _dur_val_bad.append(f'"вҸі {_val[:60]}"')
    check(
        'вҸі duration value must be an exact number-led time ("45 min", '
        '"1 hr 30 min", "3 hr") вҖ” no vague values like "Full day" '
        '(per Icon Order and Format.html Pos 2b/4a)',
        len(_dur_val_bad) == 0,
        f"{len(_dur_val_bad)} вҸі value(s) not a number-led duration: "
        + "; ".join(_dur_val_bad[:5]) if _dur_val_bad else "",
    )

    # в”Җв”Җв”Җ вҸі DURATION VALUE вҖ” canonical unit vocabulary (warn) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The number-led check above only verifies the value STARTS with a digit;
    # unit spelling itself was never checked, so "90 minutes", "45m", "1.5h"
    # all pass. Icon Order and Format.html Pos 2b/4a gives exactly two
    # canonical examples: "45 min" and "1 hr 30 min" вҖ” i.e. unit spelling
    # "min" / "hr", not "mins"/"minutes"/"m", "hrs"/"hours"/"h", decimal
    # hours ("1.5 hr"), en-dash/hyphen ranges, or a bare day-count. WARN, not
    # a hard-fail: a fleet scan (2026-07-11, enforcement-gap sweep) found 187
    # distinct вҸі value strings across the 219-guide fleet, the majority using
    # a non-canonical unit spelling вҖ” hard-failing today would break most of
    # the shipped fleet at once. Tracked as known debt (like css-duplication)
    # until a dedicated content pass normalizes the vocabulary.
    print("\nв”Җв”Җ вҸі DURATION VALUE вҖ” canonical unit vocabulary (warn) в”Җв”Җ")
    _dur_unit_re = re.compile(r'^\d+\s*min$|^\d+\s*hr(\s+\d+\s*min)?$', re.IGNORECASE)
    _dur_unit_bad: list[str] = []
    for _dvm in re.finditer(r'вҸі\s*([^В·<]*)', _dur_html):
        _val = RE_STRIP_TAGS.sub('', _dvm.group(1)).strip()
        if not _val or not _val[0].isdigit():
            continue   # covered by the hard-fail check above
        if not _dur_unit_re.match(_val):
            _dur_unit_bad.append(f'"вҸі {_val[:60]}"')
    if _dur_unit_bad:
        warn(
            'Non-canonical вҸі duration unit spelling вҖ” canonical forms are "N min" and '
            '"N hr" / "N hr M min" only (per Icon Order and Format.html Pos 2b/4a examples)',
            f"{len(_dur_unit_bad)} value(s): " + "; ".join(_dur_unit_bad[:6]),
            tag='duration-unit-vocabulary',
        )

    check(
        'Every рҹ“… tour-box carries вҸі duration',
        len(tb_missing_hourglass) == 0,
        f"{len(tb_missing_hourglass)} tour-box(es) missing вҸі: " + "; ".join(tb_missing_hourglass[:5]),
    )
    check(
        'Every рҹ“… tour-box carries рҹ‘Ҙ max group size',
        len(tb_missing_group) == 0,
        f"{len(tb_missing_group)} tour-box(es) missing рҹ‘Ҙ: " + "; ".join(tb_missing_group[:5]),
    )
    check(
        'Every рҹ“… tour-box carries a review count (e.g. "2,100+ reviews")',
        len(tb_count_missing) == 0,
        f"{len(tb_count_missing)} tour-box(es) missing review count: " + "; ".join(tb_count_missing[:5]),
    )
    check(
        'Review counts round down to nearest 10 (<100) or 100 (вүҘ100) and end in "+ reviews"',
        len(tb_count_unrounded) == 0,
        f"{len(tb_count_unrounded)} tour-box(es) with unrounded review count "
        f"(per cleanliness_checks.md Rule 147 v2 вҖ” digits before `+ reviews` must end in 0 вҖ” "
        f"`20+ reviews`, `100+ reviews`, `2,100+ reviews`): " + "; ".join(tb_count_unrounded[:5]),
    )
    check(
        'No currency symbols in .tour-box вҖ” prices do not belong in the guide ($, вӮ¬, ВЈ, ВҘ)',
        len(tb_price_leak) == 0,
        f"{len(tb_price_leak)} tour-box(es) contain a currency symbol: "
        + "; ".join(tb_price_leak[:5]),
    )
    check(
        'Every stop has distinct booking URLs across its tour-boxes (no copy-paste duplicates)',
        len(tb_dup_url) == 0,
        f"{len(tb_dup_url)} stop(s) with two or more tour-boxes pointing to the same booking URL: "
        + "; ".join(tb_dup_url[:5]),
    )
    # Dup-address: legitimate when operators genuinely share a meeting point
    # (e.g. two cruise operators at the same dock). Document with sentinel:
    #   <!-- shared-address-ok: reason -->  anywhere inside the stop-block.
    # Without the sentinel this is a hard FAIL вҖ” "I didn't check" is not valid.
    check(
        'Tour-boxes with a shared рҹ“Қ address carry <!-- shared-address-ok: reason --> sentinel',
        len(tb_dup_address) == 0,
        (f"{len(tb_dup_address)} stop(s) with duplicate рҹ“Қ address and no sentinel: "
         + "; ".join(tb_dup_address[:5])
         + " вҖ” add <!-- shared-address-ok: reason --> inside the stop-block if the shared address is correct.")
        if tb_dup_address else "",
    )
    check(
        'No рҹ“– Wikipedia link inside a .tour-box (рҹ“– is a stop-level element)',
        len(tb_has_wiki) == 0,
        f"{len(tb_has_wiki)} tour-box(es) contain a рҹ“– (belongs above tour-boxes, at stop level): "
        + "; ".join(tb_has_wiki[:5]),
    )
    check(
        'No вҶі stop description inside a .tour-box (вҶі is a stop-level element, belongs above tour-boxes)',
        len(tb_has_summary) == 0,
        f"{len(tb_has_summary)} tour-box(es) contain a вҶі (belongs above tour-boxes, at stop level): "
        + "; ".join(tb_has_summary[:5]),
    )
    check(
        'No .stop-photos wrapper inside a .tour-box (photos come AFTER all tour-boxes)',
        len(tb_has_stop_photos) == 0,
        f"{len(tb_has_stop_photos)} tour-box(es) contain a .stop-photos wrapper "
        f"(photos belong after the last tour-box, not inside one): " + "; ".join(tb_has_stop_photos[:5]),
    )

    # в”Җв”Җв”Җ PHOTO PLACEMENT (Photos Rules.html Placement) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ PHOTO PLACEMENT (Photos Rules.html) в”Җв”Җ")

    # A вҖ” .stop-photos wrapper inside .ticket-box.
    tk_has_stop_photos: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        # Best-effort label from the .stop-name in this stop block.
        name_m = RE_STOP_NAME.search( block)
        label = name_m.group(1).strip() if name_m else "(unnamed stop)"
        for tk in ticket_box_open.finditer(block):
            inner, _ = _walk_balanced_div(block, tk.end())
            if re.search(r'class\s*=\s*"[^"]*\bstop-photos\b', inner):
                tk_has_stop_photos.append(label)
                break  # one hit per stop is enough to flag it
    check(
        'No .stop-photos wrapper inside a .ticket-box (Photos Rules.html Placement вҖ” photos belong directly under .stop-block, never inside .ticket-box)',
        len(tk_has_stop_photos) == 0,
        f"{len(tk_has_stop_photos)} ticket-box(es) contain a .stop-photos wrapper: "
        + "; ".join(tk_has_stop_photos[:5]),
    )

    # B вҖ” .stop-photos must be the LAST element inside .stop-block.
    photo_not_last: list[str] = []
    for i, s in enumerate(stop_starts):
        end = stop_ends[i]
        block = html[s:end]
        name_m = RE_STOP_NAME.search( block)
        label = name_m.group(1).strip() if name_m else "(unnamed stop)"

        photo_opens = list(re.finditer(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bstop-photos\b[^"]*"[^>]*>',
            block,
        ))
        if not photo_opens:
            # No .stop-photos вҖ” either sentinel-exempt or already caught
            # by the missing-photos check up in the PHOTOS section.
            continue

        last = photo_opens[-1]
        _, photo_end = _walk_balanced_div(block, last.end())
        tail = block[photo_end:]
        # Strip HTML comments, closing tags (the stop-block's own </div>
        # and any further wrapping containers like </section>), and
        # whitespace. What remains is meaningful trailing content вҖ” any
        # leftover prose, summary rows, stop flags, etc. The closing-tag
        # strip is required because `block` slice runs from stop-block
        # open to the next sibling boundary, so the stop-block's own
        # </div> is always at the tail end.
        tail_clean = RE_HTML_COMMENT.sub('', tail)
        tail_clean = re.sub(r'</\w+>', '', tail_clean)
        tail_clean = tail_clean.strip()
        if tail_clean:
            photo_not_last.append(f"{label} (tail: {tail_clean[:40]!r})")

    check(
        'Photo block (.stop-photos / .stop-photos-empty) is the LAST element inside .stop-block (Photos Rules.html Placement)',
        len(photo_not_last) == 0,
        (f"{len(photo_not_last)} stop(s) have non-photo content after the "
         f"photo block: " + "; ".join(photo_not_last[:5]))
        if photo_not_last else "",
    )

    # в”Җв”Җв”Җ рҹ“Қ ADDRESS = LAST ROW OF EVERY .tour-box / .ticket-box в”Җв”Җв”Җв”Җ
    box_pin_not_last: list[str] = []
    box_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\b(tour-box|ticket-box)\b[^"]*"[^>]*>(.*?)</div>\s*'
        r'(?=<div\b[^>]*class\s*=\s*"[^"]*\b(?:tour-box|ticket-box|stop-photos|stop-photos-empty|next|stop-block)\b|</div>\s*</div>)',
        re.DOTALL | re.IGNORECASE,
    )
    cal_row_re = re.compile(r'<div[^>]*>\s*рҹ“…', re.IGNORECASE)
    info_row_re = re.compile(
        r'<div[^>]*>\s*(?:рҹ“Қ|рҹ“…|рҹҺҹпёҸ|рҹҺҹ|рҹҸӣ|рҹҸӣпёҸ|вҸ°|рҹҶ“|рҹҡ«|рҹ’ө|вҡ пёҸ|рҹ•җ|вҸі|рҹ‘Ҙ)',
        re.IGNORECASE,
    )
    for box_m in box_re.finditer(html):
        box_class = box_m.group(1)
        body = box_m.group(2)
        # Skip рҹ“…-led tour-boxes (Type 1 Guided): meeting point lives in
        # .tour-meet at the bottom, which is itself last by definition.
        if cal_row_re.search(body):
            continue
        # Find the last info row (рҹ“Қ / рҹҸӣ / вҸ° / рҹҶ“ / рҹҡ« / рҹ’ө / вҡ пёҸ) and
        # check that it's a рҹ“Қ row.
        info_rows = list(info_row_re.finditer(body))
        if not info_rows:
            continue
        last_row = info_rows[-1].group(0)
        if 'рҹ“Қ' not in last_row:
            # Find the stop name from the surrounding stop-block for
            # the error message.
            label = "(unnamed stop)"
            block_search = html[max(0, box_m.start() - 1500):box_m.start()]
            name_matches = list(re.finditer(
                r'<span class="stop-name[^"]*">([^<]+)</span>',
                block_search,
            ))
            if name_matches:
                label = name_matches[-1].group(1).strip()[:60]
            box_pin_not_last.append(
                f'"{label}" [{box_class}]: рҹ“Қ is not the last row '
                f'(last row starts with: {last_row[:30]!r})'
            )
    check(
        'рҹ“Қ address is the LAST row of every .tour-box / .ticket-box '
        '(per CORE RULES/Stops Structure.html вҖ” Type 2 Option 1, '
        'Type 2 Option 2, Type 3 ticket box. Type 1 рҹ“… tour-boxes carry the '
        'meeting point inside .tour-meet, exempt.)',
        len(box_pin_not_last) == 0,
        (f"{len(box_pin_not_last)} box(es) with рҹ“Қ not in the last row: "
         + "; ".join(box_pin_not_last[:5]))
        if box_pin_not_last else "",
    )

    # в”Җв”Җв”Җ UNIVERSAL STOP-BOX INNER ROW ORDER в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ UNIVERSAL STOP-BOX INNER ROW ORDER в”Җв”Җ")

    def _first_row_pos(body: str, *glyphs) -> int:
        """Return the start position of the FIRST <div> row that leads
        with any of the given glyphs, or -1 if none found."""
        _rre = re.compile(
            r'<div[^>]*>\s*(?:' + '|'.join(re.escape(g) for g in glyphs) + r')',
            re.IGNORECASE,
        )
        _m = _rre.search(body)
        return _m.start() if _m else -1

    # в”Җв”Җв”Җ day-coverage helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _DAY_FULL = ['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday','Sunday']
    _DAY_ABBR3 = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun']

    def _day_idx(name: str) -> int:
        """Return 0-based weekday index (Mon=0 вҖҰ Sun=6) for a name/abbr, or -1."""
        n = name.strip().lower()
        # Require вүҘ3 chars for the prefix branch: "" startswith-matches Monday and
        # single letters ("t","s") resolve ambiguously to the first weekday that
        # happens to share the prefix. Full-name + abbr equality already cover
        # every legal token; the prefix branch only helps "thur"/"tues" etc.
        # (Lane1-05 fix.)
        for i, (f, a) in enumerate(zip(_DAY_FULL, _DAY_ABBR3)):
            if n == f.lower() or n == a.lower() or (len(n) >= 3 and f.lower().startswith(n)):
                return i
        return -1

    _day_range_re = re.compile(
        r'\b(Mon(?:day)?|Tue(?:sday)?|Wed(?:nesday)?|Thu(?:rsday)?|Fri(?:day)?'
        r'|Sat(?:urday)?|Sun(?:day)?)\s*[вҖ“\-]\s*'
        r'(Mon(?:day)?|Tue(?:sday)?|Wed(?:nesday)?|Thu(?:rsday)?|Fri(?:day)?'
        r'|Sat(?:urday)?|Sun(?:day)?)\b',
        re.IGNORECASE,
    )

    def _days_from_text(raw: str) -> set:
        """Extract day-of-week indices from raw HTML/text. Returns set of 0вҖ“6.
        Returns empty set for 'open daily' indicators (24/7, daily, every day) вҖ”
        those mean 'no day constraint', not a specific day list."""
        t = RE_STRIP_TAGS.sub( '', raw)
        # "24/7", "daily", "every day" вҶ’ no specific days вҶ’ caller skips coverage check
        if re.search(r'\b24/7\b|\b(daily|every\s+day)\b', t, re.IGNORECASE):
            return set()
        result: set = set()
        # Consume ranges first so individual-day scan doesn't double-count.
        used = [False] * len(t)
        for rm in _day_range_re.finditer(t):
            s, e = _day_idx(rm.group(1)), _day_idx(rm.group(2))
            if s == -1 or e == -1:
                continue
            if s <= e:
                result.update(range(s, e + 1))
            else:  # wrapped: e.g. Wed(2)вҖ“Mon(0)
                result.update(range(s, 7))
                result.update(range(0, e + 1))
            for i in range(rm.start(), rm.end()):
                used[i] = True
        # Individual days (skip positions already consumed by ranges)
        for im in re.finditer(
            r'\b(Mon(?:day)?|Tue(?:sday)?|Wed(?:nesday)?|Thu(?:rsday)?'
            r'|Fri(?:day)?|Sat(?:urday)?|Sun(?:day)?)\b',
            t, re.IGNORECASE,
        ):
            if not any(used[im.start():im.end()]):
                idx = _day_idx(im.group(1))
                if idx != -1:
                    result.add(idx)
        return result

    # Matches a .tour-box or .ticket-box and captures only its direct-child rows.
    # Each row is a flat <div>вҖҰ</div> with no nested <div> elements (only <a>, <span>,
    # etc. inside). Using (?:(?!</?div\b).)* prevents the body from bleeding past the
    # box's own closing </div> into subsequent stop-blocks вҖ” the previous lookahead
    # approach over-extended across multiple stops and produced false positives
    # (e.g. a рҹҡ« row from a later stop was attributed to an earlier box).
    # Fixed 2026-05-08.
    _uro_box_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\b(tour-box|ticket-box)\b[^"]*"[^>]*>'
        r'((?:\s*<div[^>]*>(?:(?!</?div\b).)*</div>)*)'
        r'\s*</div>',
        re.DOTALL | re.IGNORECASE,
    )
    _uro_order_violations: list[str] = []
    _uro_mutex_violations: list[str] = []
    _uro_days_violations:  list[str] = []

    for _box_m in _uro_box_re.finditer(html):
        _box_class = _box_m.group(1)
        _body = _box_m.group(2)

        # Skip рҹ“…-led guided tour-boxes (Type 1) вҖ” different schema.
        if cal_row_re.search(_body):
            continue

        # Stop label for error messages.
        _bsearch = html[max(0, _box_m.start() - 1500):_box_m.start()]
        _nm = RE_STOP_NAME.search(_bsearch)
        _label = _nm.group(1).strip()[:60] if _nm else "(unnamed stop)"
        _blabel = f'"{_label}" [{_box_class}]'

        # Row positions (character index of each emoji's <div> opening).
        p_pickup  = _first_row_pos(_body, 'рҹҡҗ')
        p_hours   = _first_row_pos(_body, 'рҹҸӣ', 'рҹҸӣпёҸ', 'вҸі')
        p_closed  = _first_row_pos(_body, 'рҹҡ«')
        p_time    = _first_row_pos(_body, 'вҸ°', 'рҹ•җ')
        p_payment = _first_row_pos(_body, 'рҹҶ“', 'рҹ’ө')
        p_warning = _first_row_pos(_body, 'вҡ пёҸ')
        p_pin     = _first_row_pos(_body, 'рҹ“Қ')

        # Order 0: рҹҡҗ hotel pickup before рҹҸӣ/вҸі (Position 2 before Position 3)
        if p_pickup != -1 and p_hours != -1 and p_pickup > p_hours:
            _uro_order_violations.append(
                f'{_blabel}: рҹҡҗ hotel pickup row is AFTER рҹҸӣ/вҸі вҖ” '
                f'correct order: рҹҡҗ вҶ’ рҹҸӣ/вҸі вҶ’ рҹҡ« вҶ’ вҸ°/рҹ•җ'
            )

        # Order A: рҹҸӣ/вҸі before вҸ°/рҹ•җ
        if p_hours != -1 and p_time != -1 and p_hours > p_time:
            _uro_order_violations.append(
                f'{_blabel}: рҹҸӣ/вҸі hours/schedule row is AFTER вҸ°/рҹ•җ вҖ” '
                f'correct order: рҹҸӣ/вҸі вҶ’ рҹҡ« вҶ’ вҸ°/рҹ•җ'
            )

        # Order B: рҹҡ« before вҸ°/рҹ•җ
        if p_closed != -1 and p_time != -1 and p_closed > p_time:
            _uro_order_violations.append(
                f'{_blabel}: рҹҡ« closed-day row is AFTER вҸ°/рҹ•җ вҖ” '
                f'correct order: рҹҸӣ/вҸі вҶ’ рҹҡ« вҶ’ вҸ°/рҹ•җ'
            )

        # Order C: вҸ°/рҹ•җ before рҹҶ“/рҹ’ө
        if p_time != -1 and p_payment != -1 and p_time > p_payment:
            _uro_order_violations.append(
                f'{_blabel}: вҸ°/рҹ•җ time row is AFTER рҹҶ“/рҹ’ө payment row вҖ” '
                f'correct order: вҸ°/рҹ•җ вҶ’ рҹҶ“/рҹ’ө вҶ’ вҡ пёҸ вҶ’ рҹ“Қ'
            )

        # Order D: рҹҶ“/рҹ’ө before вҡ пёҸ
        if p_payment != -1 and p_warning != -1 and p_payment > p_warning:
            _uro_order_violations.append(
                f'{_blabel}: рҹҶ“/рҹ’ө payment row is AFTER вҡ пёҸ warning вҖ” '
                f'correct order: рҹҶ“/рҹ’ө вҶ’ вҡ пёҸ вҶ’ рҹ“Қ'
            )

        # Order E: вҡ пёҸ before рҹ“Қ
        if p_warning != -1 and p_pin != -1 and p_warning > p_pin:
            _uro_order_violations.append(
                f'{_blabel}: вҡ пёҸ warning row is AFTER рҹ“Қ address вҖ” '
                f'must come before рҹ“Қ (вҡ пёҸ вҶ’ рҹ“Қ)'
            )

        # Orders FвҖ“H: all flag rows must precede рҹ“Қ (direct per-flag check;
        # the AвҶ’E chain only covers this transitively when all rows present).
        for _flag, _fname in (("рҹҡ«", "рҹҡ« closed"), ("рҹҶ“", "рҹҶ“ free"), ("рҹ’ө", "рҹ’ө cash-only")):
            _p_flag = _first_row_pos(_body, _flag)
            if _p_flag != -1 and p_pin != -1 and _p_flag > p_pin:
                _uro_order_violations.append(
                    f'{_blabel}: {_fname} row is AFTER рҹ“Қ address вҖ” '
                    f'all flag rows must precede рҹ“Қ'
                )

        # Mutual X: рҹҸӣ and вҸі must not both appear
        _has_hrs  = bool(re.search(r'<div[^>]*>\s*рҹҸӣ', _body, re.IGNORECASE))
        _has_dur  = bool(re.search(r'<div[^>]*>\s*вҸі', _body, re.IGNORECASE))
        if _has_hrs and _has_dur:
            _uro_mutex_violations.append(
                f'{_blabel}: both рҹҸӣ hours AND вҸі schedule present вҖ” '
                f'mutually exclusive: use one (рҹҸӣ for self-walk, вҸі for tour)'
            )

        # Mutual Y: вҸ° and рҹ•җ must not both appear as row leaders
        _has_clock = bool(re.search(r'<div[^>]*>\s*вҸ°', _body, re.IGNORECASE))
        _has_start = bool(re.search(r'<div[^>]*>\s*рҹ•җ', _body, re.IGNORECASE))
        if _has_clock and _has_start:
            _uro_mutex_violations.append(
                f'{_blabel}: both вҸ° visit-time AND рҹ•җ start-time present вҖ” '
                f'mutually exclusive: use вҸ° for self-walk, рҹ•җ for fixed start'
            )

        # Mutual Z: рҹҶ“ and рҹ’ө must not both appear as row leaders
        _has_free = bool(re.search(r'<div[^>]*>\s*рҹҶ“', _body, re.IGNORECASE))
        _has_cash = bool(re.search(r'<div[^>]*>\s*рҹ’ө', _body, re.IGNORECASE))
        if _has_free and _has_cash:
            _uro_mutex_violations.append(
                f'{_blabel}: both рҹҶ“ free AND рҹ’ө cash-only present вҖ” '
                f'mutually exclusive: a venue is either free or cash-only'
            )

        # Days coverage: open days (рҹҸӣ) + closed days (рҹҡ«) must cover all 7.
        # If рҹҸӣ row contains NO day names at all вҶ’ venue assumed open daily вҶ’ skip.
        # Logic: every day of the week must appear on exactly one side of the ledger.
        _open_days:   set = set()
        _closed_days: set = set()
        for _hm in re.finditer(r'<div[^>]*>\s*(?:рҹҸӣпёҸ|рҹҸӣ|вҸі)(.*?)</div>', _body, re.DOTALL):
            _open_days |= _days_from_text(_hm.group(1))
        for _cm in re.finditer(r'<div[^>]*>\s*рҹҡ«(.*?)</div>', _body, re.DOTALL):
            _closed_days |= _days_from_text(_cm.group(1))
        if _open_days:  # only check when рҹҸӣ explicitly lists days; hours-only = skip
            _all_acc = _open_days | _closed_days
            _overlap = _open_days & _closed_days
            _missing = sorted(set(range(7)) - _all_acc)
            if _missing:
                _uro_days_violations.append(
                    f'{_blabel}: days not fully covered вҖ” '
                    f'missing: {", ".join(_DAY_FULL[d] for d in _missing)}'
                )
            if _overlap:
                _uro_days_violations.append(
                    f'{_blabel}: day(s) listed as BOTH open and closed вҖ” '
                    f'{", ".join(_DAY_FULL[d] for d in sorted(_overlap))}'
                )

    check(
        'Universal stop-box row order вҖ” inside every .ticket-box and self-walk '
        '.tour-box: рҹҡҗ вҶ’ рҹҸӣ/вҸі вҶ’ рҹҡ« вҶ’ вҸ°/рҹ•җ вҶ’ рҹҶ“/рҹ’ө вҶ’ вҡ пёҸ вҶ’ рҹ“Қ '
        '(per Icon Order and Format.html universal row order)',
        len(_uro_order_violations) == 0,
        (f"{len(_uro_order_violations)} box(es) with out-of-order rows: "
         + "; ".join(_uro_order_violations[:5]))
        if _uro_order_violations else "",
    )
    check(
        'Universal stop-box mutual exclusion вҖ” '
        'рҹҸӣ OR вҸі (not both), вҸ° OR рҹ•җ (not both), рҹҶ“ OR рҹ’ө (not both) inside any single box '
        '(per Icon Order and Format.html вҖ” mutually exclusive pairs)',
        len(_uro_mutex_violations) == 0,
        (f"{len(_uro_mutex_violations)} box(es) with mutually exclusive rows: "
         + "; ".join(_uro_mutex_violations[:5]))
        if _uro_mutex_violations else "",
    )
    check(
        'Venue days fully covered вҖ” рҹҸӣ (open days+hours) + рҹҡ« (closed days) '
        'together must account for all 7 days of the week; no day may be missing '
        'or listed on both sides',
        len(_uro_days_violations) == 0,
        (f"{len(_uro_days_violations)} box(es) with day gaps: "
         + "; ".join(_uro_days_violations[:5]))
        if _uro_days_violations else "",
    )

    # в”Җв”Җв”Җ STOP-BLOCK CANONICAL ELEMENT ORDER в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Stops Structure.html В§3a/В§3b + Icon Order and Format.html В§2: within
    # every .stop-block the children appear in this fixed sequence (rows
    # skipped when not applicable, but the order never changes):
    #   Pos 1: вҶі  stop description   (outside the box)
    #   Pos 2: рҹ“– Wikipedia          (outside the box)
    #   then the operational BOX, which FOLLOWS the вҶі/рҹ“– rows вҖ” either a
    #   рҹҺҹ-led .ticket-box (ticketed stop, В§3b) or a рҹ“Қ-led .tour-box
    #   (no-ticket stop, В§3a) вҖ” carrying рҹҸӣ/вҸі hours В· вҸ°/рҹ•җ time В· рҹ“Қ address
    #   inside it. The box never precedes the description rows.
    # NOTE: the рҹ“Қ-led .tour-box is the canonical no-ticket logistics box
    # (see _strip_guided_tour_boxes) and needs no рҹ“… вҖ” it is NOT retired
    # format. Operational rows live INSIDE the box, not as bare stop-rows.
    print("\nв”Җв”Җ STOP-BLOCK CANONICAL ELEMENT ORDER в”Җв”Җ")

    _sb_box_before_desc:  list[str] = []   # operational box placed before вҶі/рҹ“–
    _sb_order_violations: list[str] = []   # вҶі / рҹ“– out of order

    for _sbi, _sbs in enumerate(stop_starts):
        _sbe = stop_ends[_sbi]
        _blk = html[_sbs:_sbe]
        _nm  = RE_STOP_NAME.search(_blk)
        _lbl = _nm.group(1).strip()[:60] if _nm else f"(stop #{_sbi + 1})"

        # Operational box = first .ticket-box or .tour-box in the block.
        _kb_mo   = ticket_box_open.search(_blk)
        _tb_mo   = tour_box_open.search(_blk)
        _box_pos = [m.start() for m in (_kb_mo, _tb_mo) if m]
        _p_box   = min(_box_pos) if _box_pos else -1

        # вҶі description (Pos 1) and рҹ“– Wikipedia (Pos 2) вҖ” always outside the box.
        _arr_mo  = re.search(r'<div[^>]*>\s*вҶі', _blk)
        _p_arr   = _arr_mo.start() if _arr_mo else -1
        _wiki_mo = re.search(r'<div[^>]*>\s*рҹ“–', _blk)
        _p_wiki  = _wiki_mo.start() if _wiki_mo else -1

        # (A) The operational box must FOLLOW the вҶі/рҹ“– description rows.
        _p_desc_last = max(_p_arr, _p_wiki)
        if _p_box != -1 and _p_desc_last != -1 and _p_box < _p_desc_last:
            _sb_box_before_desc.append(
                f'"{_lbl}": operational box (рҹҺҹ .ticket-box / рҹ“Қ .tour-box) appears '
                f'BEFORE the вҶі description / рҹ“– Wikipedia rows вҖ” вҶі (Pos 1) and рҹ“– '
                f'(Pos 2) come first, then the box (per Stops Structure.html В§3a/В§3b)'
            )

        # (B) вҶі (Pos 1) must appear before рҹ“– (Pos 2).
        if _p_arr != -1 and _p_wiki != -1 and _p_arr > _p_wiki:
            _sb_order_violations.append(
                f'"{_lbl}": вҶі description (Pos 1) appears AFTER рҹ“– Wikipedia (Pos 2) вҖ” '
                f'вҶі must precede рҹ“– (per Icon Order and Format.html В§2)'
            )

    check(
        'Stop-block вҖ” operational box (рҹҺҹ .ticket-box / рҹ“Қ .tour-box) follows the '
        'вҶі description and рҹ“– Wikipedia rows; it never precedes them '
        '(per Stops Structure.html В§3a/В§3b вҖ” вҶі Pos 1, рҹ“– Pos 2, then the box)',
        len(_sb_box_before_desc) == 0,
        (f"{len(_sb_box_before_desc)} stop(s) with the box before the description rows: "
         + "; ".join(_sb_box_before_desc[:5]))
        if _sb_box_before_desc else "",
    )
    check(
        'Stop-block вҖ” вҶі description (Pos 1) precedes рҹ“– Wikipedia (Pos 2) '
        '(per Icon Order and Format.html В§2)',
        len(_sb_order_violations) == 0,
        (f"{len(_sb_order_violations)} stop(s) with вҶі/рҹ“– out of order: "
         + "; ".join(_sb_order_violations[:5]))
        if _sb_order_violations else "",
    )

    # в”Җв”Җв”Җ STOP-BLOCK вҖ” OPERATIONAL ROWS MUST LIVE INSIDE THE BOX в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Stops Structure.html В§3a/В§3b + Icon Order and Format.html В§2: the hours
    # (рҹҸӣпёҸ/рҹҸӣ), avg-time (вҸ°), address (рҹ“Қ), closed-day (рҹҡ«) and вҡ пёҸ note rows
    # are the LOGISTICS rows and belong INSIDE the operational box (рҹҺҹ-led
    # .ticket-box or рҹ“Қ-led .tour-box) вҖ” never as bare children of the
    # .stop-block. A bare row renders OUTSIDE the warm yellow box and throws the
    # icon order off (caught visually 2026-06-16: Bali Tegallalang / Mount Batur
    # / Uluwatu вҖ” рҹҸӣ hours В· вҸ° В· рҹ“Қ sitting above or with no box at all). The
    # 2026-06-16 element-order rewrite left this "bare operational rows" case
    # explicitly unenforced ("not enforced here yet вҖ” Istanbul, Palm Desert");
    # restored here. Box subtrees are stripped first (defense-in-depth via
    # _strip_balanced_div), so only rows OUTSIDE every box are scanned; the
    # glyph must lead its row (immediately after a <div ...> open) so emojis
    # inside вҶі prose never match.
    print("\nв”Җв”Җ STOP-BLOCK вҖ” OPERATIONAL ROWS INSIDE THE BOX в”Җв”Җ")
    _sb_bare_oprows: list[str] = []
    _sb_nobox:       list[str] = []
    # Every inside-box logistics glyph (Icon Order and Format.html В§2 inside the
    # blue box): hours В· duration В· closed В· start-time В· avg-time В· free В· cash
    # В· warning В· address. Any of these LEADING a row outside every box = bare.
    _OP_ROW_LEAD_RE = re.compile(r'<div\b[^>]*>\s*(рҹҸӣпёҸ|рҹҸӣ|вҸі|рҹҡ«|рҹ•җ|вҸ°|рҹҶ“|рҹ’ө|вҡ пёҸ|вҡ |рҹ“Қ)')
    for _sbi, _sbs in enumerate(stop_starts):
        _blk = html[_sbs:stop_ends[_sbi]]
        _nm  = RE_STOP_NAME.search(_blk)
        _lbl = _nm.group(1).strip()[:60] if _nm else f"(stop #{_sbi + 1})"
        # (1) Every stop carries an operational box (the warm-yellow box):
        # рҹ“Қ-led .tour-box (no ticket, В§3a) or рҹҺҹ-led .ticket-box (В§3b).
        _has_box = bool(ticket_box_open.search(_blk) or tour_box_open.search(_blk))
        if not _has_box:
            _sb_nobox.append(f'"{_lbl}"')
        # (2) No logistics row sits OUTSIDE the box. Strip box subtrees first;
        # the glyph must LEAD its row, so emojis inside вҶі prose never match.
        _outside = _strip_balanced_div(_blk, tour_box_open)
        _outside = _strip_balanced_div(_outside, ticket_box_open)
        _gm = _OP_ROW_LEAD_RE.search(_outside)
        if _gm:
            _sb_bare_oprows.append(f'"{_lbl}": {_gm.group(1)} row is OUTSIDE the box')
    check(
        'Stop-block вҖ” every stop carries an operational box (рҹ“Қ-led .tour-box for '
        'no-ticket stops, рҹҺҹ-led .ticket-box for ticketed stops) вҖ” the warm-yellow '
        'box that wraps the logistics rows (per Stops Structure.html В§3a/В§3b)',
        len(_sb_nobox) == 0,
        (f"{len(_sb_nobox)} stop(s) with NO operational box (yellow box missing): "
         + "; ".join(_sb_nobox[:8]))
        if _sb_nobox else "",
    )
    check(
        'Stop-block вҖ” operational rows (рҹҸӣ hours В· вҸі duration В· рҹҡ« closed В· рҹ•җ/вҸ° '
        'time В· рҹҶ“/рҹ’ө cost В· вҡ пёҸ note В· рҹ“Қ address) live INSIDE the рҹҺҹ .ticket-box / '
        'рҹ“Қ .tour-box, never as bare rows outside it (per Stops Structure.html '
        'В§3a/В§3b вҖ” the yellow box wraps the logistics rows)',
        len(_sb_bare_oprows) == 0,
        (f"{len(_sb_bare_oprows)} stop(s) with an operational row outside the box: "
         + "; ".join(_sb_bare_oprows[:8]))
        if _sb_bare_oprows else "",
    )

    # в”Җв”Җв”Җ STOP-BLOCK вҖ” INSIDE-BOX ICON ORDER в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Icon Order and Format.html В§2 (inside the blue box) fixes the row order:
    #   1  рҹҺҹ ticket   2  рҹҸӣ hours / вҸі duration   3  рҹҡ« closed days
    #   4  рҹ•җ start-time / вҸ° avg time   5  рҹҶ“ free / рҹ’ө cash only
    #   6  вҡ пёҸ warning   7  рҹ“Қ address
    # "Rows are skipped when they do not apply, but the order never changes."
    # Restores the intra-row order check the 2026-06-16 element-order rewrite
    # removed. ONLY the glyphs that В§2 actually lists for inside the box are
    # ranked. The `рҹҺ« book at` row and the guided-tour `рҹ“…` lead are NOT in the
    # В§2 inside-box table (Stops Structure В§3c documents рҹҺ« book-at for TRAIN
    # DAYS only, and its in-box position is otherwise undefined), so they are
    # left unranked вҖ” never positioned, never penalised. Ranks must be
    # non-decreasing down the box.
    print("\nв”Җв”Җ STOP-BLOCK вҖ” INSIDE-BOX ICON ORDER в”Җв”Җ")
    _BOX_ROW_RANKS = [
        ('рҹҺҹпёҸ', 1), ('рҹҺҹ', 1),
        ('рҹҸӣпёҸ', 2), ('рҹҸӣ', 2), ('вҸі', 2),
        ('рҹҡ«', 3),
        ('рҹ•җ', 4), ('вҸ°', 4),
        ('рҹҶ“', 5), ('рҹ’ө', 5),
        ('вҡ пёҸ', 6), ('вҡ ', 6),
        ('рҹ“Қ', 7),
    ]
    _box_row_lead_re = re.compile(r'<div\b[^>]*>\s*(' + '|'.join(
        re.escape(g) for g, _ in _BOX_ROW_RANKS) + r')')
    _rank_of = {g: r for g, r in _BOX_ROW_RANKS}
    _sb_iconorder_bad: list[str] = []
    for _sbi, _sbs in enumerate(stop_starts):
        _blk = html[_sbs:stop_ends[_sbi]]
        _nm  = RE_STOP_NAME.search(_blk)
        _lbl = _nm.group(1).strip()[:60] if _nm else f"(stop #{_sbi + 1})"
        for _bx_re in (ticket_box_open, tour_box_open):
            for _bm in _bx_re.finditer(_blk):
                _inner, _ = _walk_balanced_div(_blk, _bm.end())
                _prev_rank = 0
                _prev_g = ''
                for _m in _box_row_lead_re.finditer(_inner):
                    _g = _m.group(1); _r = _rank_of[_g]
                    if _r < _prev_rank:
                        _sb_iconorder_bad.append(
                            f'"{_lbl}": {_g} (pos {_r}) appears after {_prev_g} '
                            f'(pos {_prev_rank}) inside the box'
                        )
                        break
                    _prev_rank, _prev_g = _r, _g
    check(
        'Stop-block вҖ” inside-box icon order follows рҹҺҹ вҶ’ рҹҸӣ/вҸі вҶ’ рҹҡ« вҶ’ рҹ•җ/вҸ° вҶ’ '
        'рҹҶ“/рҹ’ө вҶ’ вҡ пёҸ вҶ’ рҹ“Қ (per Icon Order and Format.html В§2 вҖ” inside the blue box; '
        'the undocumented рҹҺ« book-at / рҹ“… rows are not position-checked)',
        len(_sb_iconorder_bad) == 0,
        (f"{len(_sb_iconorder_bad)} box(es) with rows out of icon order: "
         + "; ".join(_sb_iconorder_bad[:8]))
        if _sb_iconorder_bad else "",
    )

    # в”Җв”Җв”Җ рҹҸЁ вҶ”/вҶ’/вҶҗ рҹҡҗ BANNED IN STOP-BLOCK TICKET BOXES в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Icon Order and Format.html В§2 inside-box table (Pos 1вҖ“7) has NO рҹҡҗ row.
    # The hotel-pickup variants (рҹҸЁ вҶ” рҹҡҗ / рҹҸЁ вҶ’ рҹҡҗ / рҹҸЁ вҶҗ рҹҡҗ) belong ONLY
    # in Tours section entries (under a рҹ“… heading, per В§2 Tours table). A stop
    # block's ticket-box never contains a shuttle-pickup row вҖ” its schema is
    # рҹҺҹ вҶ’ рҹҸӣ/вҸі вҶ’ рҹҡ« вҶ’ рҹ•җ/вҸ° вҶ’ рҹҶ“/рҹ’ө вҶ’ вҡ пёҸ вҶ’ рҹ“Қ, period.
    print("\nв”Җв”Җ рҹҸЁ PICKUP ROW BANNED IN STOP-BLOCK TICKET BOXES в”Җв”Җ")
    _pickup_re = re.compile(r'рҹҸЁ\s*(?:вҶ”|вҶ’|вҶҗ)\s*рҹҡҗ')
    _sb_pickup_bad: list[str] = []
    for _sbi, _sbs in enumerate(stop_starts):
        _blk = html[_sbs:stop_ends[_sbi]]
        _nm  = RE_STOP_NAME.search(_blk)
        _lbl = _nm.group(1).strip()[:60] if _nm else f"(stop #{_sbi + 1})"
        for _tbm in ticket_box_open.finditer(_blk):
            _inner, _ = _walk_balanced_div(_blk, _tbm.end())
            if _pickup_re.search(_inner):
                _sb_pickup_bad.append(f'"{_lbl}": рҹҸЁ вҶ”/вҶ’/вҶҗ рҹҡҗ inside a stop-block ticket-box')
    check(
        'рҹҸЁ вҶ”/вҶ’/вҶҗ рҹҡҗ (hotel pickup) must NEVER appear in a stop-block ticket-box вҖ” '
        'it belongs only in Tours section entries (Icon Order and Format.html В§2)',
        len(_sb_pickup_bad) == 0,
        f"{len(_sb_pickup_bad)} stop(s) with banned pickup row: "
        + "; ".join(_sb_pickup_bad[:8])
        if _sb_pickup_bad else "",
    )

    # в”Җв”Җв”Җ рҹҡ« CLOSED DAYS NEVER STACKED в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Icon Order and Format.html В§2 (inside the blue box, Pos 3 + the рҹҸӣ note):
    # "Multiple closed days collapse into one рҹҡ« row (range or '&'), never
    # stacked." A container (stop operational box OR extras-section entry)
    # carries AT MOST ONE рҹҡ« row вҖ” e.g. "рҹҡ« Closed Saturday" + "рҹҡ« Closed
    # Sunday" must become "рҹҡ« Closed Saturday & Sunday" or "вҖҰSaturdayвҖ“Sunday".
    # Detector: two рҹҡ«-led <div> rows ADJACENT (only closing/opening div tags
    # and whitespace between them) вҖ” adjacency proves the same container, so it
    # catches both stop tour-/ticket-boxes (Montevideo, Virgin Islands) and
    # extras entry-bodies (Zurich, Big Island, Bordeaux, Chicago) without
    # mis-flagging two separate entries (which are split by an .extras-sub
    # heading and other rows).
    print("\nв”Җв”Җ рҹҡ« CLOSED DAYS NEVER STACKED в”Җв”Җ")
    _stacked_closed_re = re.compile(
        r'рҹҡ«\s*Closed[^<]*</div>\s*(?:</div>\s*)*<div\b[^>]*>\s*рҹҡ«\s*Closed'
    )
    _n_stacked = len(_stacked_closed_re.findall(html))
    check(
        'Multiple closed days collapse into ONE рҹҡ« row (range "вҖ“" or "&"), '
        'never stacked as separate рҹҡ« rows вҖ” applies to stop boxes and extras '
        'entries alike (per Icon Order and Format.html В§2 Pos 3)',
        _n_stacked == 0,
        (f"{_n_stacked} stacked рҹҡ« pair(s) found вҖ” collapse each to one row "
         f'(e.g. "рҹҡ« Closed Saturday & Sunday")')
        if _n_stacked else "",
    )

    # в”Җв”Җв”Җ MOTION RULE вҖ” PATTERN CHECK () в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ MOTION RULE вҖ” PATTERN CHECK () в”Җв”Җ")

    # All motion emojis
    _MOTION_PATTERN = (
        r'рҹҡ¶|рҹҡ•|рҹҡ—|рҹҡҷ|рҹӣә|рҹҡҗ|рҹҡҺ'
        r'|рҹҡҮ|рҹҡҲ|рҹҡҠ|рҹҡӢ|рҹҡқ|рҹҡһ'
        r'|рҹҡҶ|рҹҡ„|рҹҡ…'
        r'|рҹҡҒ|вӣө|рҹҡӨ|рҹӣҘпёҸ|рҹҡў'
    )
    _motion_re       = re.compile(_MOTION_PATTERN)
    _unit_re         = re.compile(r'\d+\s*(?:min|h|minutes|hrs|hour|hours)?', re.IGNORECASE)
    _wr_hours_min_re = re.compile(r'^(\d+)h\s*(\d+)min\b', re.IGNORECASE)  # Xh Ymin
    _wr_hours_re     = re.compile(r'^(\d+)h\b', re.IGNORECASE)             # Xh (Y=0)
    _wr_min_re       = re.compile(r'^(\d+)\s*min\b', re.IGNORECASE)        # N min

    def _validate_motion_row(text: str, label: str) -> list[str]:
        """Validate one motion row against Motion Rule Returns violation strings."""
        errs: list[str] = []
        plain = text.strip()
        if not plain or not _motion_re.search(plain):
            return errs  # not a motion row

        # Strip known banner prefixes before core validation:
        #   рҹҸЁ From Hotel: ...  (day opener вҖ” departure time no longer allowed here; Rule 402)
        #   рҹҡү ARRIVE {station} [В· address] ... (train-day arrival вҖ” strip up to first motion emoji)
        core = re.sub(r'^рҹҸЁ\s*From\s+Hotel:\s*', '', plain, flags=re.IGNORECASE)
        # NOTE: time-stripping step removed 2026-05-25 (Rule 402 вҖ” times banned from From Hotel)
        # For arrive-first: strip everything before the first motion emoji (рҹҡ¶/рҹҡ•/рҹҡҺ/рҹҡқ/рҹҡў)
        _arrive_m = re.match(r'^рҹҡү\s*ARRIVE\b', core, re.IGNORECASE)
        if _arrive_m:
            _first_motion = re.search(r'рҹҡ¶|рҹҡ•|рҹҡҺ|рҹҡқ|рҹҡў', core)
            core = core[_first_motion.start():] if _first_motion else core
        # Strip destination (вҶ’ dest) for core validation
        core = re.sub(r'\s*вҶ’.*$', '', core, flags=re.DOTALL).strip()

        # Each motion emoji must be followed by a number.
        # рҹҡ¶ and рҹҡ• enforce Motion Rule В§1 time format:
        #   < 60 min  вҶ’ "N min"   (N must be < 60)
        #   вүҘ 60 min  вҶ’ "Xh Ymin" (e.g. 2h 30min) or "Xh" when Y=0 (e.g. 2h)
        #   "N min" with N вүҘ 60 is banned вҖ” use hours format instead.
        for seg in re.finditer(
            rf'({_MOTION_PATTERN})((?:(?!{_MOTION_PATTERN}).)*)', core, re.DOTALL
        ):
            emoji = seg.group(1)
            after = seg.group(2).strip()
            if not after or not after[0].isdigit():
                errs.append(
                    f'{label}: {emoji} has no numeric time вҖ” "{plain[:60]}"'
                )
            elif emoji in ('рҹҡ¶', 'рҹҡ•', 'рҹҡў', 'рҹҡқ'):
                # рҹҡў ferry / рҹҡқ metro carry the SAME [N min] / Xh Ymin shape as
                # walk/ride (Icon Order and Format.html В§2 8aвҖ“8e), so they get the
                # full вүҘ60-minвҶ’hours + no-0-min enforcement вҖ” not just the "has a
                # digit" check. рҹҡҺ tram is deliberately EXCLUDED: its inline form is
                # a line identifier ("рҹҡҺ 2 tram to вҖҰ", "рҹҡҺ T1 tram вҖҰ"), validated by
                # the dedicated .next-tram shape check, and its segment is stripped
                # by the "вҶ’ dest" cut above.
                _hm = _wr_hours_min_re.match(after)
                _ho = _wr_hours_re.match(after)
                _mo = _wr_min_re.match(after)
                if _hm or _ho:
                    # Zero-hours check: 0h or 0h 0min is not a valid travel time.
                    _total_h = int(_hm.group(1)) if _hm else int(_ho.group(1))
                    _total_m = int(_hm.group(2)) if _hm else 0
                    if _total_h == 0 and _total_m == 0:
                        errs.append(
                            f'{label}: {emoji} 0 min is not a valid travel time вҖ” '
                            f'use actual measured time or omit the row вҖ” "{plain[:60]}"'
                        )
                elif _mo:
                    _n = int(_mo.group(1))
                    if _n == 0:
                        errs.append(
                            f'{label}: {emoji} 0 min is not a valid travel time вҖ” '
                            f'use actual measured time or omit the row вҖ” "{plain[:60]}"'
                        )
                    elif _n >= 60:
                        _h, _m = divmod(_n, 60)
                        _suggested = f'{_h}h {_m}min' if _m else f'{_h}h'
                        errs.append(
                            f'{label}: {emoji} "{_n} min" must use hours format for вүҘ60 min'
                            f' вҖ” use "{_suggested}" вҖ” "{plain[:60]}"'
                        )
                    # else 1 вүӨ N < 60 вҶ’ valid
                else:
                    errs.append(
                        f'{label}: {emoji} time must be "N min" or "Xh Ymin" вҖ” '
                        f'got "{after[:20]}" in "{plain[:60]}"'
                    )

        # No leftover prose after stripping emojis, numbers, and separators
        stripped = _motion_re.sub('', core)
        stripped = _unit_re.sub('', stripped)
        stripped = re.sub(r'[В·вҶ”вҶҗвҶ’\[\]\s]+', '', stripped)
        if stripped:
            errs.append(
                f'{label}: unexpected text in motion row вҖ” "{plain[:60]}" '
                f'вҶ’ leftover: "{stripped[:30]}"'
            )

        return errs

    _pattern_violations: list[str] = []

    # All itinerary banner divs: .next, .next-tram, .next-metro, .hotel-first, .depart, .arrive-first
    _next_any_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\b(next(?:-tram|-metro)?|hotel-first|depart|arrive-first)\b[^"]*"[^>]*>(.*?)</div>',
        re.IGNORECASE | re.DOTALL,
    )
    for _nm in _next_any_re.finditer(html):
        _div_class = _nm.group(1)
        _plain = RE_STRIP_TAGS.sub( '', _nm.group(2)).strip()
        if not _plain:
            continue
        if not _motion_re.search(_plain):
            _pattern_violations.append(
                f'.{_div_class} has no motion emoji вҖ” prose in a motion banner: '
                f'"{_plain[:80]}"'
            )
            continue
        _pattern_violations.extend(_validate_motion_row(_plain, f'.{_div_class}'))

    # Extras box motion rows (shows-box, entry-body, station-box)
    _EOI_BOX_RE = re.compile(
        r'<div\b[^>]*class\s*=\s*"[^"]*\b(?:shows-box|entry-body|station-box)\b[^"]*"[^>]*>',
        re.IGNORECASE,
    )
    for _ebm in _EOI_BOX_RE.finditer(html):
        _eb_inner, _ = _walk_balanced_div(html, _ebm.end())
        _prec = html[max(0, _ebm.start() - 400):_ebm.start()]
        _sub_labels = list(re.finditer(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bextras-sub\b[^"]*"[^>]*>(.*?)</div>',
            _prec, re.DOTALL,
        ))
        _box_label = RE_STRIP_TAGS.sub( '', _sub_labels[-1].group(1)).strip()[:50] \
            if _sub_labels else '(unknown entry)'
        for _rdm in re.finditer(r'<div\b[^>]*>(.*?)</div>', _eb_inner, re.DOTALL):
            _row = RE_STRIP_TAGS.sub( '', _rdm.group(1)).strip()
            if re.search(r'рҹҡ¶|рҹҡ•|рҹҡў', _row):
                _pattern_violations.extend(_validate_motion_row(_row, f'"{_box_label}"'))

    check(
        'Motion Rule вҖ” every motion row matches a valid pattern: '
        'рҹҡ¶ N В· рҹҡ• M  or  рҹҡ• M  or tram/metro pattern. Anything else fails.',
        len(_pattern_violations) == 0,
        (f'{len(_pattern_violations)} invalid motion row(s): '
         + '; '.join(_pattern_violations[:5]))
        if _pattern_violations else '',
    )

    # в”Җв”Җв”Җ TWO CONSECUTIVE MOTION ROWS вҖ” hard fail в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # рҹҡ¶ and рҹҡ• must share one row ("рҹҡ¶ N min В· рҹҡ• M min"). If they appear as
    # two separate adjacent <div> rows inside the same box, it is format drift.
    print("\nв”Җв”Җ CONSECUTIVE MOTION ROWS в”Җв”Җ")
    _consec_motion_hits: list[str] = []
    _MOTION_LEAD_RE = re.compile(r'^[рҹҡ¶рҹҡ•рҹҡўрҹҡқрҹҡҺ]')
    for _cbm in _EOI_BOX_RE.finditer(html):
        _cb_inner, _ = _walk_balanced_div(html, _cbm.end())
        _prec2 = html[max(0, _cbm.start() - 400):_cbm.start()]
        _sub2 = list(re.finditer(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bextras-sub\b[^"]*"[^>]*>(.*?)</div>',
            _prec2, re.DOTALL,
        ))
        _lbl2 = RE_STRIP_TAGS.sub('', _sub2[-1].group(1)).strip()[:50] \
            if _sub2 else '(unknown entry)'
        _rows2 = [
            RE_STRIP_TAGS.sub('', m.group(1)).strip()
            for m in re.finditer(r'<div\b[^>]*>(.*?)</div>', _cb_inner, re.DOTALL)
        ]
        for _ri in range(len(_rows2) - 1):
            if _MOTION_LEAD_RE.match(_rows2[_ri]) and _MOTION_LEAD_RE.match(_rows2[_ri + 1]):
                _consec_motion_hits.append(
                    f'"{_lbl2[:50]}" вҖ” rows {_ri+1} and {_ri+2} are both motion rows: '
                    f'"{_rows2[_ri][:40]}" / "{_rows2[_ri+1][:40]}"'
                )
    check(
        'No two consecutive motion rows in the same box вҖ” рҹҡ¶ and рҹҡ• must share '
        'one row ("рҹҡ¶ N min В· рҹҡ• M min"); splitting them into adjacent <div> rows '
        'is format drift (Motion Rule)',
        len(_consec_motion_hits) == 0,
        (f'{len(_consec_motion_hits)} consecutive-motion violation(s): '
         + '; '.join(_consec_motion_hits[:5]))
        if _consec_motion_hits else '',
    )

    # в”Җв”Җв”Җ рҹҡҗ IN .next AFTER GUIDED STOPS вҖ” DEAD CODE REMOVED 2026-05-25 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # The .guided CSS class on .stop-name was retired 2026-05-20.
    # Any guide that still carries class="...guided..." already hard-fails the
    # stop-name modifier check (Stops Structure.html В§ 2). Because
    # _guided_sn_re always returned False on every current guide, _is_guided was
    # always False, the loop body never executed, _guided_next_violations was always
    # [], and the check() passed vacuously on every run. Full block removed.
    # рҹҡҗ in all motion banners is still caught by the check immediately below.

    # в”Җв”Җв”Җ рҹҡҗ BANNED IN ALL MOTION BANNERS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    print("\nв”Җв”Җ рҹҡҗ BANNED IN ALL MOTION BANNERS в”Җв”Җ")
    _bus_in_motion_hits: list[str] = []
    _motion_banner_re = re.compile(
        r'<div\b[^>]*class\s*=\s*"(next|next-tram|next-metro|hotel-first|arrive-first)"[^>]*>'
        r'(.*?)</div>',
        re.DOTALL | re.IGNORECASE,
    )
    for _mbm in _motion_banner_re.finditer(html):
        _mb_class = _mbm.group(1)
        _mb_plain = RE_STRIP_TAGS.sub( '', _mbm.group(2)).strip()
        if 'рҹҡҗ' in _mb_plain:
            _bus_in_motion_hits.append(
                f'class="{_mb_class}" вҖ” "{_mb_plain[:80]}"'
            )
    check(
        'рҹҡҗ never in motion banners (.next / .next-tram / .next-metro / .hotel-first / .arrive-first) вҖ” '
        'emoji belongs to tour operator only; use рҹҡ• / рҹҡ¶ / рҹҡҺ / рҹҡқ / рҹҡў for motion '
        '(per Tours - Extra Section.html )',
        len(_bus_in_motion_hits) == 0,
        (f'{len(_bus_in_motion_hits)} motion banner(s) containing рҹҡҗ: '
         + '; '.join(_bus_in_motion_hits[:5]))
        if _bus_in_motion_hits else '',
    )

    # в”Җв”Җв”Җ INFORMATION ROWS ARE PLAIN TEXT вҖ” NO EMBEDDED <a> в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    info_link_violations: list[str] = []
    # Match each info row separately. The рҹҺҹ row is excluded вҖ” that's the
    # ticket-box lead row, which is supposed to be a link.
    _row_end_re = re.compile(r'</div>')   # fixed pattern вҖ” compiled once before both loops
    for glyph in ['рҹҸӣ', 'вҸ°', 'рҹҶ“', 'рҹҡ«', 'рҹ’ө', 'вҡ пёҸ']:
        # Match a <div>...</div> that starts with the glyph and contains
        # an <a> anywhere inside it.
        row_re = re.compile(
            rf'<div[^>]*>\s*{re.escape(glyph)}[^<]*<a\b',
            re.IGNORECASE,
        )
        for m in row_re.finditer(html):
            # Get the row's full text for the error message.
            tail = html[m.start():m.start() + 400]
            row_close = _row_end_re.search(tail)
            row_text = tail[:row_close.end()] if row_close else tail[:200]
            # Strip tags for a cleaner snippet.
            row_clean = RE_STRIP_TAGS.sub( ' ', row_text)
            row_clean = RE_WS.sub(' ', row_clean).strip()
            info_link_violations.append(
                f'{glyph} row with embedded link: "{row_clean[:80]}"'
            )
    check(
        'Information rows are plain text вҖ” no embedded <a> in рҹҸӣ / вҸ° / рҹҶ“ / '
        'рҹҡ« / рҹ’ө / вҡ пёҸ rows (per CORE RULES/Stops Structure.html вҖ” '
        'supplementary booking info goes on its own row or its own box, '
        'never spliced inline into an information row.)',
        len(info_link_violations) == 0,
        (f"{len(info_link_violations)} information row(s) with embedded "
         f"<a> hyperlink: " + "; ".join(info_link_violations[:5]))
        if info_link_violations else "",
    )

    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ
    # в”Ӯ Pos  в”Ӯ Icon в”Ӯ FORMAT                                                  в”Ӯ
